import type { ExamQuestion } from "./types";

export const rnArrhythmiasChdAnticoagTestbankQuestions: ExamQuestion[] = [
  // ===== ATRIAL FIBRILLATION (35 questions) =====
  { q: "A client presents with new-onset palpitations and dizziness. The telemetry monitor shows an irregularly irregular rhythm with no discernible P waves and a ventricular rate of 142 bpm. Which rhythm does the nurse identify?", o: ["Sinus tachycardia", "Atrial fibrillation with rapid ventricular response", "Atrial flutter with variable block", "Ventricular tachycardia"], a: 1, r: "Atrial fibrillation is characterized by an irregularly irregular rhythm with absent P waves (replaced by fibrillatory waves). The rapid ventricular response (>100 bpm) indicates uncontrolled rate. Sinus tachycardia has visible P waves. Atrial flutter has regular sawtooth waves. VTach has wide QRS complexes.", s: "Arrhythmias" },
  { q: "A nurse is calculating the CHA2DS2-VASc score for a 72-year-old female client with atrial fibrillation, hypertension, and diabetes. What is the score?", o: ["2", "3", "4", "5"], a: 2, r: "CHA2DS2-VASc: Age 65-74 = 1 point, Hypertension = 1 point, Diabetes = 1 point, Female sex = 1 point. Total = 4 points. This indicates high stroke risk requiring oral anticoagulation.", s: "Arrhythmias" },
  { q: "A client with atrial fibrillation is hemodynamically stable with HR 148 bpm. The provider orders IV diltiazem. Which assessment is most important before administration?", o: ["Blood glucose level", "Blood pressure and presence of heart failure with reduced ejection fraction", "Urine output", "Bowel sounds"], a: 1, r: "Diltiazem has negative inotropic effects and is contraindicated in HFrEF. It can also cause significant hypotension. Assess baseline BP and cardiac function before administration.", s: "Arrhythmias" },
  { q: "A client with AFib has been on warfarin for 2 years with stable INR. At today's visit, the INR is 1.4. Which action is most appropriate?", o: ["Continue the same dose", "Notify the provider as the INR is subtherapeutic and the client is at risk for stroke", "Hold the next dose of warfarin", "Administer vitamin K"], a: 1, r: "For AFib, the therapeutic INR range is 2.0-3.0. An INR of 1.4 is subtherapeutic, placing the client at increased risk for thromboembolic stroke.", s: "Arrhythmias" },
  { q: "A client with new-onset AFib of unknown duration is scheduled for elective cardioversion. Which intervention must be completed first?", o: ["Baseline chest X-ray", "Either 3 weeks of therapeutic anticoagulation or TEE showing no left atrial thrombus", "Complete blood count", "Thyroid function tests"], a: 1, r: "AFib >48 hours requires either 3 weeks of anticoagulation or TEE to rule out LA thrombus before cardioversion. Converting with existing thrombus can cause stroke.", s: "Arrhythmias" },
  { q: "Which rate control agent is preferred for AFib with heart failure with reduced ejection fraction?", o: ["Diltiazem", "Verapamil", "Metoprolol", "Nifedipine"], a: 2, r: "Beta-blockers (metoprolol, carvedilol) are preferred for rate control in HFrEF. Non-DHP CCBs are contraindicated due to negative inotropy.", s: "Arrhythmias" },
  { q: "A client on warfarin for AFib has INR 4.8 with no active bleeding. What action does the nurse anticipate?", o: ["Administer protamine sulfate", "Hold warfarin and administer oral vitamin K", "Continue current dose", "Administer FFP immediately"], a: 1, r: "INR 4.8 without bleeding: hold warfarin, give oral vitamin K 2.5-5 mg, recheck INR in 24 hours. FFP/PCC is reserved for active serious bleeding.", s: "Arrhythmias" },
  { q: "A client with AFib becomes hemodynamically unstable (BP 72/40, AMS). What is the priority intervention?", o: ["IV diltiazem bolus", "Immediate synchronized cardioversion", "IV amiodarone drip", "12-lead ECG and monitor"], a: 1, r: "Unstable tachyarrhythmia requires immediate synchronized cardioversion per ACLS. Do not delay for medication trials when hemodynamically compromised.", s: "Arrhythmias" },
  { q: "A client with AFib on apixaban is scheduled for knee replacement surgery. When should apixaban be stopped?", o: ["1 hour before surgery", "24-48 hours before surgery based on bleeding risk", "5 days before surgery", "No need to stop"], a: 1, r: "DOACs have shorter half-lives than warfarin. Apixaban is stopped 24-48 hours pre-op depending on procedure bleeding risk and renal function. No bridging typically needed.", s: "Arrhythmias" },
  { q: "What is the most serious complication of atrial fibrillation?", o: ["Pneumonia", "Cardioembolic stroke from left atrial thrombus", "Peptic ulcer disease", "Urinary tract infection"], a: 1, r: "Stagnant blood in the fibrillating LA (especially the LA appendage) forms thrombi. AFib increases stroke risk 5-fold. Anticoagulation is the primary prevention.", s: "Arrhythmias" },
  { q: "A newly diagnosed AFib client asks about lifestyle modifications. Which teaching is most important?", o: ["Avoid all physical activity", "Limit alcohol intake, manage stress, maintain healthy weight, and report palpitations or neurological symptoms promptly", "Eat more vitamin K", "Increase sodium intake"], a: 1, r: "Alcohol is a known AFib trigger ('holiday heart'). Obesity, sleep apnea, and uncontrolled HTN worsen AFib. Reporting stroke symptoms (facial droop, weakness, speech changes) is critical for early intervention.", s: "Arrhythmias" },
  { q: "Which finding indicates digoxin toxicity in a client taking digoxin for AFib rate control?", o: ["Heart rate 78 bpm", "Nausea, visual disturbances (yellow-green halos), and new bradycardia", "Blood pressure 130/80", "INR 2.5"], a: 1, r: "Digoxin toxicity signs: GI (nausea, vomiting, anorexia), visual (yellow-green halos, blurred vision), cardiac (bradycardia, new arrhythmias). Therapeutic level: 0.5-2.0 ng/mL. Hypokalemia potentiates toxicity.", s: "Arrhythmias" },
  { q: "A client with AFib has a CHA2DS2-VASc score of 0 (male). What anticoagulation does the nurse anticipate?", o: ["Warfarin with INR 2-3", "No anticoagulation recommended — may consider aspirin or nothing", "Apixaban 5 mg BID", "Heparin infusion"], a: 1, r: "CHA2DS2-VASc 0 in males (1 in females for sex alone) is low risk. Guidelines recommend no anticoagulation or aspirin alone. Anticoagulation risk may outweigh benefit at very low stroke risk.", s: "Arrhythmias" },
  { q: "The nurse is teaching a client about apixaban (Eliquis) for AFib. Which statement by the client requires further teaching?", o: ["I will take it twice a day", "I can eat whatever I want without worrying about vitamin K", "I don't need regular blood tests to monitor the drug level", "I will stop taking it if I feel better"], a: 3, r: "Apixaban must be taken consistently as prescribed; stopping increases stroke risk. Unlike warfarin, DOACs don't require routine INR monitoring and don't interact with vitamin K foods.", s: "Arrhythmias" },
  { q: "During the transition from heparin to warfarin for AFib, when should heparin be discontinued?", o: ["When the first warfarin dose is given", "When INR has been therapeutic (2.0-3.0) for at least 24 hours AND at least 5 days of overlap", "After 24 hours of warfarin", "When aPTT normalizes"], a: 1, r: "Both criteria must be met: minimum 5 days overlap AND INR therapeutic for ≥24 hours. This ensures warfarin has fully depleted procoagulant factors. Early heparin discontinuation risks thrombosis.", s: "Arrhythmias" },
  { q: "A client with AFib develops sudden right arm weakness, facial droop, and slurred speech. What is the nurse's priority?", o: ["Check blood glucose", "Activate stroke protocol — time is critical for potential thrombolytic therapy", "Administer aspirin 325 mg", "Recheck INR"], a: 1, r: "These are signs of acute cardioembolic stroke, a major complication of AFib. Activate stroke protocol immediately for rapid assessment and potential tPA administration within the treatment window.", s: "Arrhythmias" },
  { q: "Which laboratory test should be checked in all new-onset AFib patients to rule out a reversible cause?", o: ["BNP", "TSH (thyroid function)", "Troponin", "D-dimer"], a: 1, r: "Hyperthyroidism can trigger AFib in up to 15% of thyrotoxic patients. TSH should be checked in all new AFib patients. Treating hyperthyroidism may resolve the AFib.", s: "Arrhythmias" },
  { q: "After successful cardioversion for AFib, how long should anticoagulation continue at minimum?", o: ["Can stop immediately after conversion", "At least 4 weeks post-cardioversion", "Only 24 hours", "Until the next provider visit"], a: 1, r: "Anticoagulation must continue ≥4 weeks after cardioversion regardless of rhythm status. Atrial stunning can allow thrombus formation even after rhythm restoration.", s: "Arrhythmias" },
  { q: "A client with mechanical mitral valve and AFib requires anticoagulation. Which agent is indicated?", o: ["Apixaban", "Rivaroxaban", "Warfarin — DOACs are contraindicated with mechanical valves", "Aspirin alone"], a: 2, r: "Mechanical heart valves require warfarin specifically. All DOACs are contraindicated due to increased thromboembolic events in clinical trials with mechanical valves.", s: "Arrhythmias" },
  { q: "The nurse observes a client's AFib rhythm strip change from irregular to regular at 72 bpm with visible P waves. What happened?", o: ["The client went into VTach", "The client spontaneously converted to normal sinus rhythm", "Equipment malfunction", "The client developed complete heart block"], a: 1, r: "Conversion from irregular AFib (no P waves) to a regular rhythm with visible P waves at a normal rate indicates restoration of normal sinus rhythm, either spontaneously or from medications.", s: "Arrhythmias" },
  { q: "Which medication is used for pharmacological cardioversion of recent-onset AFib?", o: ["Metoprolol", "Diltiazem", "Flecainide or amiodarone", "Digoxin"], a: 2, r: "Flecainide, propafenone, and amiodarone can convert AFib to sinus rhythm. Beta-blockers and CCBs are rate control agents that do not restore sinus rhythm.", s: "Arrhythmias" },
  { q: "What is the primary purpose of the Watchman device in AFib management?", o: ["Rate control", "Rhythm control", "Left atrial appendage occlusion as an alternative to long-term anticoagulation", "Pacemaker function"], a: 2, r: "The Watchman device occludes the LA appendage (source of >90% of thrombi in non-valvular AFib), providing stroke prevention for patients who cannot tolerate long-term anticoagulation.", s: "Arrhythmias" },
  { q: "A client with paroxysmal AFib reports episodes triggered by alcohol consumption. What is this phenomenon called?", o: ["Sick sinus syndrome", "Holiday heart syndrome", "Brugada syndrome", "WPW syndrome"], a: 1, r: "Holiday heart: AFib triggered by acute alcohol intake, even in structurally normal hearts. Named because it often presents after holiday binge drinking. Alcohol cessation can reduce or eliminate episodes.", s: "Arrhythmias" },
  { q: "A client on rivaroxaban for AFib is prescribed clarithromycin for pneumonia. What is the nurse's concern?", o: ["No interaction", "Clarithromycin inhibits CYP3A4 and P-glycoprotein, increasing rivaroxaban levels and bleeding risk", "Clarithromycin reduces rivaroxaban effectiveness", "Only affects warfarin"], a: 1, r: "Strong CYP3A4 inhibitors (clarithromycin, ketoconazole, ritonavir) significantly increase DOAC levels. Alternative antibiotics or dose adjustments may be needed. Review drug interactions for all DOACs.", s: "Arrhythmias" },
  { q: "What is the role of catheter ablation in AFib?", o: ["It replaces the need for all medications permanently", "Pulmonary vein isolation destroys triggers; indicated when medications fail or as first-line in select patients", "Only for atrial flutter", "Experimental with no proven benefit"], a: 1, r: "PVI targets ectopic foci from pulmonary veins triggering AFib. Success 60-80% for paroxysmal AFib. May need repeat procedures. First-line option in symptomatic patients who prefer a procedural approach.", s: "Arrhythmias" },
  { q: "A client with AFib on warfarin has been eating large amounts of kale for the past week. What effect will this have?", o: ["No effect", "Increased INR with higher bleeding risk", "Decreased INR with increased stroke risk due to vitamin K counteracting warfarin", "Increased heart rate"], a: 2, r: "Kale is very high in vitamin K, which counteracts warfarin's mechanism. Sudden increase in vitamin K intake decreases INR, reducing anticoagulation and increasing clot/stroke risk.", s: "Arrhythmias" },
  { q: "A nurse is monitoring a client during electrical cardioversion for AFib. What mode must the defibrillator be set to?", o: ["Unsynchronized (defibrillation mode)", "Synchronized mode to deliver shock on the R wave", "AED mode", "Pacing mode"], a: 1, r: "Synchronized cardioversion delivers the shock timed to the R wave, avoiding the vulnerable T-wave period which could cause VFib. Only use unsynchronized mode for pulseless VTach/VFib.", s: "Arrhythmias" },
  { q: "What vital sign assessment is most important for detecting AFib clinically?", o: ["Blood pressure", "Pulse assessment — noting irregularly irregular rhythm", "Respiratory rate", "Temperature"], a: 1, r: "An irregularly irregular pulse is the clinical hallmark of AFib. Routine pulse assessment can detect previously undiagnosed AFib. Confirm with ECG. Some patients are asymptomatic.", s: "Arrhythmias" },
  { q: "A client with lone AFib (no structural heart disease, age <65, no risk factors) has a CHA2DS2-VASc of 0. What is the recommended treatment?", o: ["Lifelong warfarin", "Rhythm control may be considered; anticoagulation is generally not recommended", "Immediate cardioversion", "ICD placement"], a: 1, r: "Lone AFib with CHA2DS2-VASc 0 has low stroke risk. Rate or rhythm control based on symptoms. Anticoagulation is not recommended. Reassess risk factors annually.", s: "Arrhythmias" },
  { q: "A client's telemetry shows AFib RVR at 160 bpm. HR was 80 on metoprolol yesterday. What should the nurse assess first?", o: ["Whether the client ate lunch", "Medication compliance — ask if metoprolol doses were taken", "Bowel movement history", "Sleep quality"], a: 1, r: "Sudden loss of rate control in previously well-controlled AFib should prompt assessment for missed medications, new triggers (infection, PE, thyrotoxicosis), or medication interactions.", s: "Arrhythmias" },
  { q: "The nurse notes the aPTT is 95 seconds (therapeutic range 60-80) on a heparin drip while bridging to warfarin for AFib. What is the priority action?", o: ["Continue the infusion", "Stop or reduce heparin per protocol and notify provider", "Increase the heparin rate", "Administer protamine"], a: 1, r: "Supratherapeutic aPTT indicates over-anticoagulation with bleeding risk. Follow the weight-based heparin protocol to hold or reduce the infusion and recheck aPTT.", s: "Arrhythmias" },
  { q: "A client with persistent AFib is prescribed amiodarone for rhythm control. What baseline test is essential before initiation?", o: ["Blood glucose", "Thyroid function (TSH), pulmonary function tests, liver function, and eye exam", "Urine culture", "Stool guaiac"], a: 1, r: "Amiodarone has significant organ toxicities: thyroid (hypo/hyperthyroidism — contains iodine), pulmonary fibrosis, hepatotoxicity, corneal microdeposits, peripheral neuropathy. Baseline testing establishes a comparison point for monitoring.", s: "Arrhythmias" },
  { q: "A client with AFib on dabigatran (Pradaxa) develops gross hematuria. What specific reversal agent does the nurse anticipate?", o: ["Vitamin K", "Protamine sulfate", "Idarucizumab (Praxbind)", "Andexanet alfa"], a: 2, r: "Idarucizumab is the specific reversal agent for dabigatran. It is a monoclonal antibody fragment that binds dabigatran with 350x greater affinity than thrombin, providing immediate reversal.", s: "Arrhythmias" },
  { q: "Why is aspirin monotherapy no longer recommended for stroke prevention in most AFib patients?", o: ["Aspirin is too effective", "Studies showed aspirin provides minimal stroke reduction compared to DOACs/warfarin while still carrying bleeding risk", "Aspirin causes AFib", "Cost is too high"], a: 1, r: "Clinical evidence shows aspirin provides minimal stroke prevention in AFib (compared to placebo) while still carrying significant bleeding risk. Oral anticoagulants are far superior for stroke prevention when indicated.", s: "Arrhythmias" },
  { q: "A client with AFib reports a recent increase in alcohol consumption. What education does the nurse provide?", o: ["Alcohol has no effect on AFib", "Alcohol is a well-established AFib trigger; even moderate intake can increase episode frequency and severity", "Alcohol helps with rate control", "Only spirits affect AFib"], a: 1, r: "Alcohol increases AFib risk dose-dependently. Even moderate drinking increases episode frequency. Alcohol causes atrial electrophysiological changes and direct myocardial toxicity. Reduce or eliminate consumption.", s: "Arrhythmias" },
  { q: "A client with controlled AFib on metoprolol develops pneumonia with high fever. The nurse notes HR has increased to 134 bpm. What is the most likely explanation?", o: ["Metoprolol stopped working", "Fever and infection increase sympathetic drive, overriding rate control effects of metoprolol", "New-onset VTach", "Equipment error"], a: 1, r: "Acute illness (fever, infection, sepsis) increases catecholamine release and sympathetic tone, which can overcome the rate-controlling effect of medications. This is appropriate sinus tachycardia or AFib RVR due to physiologic stress.", s: "Arrhythmias" },

  // ===== ATRIAL FLUTTER (35 questions) =====
  { q: "A nurse observes a regular tachycardia at 150 bpm on telemetry with no visible P waves. After administering adenosine, sawtooth waves become visible at 300 bpm. What is the rhythm?", o: ["Sinus tachycardia", "SVT", "Atrial flutter with 2:1 conduction", "VTach"], a: 2, r: "Adenosine transiently blocks AV conduction, unmasking sawtooth flutter waves at ~300 bpm. With 2:1 conduction (300/2=150 bpm). A regular tachycardia at exactly 150 bpm should always raise suspicion for atrial flutter.", s: "Arrhythmias" },
  { q: "A client with atrial flutter undergoes CTI ablation. What post-procedure teaching is appropriate?", o: ["The procedure rarely works", "Success rate exceeds 95%; monitor for recurrence symptoms and attend follow-up", "Lifelong bed rest required", "A pacemaker will be needed"], a: 1, r: "CTI ablation for typical atrial flutter has >95% success rate. Post-procedure: avoid strenuous activity 48 hours, monitor access site for bleeding, report recurrence symptoms, attend follow-up.", s: "Arrhythmias" },
  { q: "A client with atrial flutter is prescribed flecainide without an AV nodal blocking agent. What is the nurse's concern?", o: ["No concern", "Flecainide alone can slow atrial rate to allow 1:1 conduction, causing dangerously rapid ventricular rates", "Renal failure risk", "Flecainide is only for VTach"], a: 1, r: "Class IC drugs can slow flutter rate from 300 to 200 bpm, allowing 1:1 AV conduction with ventricular rates >200 bpm. Always co-prescribe an AV nodal blocker.", s: "Arrhythmias" },
  { q: "What is the typical atrial rate in atrial flutter?", o: ["60-100 bpm", "150-180 bpm", "250-350 bpm (approximately 300 bpm)", "400-600 bpm"], a: 2, r: "Typical atrial flutter has an atrial rate of approximately 300 bpm from a single macro-reentrant circuit around the tricuspid valve annulus. The ventricular rate depends on the conduction ratio (2:1, 3:1, 4:1).", s: "Arrhythmias" },
  { q: "A client with atrial flutter has 4:1 conduction. What is the expected ventricular rate?", o: ["300 bpm", "150 bpm", "100 bpm", "75 bpm"], a: 3, r: "With atrial rate of ~300 bpm and 4:1 conduction ratio: 300/4 = 75 bpm. Conduction ratios: 2:1 = 150, 3:1 = 100, 4:1 = 75 bpm.", s: "Arrhythmias" },
  { q: "Does atrial flutter carry stroke risk similar to AFib?", o: ["No stroke risk", "Yes, the same CHA2DS2-VASc guidelines and anticoagulation thresholds apply", "Much higher than AFib", "Only with diabetes"], a: 1, r: "Atrial flutter carries similar stroke risk to AFib. Same CHA2DS2-VASc scoring and anticoagulation guidelines apply. Many patients alternate between flutter and fibrillation.", s: "Arrhythmias" },
  { q: "What initial cardioversion energy is typical for atrial flutter?", o: ["360 J", "50-100 J biphasic", "200-300 J", "10 J"], a: 1, r: "Atrial flutter converts at lower energy (50-100 J biphasic) than AFib because it involves a single organized reentrant circuit rather than multiple chaotic wavelets.", s: "Arrhythmias" },
  { q: "What is the mechanism of typical atrial flutter?", o: ["Multiple ectopic foci", "Single macro-reentrant circuit counterclockwise around the tricuspid valve annulus through the CTI", "Delayed afterdepolarizations", "SA node automaticity"], a: 1, r: "Typical counterclockwise flutter involves a single macro-reentrant circuit traveling around the tricuspid valve annulus through the cavotricuspid isthmus.", s: "Arrhythmias" },
  { q: "A nurse notices flutter waves are best seen in which ECG leads?", o: ["V1-V2", "Leads II, III, and aVF (inferior leads)", "aVR and aVL", "V5-V6"], a: 1, r: "Sawtooth flutter waves are most prominent in inferior leads (II, III, aVF) where the characteristic pattern is most visible. They may be subtle or hidden in other leads.", s: "Arrhythmias" },
  { q: "A client with flutter on diltiazem develops BP 82/50. What is the nursing priority?", o: ["Increase diltiazem rate", "Stop infusion, position supine, IV fluids, notify provider, prepare IV calcium gluconate", "Give adenosine", "Wait for improvement"], a: 1, r: "Hypotension from IV diltiazem: stop infusion, position supine, IV NS bolus, notify provider. IV calcium gluconate can reverse CCB-mediated vasodilation and negative inotropy.", s: "Arrhythmias" },
  { q: "What is atypical atrial flutter?", o: ["Same as typical flutter", "Flutter circuit NOT using the CTI, often in left atrium, more difficult to ablate", "Flutter with bradycardia", "Flutter in children only"], a: 1, r: "Atypical flutter uses circuits outside the CTI (often LA or around surgical scars). Doesn't respond to CTI ablation and requires more complex mapping. Success rates are lower.", s: "Arrhythmias" },
  { q: "Post-cardiac surgery, a client develops a regular atrial tachycardia at 250 bpm. What should the nurse suspect?", o: ["Normal recovery", "Post-surgical incisional atrial flutter", "VTach", "Equipment malfunction"], a: 1, r: "Incisional atrial flutter is common after cardiac surgery. Surgical scars create barriers around which reentrant circuits form. Treatment includes antiarrhythmics and potentially catheter ablation.", s: "Arrhythmias" },
  { q: "What medication can be used for acute pharmacologic cardioversion of atrial flutter?", o: ["Metoprolol", "Ibutilide (Corvert) IV", "Digoxin", "Aspirin"], a: 1, r: "Ibutilide is an IV class III antiarrhythmic effective for acute cardioversion of flutter. Monitor for QT prolongation and Torsades risk during and 4-6 hours after administration.", s: "Arrhythmias" },
  { q: "A client on dofetilide for flutter maintenance must have what monitored?", o: ["Blood glucose", "QTc interval and renal function — dose adjustments based on creatinine clearance", "Liver enzymes only", "Hemoglobin"], a: 1, r: "Dofetilide requires QTc monitoring (hold if QTc >500 ms) and dose adjustment by CrCl. FDA mandates initiation in hospital with continuous telemetry for ≥3 days.", s: "Arrhythmias" },
  { q: "How does the nurse distinguish flutter from sinus tachycardia on ECG?", o: ["They look identical", "Flutter has sawtooth F waves with no isoelectric baseline; sinus tach has normal P waves before each QRS", "Flutter is always faster", "Sinus tach has wider QRS"], a: 1, r: "Flutter: sawtooth F waves at ~300 bpm with no isoelectric baseline between waves. Sinus tach: visible upright P waves preceding each QRS with an isoelectric baseline.", s: "Arrhythmias" },
  { q: "A client converts from flutter to AFib after rate control medication. Is this a treatment failure?", o: ["Yes, medication is wrong", "No — coexistence of flutter and AFib is common; many patients alternate between both", "This never happens", "Indicates allergy"], a: 1, r: "Flutter and AFib frequently coexist. Many patients alternate between both rhythms. This is clinically common and does not necessarily indicate treatment failure.", s: "Arrhythmias" },
  { q: "What complication should the nurse watch for after cardioversion of atrial flutter?", o: ["Hyperglycemia", "Thromboembolism (stroke) from dislodged atrial thrombus", "Hyperthermia", "Renal failure"], a: 1, r: "Post-cardioversion thromboembolism can occur from thrombus dislodgement. Pre-cardioversion anticoagulation or TEE is mandatory. Continue anticoagulation ≥4 weeks post-cardioversion.", s: "Arrhythmias" },
  { q: "A client with flutter has variable conduction ratios (2:1 alternating with 4:1). How does this appear on the monitor?", o: ["Regular at 150 bpm", "Irregular ventricular rhythm that can mimic AFib", "Wide complex tachycardia", "Normal sinus rhythm"], a: 1, r: "Variable conduction ratios produce irregular R-R intervals mimicking AFib. The key distinction is regular, organized flutter waves at ~300 bpm between QRS complexes.", s: "Arrhythmias" },
  { q: "What is the nurse's role during electrical cardioversion for flutter?", o: ["Administer the shock", "Ensure sedation, confirm synchronized mode, clear patient, monitor airway post-procedure", "Leave the room", "Only monitor BP after"], a: 1, r: "Nursing role: verify consent, ensure IV access, confirm sedation, verify synchronized mode, clear patient and staff, airway equipment at bedside, monitor post-procedure.", s: "Arrhythmias" },
  { q: "What risk factors are most commonly associated with atrial flutter?", o: ["Vitamin D deficiency", "Structural heart disease, COPD, prior cardiac surgery, PE, and heart failure", "Anemia alone", "Diabetes alone"], a: 1, r: "Flutter is most commonly associated with structural heart disease: right atrial enlargement (COPD, tricuspid disease, PE, ASD), post-cardiac surgery, prior MI, and heart failure.", s: "Arrhythmias" },
  { q: "A client with flutter is hemodynamically unstable. What is the initial cardioversion approach?", o: ["Pharmacologic cardioversion only", "Synchronized cardioversion starting at 50-100 J biphasic after adequate sedation", "Unsynchronized defibrillation", "Vagal maneuvers"], a: 1, r: "Unstable flutter: synchronized cardioversion with sedation. Start at 50-100 J biphasic. Always confirm synchronized mode to avoid T-wave shock.", s: "Arrhythmias" },
  { q: "Why might adenosine be given diagnostically in suspected atrial flutter?", o: ["To convert flutter to sinus rhythm", "To transiently block AV conduction and unmask hidden flutter waves for diagnosis", "To treat hypotension", "To increase heart rate"], a: 1, r: "Adenosine does not terminate flutter but transiently blocks AV conduction, revealing underlying sawtooth waves that may be hidden in QRS/T waves. Diagnostic maneuver only.", s: "Arrhythmias" },
  { q: "What discharge teaching does the nurse provide to a client with new atrial flutter diagnosis?", o: ["No lifestyle changes needed", "Take anticoagulation as prescribed, report palpitations or neurological symptoms, avoid excessive alcohol, attend follow-up for ablation discussion", "Only take medications when symptomatic", "Avoid all physical activity"], a: 1, r: "Teaching should address: medication adherence (especially anticoagulation), symptom reporting, stroke warning signs, lifestyle modifications, and follow-up planning including discussion of catheter ablation for definitive treatment.", s: "Arrhythmias" },
  { q: "Can atrial flutter occur with 1:1 conduction?", o: ["Yes, commonly at rest", "Rarely — typically occurs with sympathetic stimulation, exercise, or class IC drugs without AV blocking agents", "Only in children", "Never occurs"], a: 1, r: "1:1 conduction is uncommon at rest but can occur with enhanced AV conduction (exercise, sympathetic surge, fever) or when class IC drugs slow atrial rate enough for 1:1 conduction. Dangerously rapid ventricular rates can result.", s: "Arrhythmias" },
  { q: "A client with atrial flutter asks about amiodarone for long-term management. What is the nurse's understanding?", o: ["First-line for all flutter", "Amiodarone can be used but is not first-line; CTI ablation is preferred for typical flutter given high success rate and low complication rate", "Contraindicated in flutter", "Only for rate control"], a: 1, r: "CTI ablation is preferred definitive therapy for typical flutter due to >95% success and low risk. Amiodarone has significant long-term toxicities and is reserved for cases unsuitable for ablation.", s: "Arrhythmias" },
  { q: "What is the significance of a 2:1 conduction ratio in flutter being 'fixed' vs 'variable'?", o: ["No clinical significance", "Fixed 2:1 produces a regular rhythm at 150 bpm; variable conduction produces irregular rhythm that may be confused with AFib", "Fixed is always dangerous", "Variable is always benign"], a: 1, r: "Fixed 2:1 conduction = regular ventricular rhythm (typically 150 bpm). Variable conduction (2:1 alternating with 3:1 or 4:1) = irregular rhythm mimicking AFib. Identifying the underlying flutter waves is key.", s: "Arrhythmias" },
  { q: "Post-CTI ablation, a client reports palpitations 2 weeks later. What should the nurse advise?", o: ["This is normal and ignore it", "Report to the cardiologist — could indicate recurrence or development of AFib, which commonly coexists with flutter", "Go to the ER immediately", "Stop all medications"], a: 1, r: "Post-ablation palpitations may indicate flutter recurrence or new AFib (common in flutter patients). Early reporting allows prompt evaluation. Many flutter patients eventually develop AFib.", s: "Arrhythmias" },
  { q: "What is the primary difference between typical and atypical flutter in terms of treatment?", o: ["No treatment difference", "Typical flutter responds well to CTI ablation (>95% success); atypical requires more complex mapping and has lower ablation success rates", "Atypical flutter doesn't need treatment", "Both require heart transplant"], a: 1, r: "Typical flutter has a predictable CTI-dependent circuit amenable to simple ablation. Atypical circuits are more variable (often left atrial or scar-related), requiring complex 3D mapping with lower success rates.", s: "Arrhythmias" },
  { q: "A client with flutter and 2:1 block has a ventricular rate of 150 bpm. Rate control is started with IV diltiazem. The rate drops to 100 bpm. What likely happened?", o: ["Flutter converted to sinus rhythm", "The conduction ratio changed from 2:1 to 3:1 as AV node conduction slowed", "The client developed heart block", "Equipment malfunction"], a: 1, r: "Diltiazem slowed AV conduction, changing the conduction ratio from 2:1 (150 bpm) to 3:1 (100 bpm). The atrial rate remains at ~300 bpm. The ventricular response rate is controlled.", s: "Arrhythmias" },
  { q: "Why is anticoagulation equally important in atrial flutter as in AFib despite flutter having organized atrial contractions?", o: ["It isn't equally important", "Despite organized contractions, blood stasis still occurs, and most flutter patients also have or will develop AFib, maintaining stroke risk", "Flutter never causes strokes", "Only chronic flutter needs anticoagulation"], a: 1, r: "Flutter patients have similar stroke risk to AFib. Organized atrial contractions don't eliminate stasis risk, and most flutter patients eventually develop AFib. Same anticoagulation guidelines apply.", s: "Arrhythmias" },

  // ===== SVT (35 questions) =====
  { q: "A 28-year-old develops HR 188 bpm with narrow QRS complexes. BP 118/76 with palpitations. What is the first intervention?", o: ["Defibrillation", "Vagal maneuvers (modified Valsalva or carotid sinus massage)", "IV amiodarone", "Synchronized cardioversion"], a: 1, r: "For stable SVT, vagal maneuvers are first-line. Modified Valsalva increases parasympathetic tone to slow AV conduction and may terminate reentrant SVT.", s: "Arrhythmias" },
  { q: "The nurse prepares adenosine 6 mg IV for SVT. Which technique is correct?", o: ["Slow IV push over 5 minutes", "Rapid IV push 1-2 seconds through antecubital IV followed by 20 mL NS rapid flush", "Mix in 250 mL D5W infusion", "IM injection in deltoid"], a: 1, r: "Adenosine half-life <10 seconds. Must be rapid IV push through large proximal IV with immediate 20 mL NS flush. Slow administration results in metabolism before reaching the heart.", s: "Arrhythmias" },
  { q: "A client with known WPW develops AFib. Which medication is absolutely contraindicated?", o: ["Procainamide", "IV diltiazem — AV nodal blockers allow unopposed rapid accessory pathway conduction", "Ibutilide", "Flecainide"], a: 1, r: "In WPW with AFib, AV nodal blockers (diltiazem, verapamil, digoxin, adenosine) block normal AV conduction while allowing rapid accessory pathway conduction, potentially causing VFib and death.", s: "Arrhythmias" },
  { q: "After adenosine for SVT, the client has a brief asystolic pause then converts to sinus rhythm. The client is frightened. Best response?", o: ["Call code blue", "Reassure that a brief pause is expected and indicates the medication worked correctly", "Give atropine", "Prepare for pacemaker"], a: 1, r: "A brief pause after adenosine is expected as it transiently blocks AV conduction, terminating the reentrant circuit. Warn patients beforehand about chest tightness, flushing, and the brief pause.", s: "Arrhythmias" },
  { q: "What is the most common mechanism of paroxysmal SVT?", o: ["SA node dysfunction", "AV nodal reentrant tachycardia (AVNRT) — dual pathways within the AV node", "Ventricular ectopy", "Flutter with variable block"], a: 1, r: "AVNRT accounts for ~60% of SVT. It involves dual AV nodal pathways (slow and fast). The impulse typically travels down the slow pathway and up the fast pathway at 150-250 bpm.", s: "Arrhythmias" },
  { q: "What is the ECG hallmark of WPW syndrome?", o: ["Prolonged QT", "Delta wave, short PR (<0.12 sec), and wide QRS from ventricular pre-excitation", "Sawtooth waves", "ST elevation"], a: 1, r: "WPW: delta wave (slurred QRS upstroke), short PR (<0.12 sec), wide QRS (>0.12 sec) from pre-excitation through accessory pathway (Bundle of Kent) bypassing the AV node.", s: "Arrhythmias" },
  { q: "What distinguishes SVT from sinus tachycardia?", o: ["SVT always has wide QRS", "SVT has abrupt onset/offset at 150-250 bpm; sinus tach has gradual onset/offset with visible P waves", "They are identical", "Sinus tach is faster"], a: 1, r: "SVT: paroxysmal onset/termination, rate 150-250, P waves often buried. Sinus tach: gradual onset/offset, visible P waves, rate usually 100-150, responds to underlying cause.", s: "Arrhythmias" },
  { q: "What is the modified Valsalva maneuver technique?", o: ["Cough forcefully", "Bear down for 15 seconds semi-recumbent, then lie supine with legs elevated 45 degrees for 15 seconds", "Hold breath indefinitely", "Deep breathing exercises"], a: 1, r: "Modified Valsalva: strain 15 seconds, then lie flat with legs elevated 45° for 15 seconds. The postural modification increases venous return and enhances vagal response.", s: "Arrhythmias" },
  { q: "Why should carotid sinus massage NOT be performed on a client with a carotid bruit?", o: ["It won't work", "Risk of dislodging carotid plaque causing stroke", "It increases heart rate", "Bruits are normal"], a: 1, r: "Carotid bruit suggests atherosclerotic plaque. Massage could dislodge plaque causing carotid embolism and stroke. Also contraindicated in known carotid stenosis and recent stroke/TIA.", s: "Arrhythmias" },
  { q: "If adenosine fails for SVT, what is the second-line treatment?", o: ["Defibrillation", "IV diltiazem or IV metoprolol", "IV amiodarone", "Oral digoxin"], a: 1, r: "If adenosine fails (2 doses of 12 mg), IV diltiazem or IV metoprolol for hemodynamically stable SVT. If unstable at any point, proceed to synchronized cardioversion.", s: "Arrhythmias" },
  { q: "A client on dipyridamole has SVT. How does this affect adenosine dosing?", o: ["No interaction", "Dipyridamole potentiates adenosine — reduce initial dose to 3 mg", "Neutralizes adenosine", "Cannot give adenosine"], a: 1, r: "Dipyridamole inhibits adenosine reuptake, significantly potentiating effects. Reduce dose to 3 mg. Conversely, theophylline/caffeine are adenosine antagonists and may reduce effectiveness.", s: "Arrhythmias" },
  { q: "A child presents with SVT (HR 260). What vagal maneuver is most appropriate for a young child?", o: ["Carotid massage", "Apply ice-cold wet cloth to the face (diving reflex)", "Valsalva maneuver", "Eyeball pressure"], a: 1, r: "In infants/young children, the diving reflex is most effective: apply ice-cold wet cloth over the eyes and bridge of nose for 15-20 seconds. Triggers powerful vagal response.", s: "Arrhythmias" },
  { q: "When is catheter ablation indicated for SVT?", o: ["First episode only", "Recurrent symptomatic SVT, failed medications, or patient preference for definitive cure", "Only if AFib develops", "Never indicated"], a: 1, r: "Catheter ablation: indicated for recurrent SVT with symptoms, medication intolerance/failure, or patient preference. Success rates >95% for AVNRT and AVRT. Curative procedure.", s: "Arrhythmias" },
  { q: "If adenosine is given to a client with atrial flutter, what will happen?", o: ["It will cure flutter", "Adenosine will transiently slow AV conduction, unmasking the underlying flutter waves, but will NOT terminate flutter", "It will cause VFib", "No effect"], a: 1, r: "Adenosine terminates reentrant SVT involving the AV node but does NOT terminate flutter or AFib. It can be diagnostically useful by unmasking flutter waves.", s: "Arrhythmias" },
  { q: "A pregnant woman develops SVT. What special considerations apply?", o: ["All treatments are safe", "Adenosine is safe in pregnancy; avoid atenolol; cardioversion safe if unstable", "SVT cannot occur in pregnancy", "Only cesarean can treat SVT"], a: 1, r: "Adenosine is considered safe in pregnancy. Beta-blockers (metoprolol) can be used with monitoring. Cardioversion is safe at all stages if unstable. Avoid atenolol (fetal growth restriction).", s: "Arrhythmias" },
  { q: "What is the correct adenosine dose sequence for SVT?", o: ["6 mg, then 6 mg, then 6 mg", "6 mg, then 12 mg, then 12 mg if needed", "12 mg, then 24 mg", "3 mg only"], a: 1, r: "Adenosine: 6 mg rapid IV push. If no effect in 1-2 minutes, give 12 mg. A second 12 mg dose can be given if needed. Maximum single dose: 12 mg.", s: "Arrhythmias" },
  { q: "Why is adenosine relatively contraindicated in asthma?", o: ["Increases heart rate", "Can trigger bronchospasm through A1 receptor stimulation on bronchial smooth muscle", "Causes hyperglycemia", "No contraindication"], a: 1, r: "Adenosine can trigger significant bronchospasm via A1 receptor stimulation. Use with extreme caution in asthma. IV diltiazem is an alternative.", s: "Arrhythmias" },
  { q: "SVT converts after adenosine but recurs 20 minutes later. What does this suggest?", o: ["Adenosine failed", "The underlying substrate (dual pathways or accessory pathway) persists — recurrence is expected until definitive ablation", "Adenosine given too fast", "Allergic reaction"], a: 1, r: "Adenosine terminates the current episode but doesn't eliminate the substrate. SVT recurrence is expected. Options: long-term oral agents or catheter ablation for cure.", s: "Arrhythmias" },
  { q: "What energy is used for synchronized cardioversion of unstable SVT?", o: ["360 J", "50-100 J biphasic initially", "200 J", "5 J"], a: 1, r: "Synchronized cardioversion for SVT: 50-100 J biphasic initially. Confirm synchronized mode. Increase energy with subsequent attempts if unsuccessful.", s: "Arrhythmias" },
  { q: "What is the significance of 'pseudo-R wave in V1' during SVT?", o: ["Normal finding", "Suggests AVNRT — retrograde P waves buried in QRS create a pseudo-R' deflection", "Indicates STEMI", "Artifact"], a: 1, r: "In typical AVNRT, retrograde P waves occur simultaneously with QRS, creating a 'pseudo-R prime' in V1. Helps identify AVNRT as the SVT mechanism.", s: "Arrhythmias" },
  { q: "A client's SVT recurs frequently despite medications. The client declines ablation. What oral medication options exist?", o: ["Warfarin", "Beta-blockers, calcium channel blockers, or flecainide/propafenone for ongoing prevention", "Aspirin", "Lisinopril"], a: 1, r: "SVT prevention: beta-blockers (metoprolol) or CCBs (diltiazem/verapamil) first-line. Flecainide/propafenone if these fail (with AV nodal blocker). Ablation remains definitive cure.", s: "Arrhythmias" },
  { q: "What monitoring is essential during adenosine administration?", o: ["Blood glucose", "Continuous ECG rhythm strip recording to capture the moment of conversion", "Urine output", "Pupil checks"], a: 1, r: "Run continuous rhythm strip during adenosine to capture the response. The transient AV block and any underlying rhythm revealed aids diagnosis. Also monitor for prolonged pauses and bronchospasm.", s: "Arrhythmias" },
  { q: "What happens when SVT does not terminate with adenosine and the client becomes unstable?", o: ["Try more adenosine", "Immediate synchronized cardioversion — do not delay", "IV antibiotics", "Chest X-ray"], a: 1, r: "If pharmacologic measures fail and the client becomes unstable (hypotension, AMS, chest pain), proceed immediately to synchronized cardioversion.", s: "Arrhythmias" },
  { q: "A client reports 'my heart suddenly starts racing and then suddenly stops.' What does this suggest?", o: ["Anxiety attack", "Paroxysmal SVT — characterized by abrupt onset and termination", "Normal sinus variation", "Ventricular tachycardia"], a: 1, r: "The abrupt onset ('turn on/off like a switch') is classic for paroxysmal SVT (AVNRT or AVRT). Sinus tachycardia has gradual onset/offset. Ambulatory monitoring (Holter/event recorder) may be needed for diagnosis.", s: "Arrhythmias" },
  { q: "What is AVRT and how does it relate to WPW?", o: ["They are unrelated", "AVRT uses an accessory pathway (as in WPW) as one limb of the reentrant circuit between atria and ventricles", "AVRT is a ventricular arrhythmia", "WPW prevents AVRT"], a: 1, r: "AVRT uses an accessory pathway (e.g., Bundle of Kent in WPW) as one circuit limb. Orthodromic AVRT: down AV node, up accessory pathway (narrow QRS). Antidromic: opposite direction (wide QRS).", s: "Arrhythmias" },
  { q: "A client with SVT is on verapamil for prevention. What should the nurse monitor?", o: ["Only heart rate", "Blood pressure (hypotension risk), heart rate (bradycardia), constipation, and signs of heart failure", "Only blood glucose", "Only temperature"], a: 1, r: "Verapamil side effects: hypotension, bradycardia, constipation (common), and negative inotropy (caution in HF). Monitor BP, HR, bowel function, and for symptoms of heart failure.", s: "Arrhythmias" },
  { q: "What makes SVT different from VTach on a 12-lead ECG?", o: ["Can't tell the difference", "SVT has narrow QRS complexes (<0.12 sec); VTach has wide QRS complexes (>0.12 sec) with AV dissociation", "SVT is always slower", "VTach has P waves before each QRS"], a: 1, r: "SVT: narrow QRS (<0.12 sec) because ventricular activation occurs normally through the His-Purkinje system. VTach: wide QRS (>0.12 sec) with possible AV dissociation, capture beats, and fusion beats.", s: "Arrhythmias" },
  { q: "A client has SVT with BP 80/50 and chest pain. Vagal maneuvers failed. What is the next step?", o: ["Adenosine 6 mg", "Immediate synchronized cardioversion with sedation", "IV metoprolol", "Observe for 30 minutes"], a: 1, r: "Unstable SVT (hypotension + chest pain) after failed vagal maneuvers requires immediate synchronized cardioversion. Do not delay for adenosine when hemodynamically unstable.", s: "Arrhythmias" },
  { q: "What is the 'pill-in-the-pocket' approach for SVT?", o: ["Daily aspirin", "Self-administering a single dose of flecainide or propafenone at symptom onset for infrequent episodes", "Wearing a Holter monitor", "Taking digoxin daily"], a: 1, r: "For select patients with infrequent SVT, a single oral dose of flecainide or diltiazem+propranolol can terminate episodes at home. Must first tolerate the drug under monitored conditions.", s: "Arrhythmias" },
  { q: "What post-ablation complication should the nurse monitor for after SVT ablation?", o: ["Only bleeding at access site", "AV block (risk of pacemaker need), cardiac perforation/tamponade, femoral access complications, and recurrence", "Hair loss", "Renal failure"], a: 1, r: "Post-SVT ablation risks: AV block if ablation near AV node (may need permanent pacemaker, ~1% risk), cardiac perforation/tamponade, vascular access complications, and SVT recurrence.", s: "Arrhythmias" },
  { q: "A nurse notes that a client's SVT rate is 220 bpm with 1:1 P-QRS relationship and short RP interval. What mechanism is most likely?", o: ["Sinus tachycardia", "Typical AVNRT — short RP interval indicates near-simultaneous atrial and ventricular activation", "Atrial flutter", "Complete heart block"], a: 1, r: "Short RP interval (P wave immediately after QRS) is typical of AVNRT where retrograde atrial activation occurs nearly simultaneously with ventricular activation through the fast pathway.", s: "Arrhythmias" },

  // ===== VENTRICULAR TACHYCARDIA (35 questions) =====
  { q: "A nurse finds a client unresponsive with wide-complex tachycardia at 180 bpm. No pulse. What is the immediate action?", o: ["Administer atropine", "Begin CPR and prepare for defibrillation", "Administer adenosine", "12-lead ECG"], a: 1, r: "Pulseless VTach = cardiac arrest. Treat like VFib: immediate CPR and defibrillation (unsynchronized shock). ACLS pulseless arrest algorithm applies.", s: "Arrhythmias" },
  { q: "A client develops sustained VTach with a pulse. BP 92/64, diaphoretic. What is the priority?", o: ["IV amiodarone", "Synchronized cardioversion", "Vagal maneuvers", "IV diltiazem"], a: 1, r: "Hemodynamically unstable VTach with pulse requires immediate synchronized cardioversion. Synchronized mode avoids T-wave shock. Amiodarone is for stable VTach.", s: "Arrhythmias" },
  { q: "A 6-beat run of wide-complex tachycardia at 160 bpm self-terminates. Classification?", o: ["Sustained VTach", "Non-sustained VTach (NSVT)", "PVCs", "SVT with aberrancy"], a: 1, r: "NSVT: ≥3 consecutive PVCs at >100 bpm lasting <30 seconds that self-terminates. Warrants evaluation for structural heart disease.", s: "Arrhythmias" },
  { q: "A client develops Torsades de Pointes with prolonged QT. First-line treatment?", o: ["IV amiodarone", "IV magnesium sulfate 1-2 grams", "Cardioversion at 50 J", "IV lidocaine"], a: 1, r: "Torsades (polymorphic VTach with prolonged QT): IV magnesium 1-2 g. Amiodarone CONTRAINDICATED (prolongs QT and worsens Torsades). May need overdrive pacing or isoproterenol.", s: "Arrhythmias" },
  { q: "Which medications prolong QT and increase Torsades risk?", o: ["Amiodarone, sotalol, and haloperidol", "Metoprolol and lisinopril", "Aspirin and acetaminophen", "Insulin and metformin"], a: 0, r: "QT-prolonging drugs: antiarrhythmics (amiodarone, sotalol), antipsychotics (haloperidol), antibiotics (azithromycin, fluoroquinolones), antiemetics (ondansetron), methadone. Monitor QTc.", s: "Arrhythmias" },
  { q: "Stable sustained monomorphic VTach with a pulse: what is the first-line drug?", o: ["Defibrillation", "IV amiodarone 150 mg over 10 minutes", "Vagal maneuvers", "Transcutaneous pacing"], a: 1, r: "Hemodynamically stable VTach with pulse: IV amiodarone 150 mg over 10 min. Have defibrillator at bedside in case of deterioration.", s: "Arrhythmias" },
  { q: "First assessment for wide-complex tachycardia on the monitor?", o: ["12-lead ECG", "Check pulse and hemodynamic status", "Administer oxygen", "Call rapid response"], a: 1, r: "Check pulse first. Pulseless → defibrillation + CPR. Pulse + unstable → synchronized cardioversion. Stable → pharmacologic therapy. Pulse determines entire treatment pathway.", s: "Arrhythmias" },
  { q: "Why synchronized cardioversion for VTach with pulse?", o: ["Uses less energy", "Synchronized mode delivers shock on R wave, avoiding T-wave vulnerability which could trigger VFib", "Less painful", "No difference"], a: 1, r: "Synchronized cardioversion times shock to R wave, avoiding the T-wave vulnerable period. Shocking on T wave could trigger VFib.", s: "Arrhythmias" },
  { q: "Most common causes of VTach?", o: ["Dehydration", "CAD, prior MI (scar reentry), cardiomyopathy, electrolyte imbalances", "URI", "UTI"], a: 1, r: "Common VTach causes: CAD, prior MI (scar reentry), cardiomyopathy, electrolyte imbalances (hypokalemia, hypomagnesemia), drug toxicity.", s: "Arrhythmias" },
  { q: "What electrolyte abnormality is most commonly associated with VTach?", o: ["Hypernatremia", "Hypokalemia", "Hypercalcemia", "Hypermagnesemia"], a: 1, r: "Hypokalemia increases myocardial automaticity and prolongs repolarization. Maintain K+ >4.0 mEq/L in cardiac patients.", s: "Arrhythmias" },
  { q: "What is an ICD and when is it indicated?", o: ["A temporary pacing device", "Implantable cardioverter-defibrillator for patients surviving cardiac arrest or with EF ≤35%", "External defibrillator", "A type of monitor"], a: 1, r: "ICD detects VTach/VFib and delivers automatic therapy. Indications: cardiac arrest survivors, EF ≤35% with HF, HCM with risk factors.", s: "Arrhythmias" },
  { q: "When in doubt about wide-complex tachycardia (VTach vs SVT with aberrancy), how should the nurse treat?", o: ["Assume SVT", "Treat as VTach — safer to treat SVT as VTach than vice versa", "Wait for 12-lead", "Give diltiazem"], a: 1, r: "Cardinal rule: when uncertain, treat as VTach. VTach protocols are safe for SVT. SVT medications (CCBs) given to VTach can cause collapse.", s: "Arrhythmias" },
  { q: "What is AV dissociation on ECG during wide-complex tachycardia?", o: ["Normal finding", "P waves and QRS at different rates — strongly suggests VTach over SVT", "Only in heart block", "Indicates flutter"], a: 1, r: "AV dissociation (independent P and QRS rates) is a hallmark of VTach. In SVT with aberrancy, 1:1 P-QRS relationship is maintained.", s: "Arrhythmias" },
  { q: "Alternative medication to amiodarone for stable VTach?", o: ["Adenosine", "IV lidocaine or IV procainamide", "Diltiazem", "Atropine"], a: 1, r: "IV lidocaine (class IB) is an alternative, especially in acute MI. IV procainamide effective but causes hypotension with slow infusion. Both are second-line after amiodarone.", s: "Arrhythmias" },
  { q: "A post-MI client has frequent PVCs and NSVT. What does the nurse anticipate?", o: ["No intervention needed", "Telemetry, electrolyte correction, possible amiodarone, and ICD evaluation", "Immediate pacemaker", "Discharge"], a: 1, r: "Frequent PVCs and NSVT post-MI indicate irritable myocardium. Correct K+/Mg2+, continuous telemetry, consider amiodarone, evaluate EF for ICD.", s: "Arrhythmias" },
  { q: "What is ventricular storm?", o: ["A single PVC", "Three or more sustained VTach/VFib episodes within 24 hours — a cardiac emergency", "Occasional NSVT", "Normal variant"], a: 1, r: "Ventricular storm: ≥3 sustained VTach/VFib in 24 hours. Requires ICU, IV amiodarone/lidocaine, sedation, beta-blocker optimization, electrolyte correction, possibly ablation.", s: "Arrhythmias" },
  { q: "A client with an ICD receives multiple appropriate shocks. What nursing care is needed?", o: ["Ignore the shocks", "Assess consciousness and hemodynamics, obtain rhythm strip, notify provider, provide emotional support", "Remove the ICD", "Give adenosine"], a: 1, r: "After ICD shocks: assess consciousness, obtain ECG/rhythm strip, assess symptoms, notify provider, document events. Multiple appropriate shocks may indicate ventricular storm requiring additional therapy.", s: "Arrhythmias" },
  { q: "What is the recommended initial energy for cardioversion of stable VTach with pulse?", o: ["50 J", "100 J biphasic initially", "360 J", "10 J"], a: 1, r: "Synchronized cardioversion for monomorphic VTach: start at 100 J biphasic. Escalate with subsequent attempts. Confirm synchronized mode.", s: "Arrhythmias" },
  { q: "A client on amiodarone develops VTach with QTc 620 ms. What should the nurse suspect?", o: ["Amiodarone working", "Amiodarone-induced Torsades — stop amiodarone, give IV magnesium", "Normal QTc", "Need higher amiodarone dose"], a: 1, r: "QTc >500 ms with polymorphic VTach = drug-induced Torsades. Stop amiodarone, give IV magnesium, avoid all QT-prolonging drugs.", s: "Arrhythmias" },
  { q: "A client with VTach has magnesium 1.0 mEq/L. Priority?", o: ["Ignore Mg level", "Replace magnesium IV — hypomagnesemia increases VTach risk", "Restrict magnesium", "Increase calcium"], a: 1, r: "Hypomagnesemia predisposes to VTach and Torsades. IV magnesium sulfate 1-2 g, then maintenance. Critical to correct alongside potassium.", s: "Arrhythmias" },
  { q: "What is polymorphic VTach WITHOUT prolonged QT?", o: ["Torsades de Pointes", "Often due to myocardial ischemia — treat with amiodarone (not magnesium) and urgent revascularization", "Normal rhythm", "Atrial flutter"], a: 1, r: "Polymorphic VTach with normal QT is NOT Torsades. Amiodarone IS appropriate. Most common cause is acute ischemia requiring urgent catheterization.", s: "Arrhythmias" },
  { q: "What is anti-tachycardia pacing (ATP) from an ICD?", o: ["External pacing", "Rapid burst pacing faster than VTach to interrupt the reentry circuit without a shock", "Slow pacing for bradycardia", "Cardiac resynchronization"], a: 1, r: "ATP: painless burst pacing slightly faster than VTach rate to capture myocardium and terminate reentry. Tried before shock for tolerated VTach to avoid painful defibrillation.", s: "Arrhythmias" },
  { q: "A client with an ICD is receiving inappropriate shocks. What should the nurse do?", o: ["Tell patient to tolerate it", "Place magnet over ICD to disable shock therapy, notify provider for urgent device interrogation", "Remove ICD", "Give adenosine"], a: 1, r: "Magnet over ICD temporarily disables tachyarrhythmia therapy without affecting pacing. Appropriate for inappropriate shocks (AFib, lead fracture, noise). Arrange urgent interrogation.", s: "Arrhythmias" },
  { q: "What is capture beat and fusion beat and what do they confirm?", o: ["Artifact", "Capture beat: normal QRS during VTach; Fusion beat: hybrid QRS — both confirm VTach diagnosis by proving AV dissociation", "Signs of SVT", "Equipment error"], a: 1, r: "Capture beats and fusion beats prove AV dissociation, confirming VTach. Capture: sinus impulse captures ventricle. Fusion: simultaneous ventricular and supraventricular activation.", s: "Arrhythmias" },
  { q: "A client is at risk for VTach from hypokalemia. What potassium level should be maintained in cardiac patients?", o: ["3.0 mEq/L", "Greater than 4.0 mEq/L to reduce arrhythmia risk", "5.5 mEq/L", "2.5 mEq/L"], a: 1, r: "Cardiac patients should maintain K+ >4.0 mEq/L (some guidelines say >4.5 mEq/L) to reduce arrhythmia risk. This is higher than the general normal range lower limit of 3.5 mEq/L.", s: "Arrhythmias" },
  { q: "What teaching does the nurse provide to a client with a new ICD?", o: ["No restrictions", "Avoid strong magnetic fields, carry device ID card, report ICD shocks, do not drive for specified period, and attend regular device checks", "Avoid all exercise", "No follow-up needed"], a: 1, r: "ICD teaching: carry ID, avoid strong magnets, report shocks, driving restrictions per guideline, MRI compatibility check, regular device interrogation schedule, CPR training for family.", s: "Arrhythmias" },
  { q: "A nurse observes VTach on the monitor but the client is sitting up, talking, and has normal vital signs. What is the first thing to check?", o: ["Give amiodarone immediately", "Verify the rhythm by assessing the patient — could be artifact from patient movement or lead issue", "Defibrillate immediately", "Start CPR"], a: 1, r: "Always correlate the monitor with the patient's clinical condition. Artifact from movement, loose leads, or tremor can mimic VTach. Assess the patient first. If truly VTach with stable vitals, proceed with treatment.", s: "Arrhythmias" },
  { q: "What is the difference between monomorphic and polymorphic VTach?", o: ["No difference", "Monomorphic: uniform QRS morphology (single reentry circuit). Polymorphic: varying QRS morphology (multiple foci or ischemia)", "Polymorphic is slower", "Monomorphic is always benign"], a: 1, r: "Monomorphic VTach has consistent QRS appearance (one reentry focus). Polymorphic has changing QRS complexes. Polymorphic with prolonged QT = Torsades. Polymorphic with normal QT often = ischemia.", s: "Arrhythmias" },
  { q: "During stable VTach treatment with IV amiodarone, what vital sign requires close monitoring?", o: ["Temperature", "Blood pressure — amiodarone can cause hypotension, especially during the IV loading dose", "Respiratory rate only", "Urine output only"], a: 1, r: "IV amiodarone commonly causes hypotension due to vasodilation (from the diluent polysorbate 80 in older formulations). Monitor BP closely. Slow the infusion rate if hypotension occurs.", s: "Arrhythmias" },
  { q: "A client with VTach is also taking digoxin. What should the nurse consider?", o: ["No interaction", "Digoxin toxicity can cause VTach — check digoxin level and potassium", "Give more digoxin", "Digoxin treats VTach"], a: 1, r: "Digoxin toxicity is a cause of ventricular arrhythmias. Check serum digoxin level (therapeutic 0.5-2.0 ng/mL) and potassium (hypokalemia potentiates toxicity). Digibind (digoxin immune Fab) is the antidote for life-threatening digoxin toxicity.", s: "Arrhythmias" },

  // ===== VENTRICULAR FIBRILLATION (35 questions) =====
  { q: "A nurse discovers a client in VFib. The defibrillator is available. What is the correct sequence?", o: ["Give epinephrine first", "Begin CPR while charging defibrillator, deliver shock, immediately resume CPR", "Check 12-lead ECG", "Call provider and wait"], a: 1, r: "Per ACLS: CPR while defibrillator charges, single shock 120-200J biphasic, immediate CPR for 2 min before rhythm check. Early defibrillation is definitive — survival drops 7-10% per minute delay.", s: "Arrhythmias" },
  { q: "During VFib arrest, the monitor shows flat line after the third shock. Leads confirmed connected. What rhythm is this?", o: ["Fine VFib", "Asystole — a non-shockable rhythm", "Normal sinus", "PEA"], a: 1, r: "After confirming leads and checking multiple leads, flat line = asystole (non-shockable). Continue CPR, epinephrine q3-5 min, identify reversible causes. Do NOT shock asystole.", s: "Arrhythmias" },
  { q: "After ROSC from VFib, what is critical post-arrest care?", o: ["Immediate discharge", "Targeted temperature management at 32-36°C for at least 24 hours", "Prophylactic antibiotics", "Liberal fluid resuscitation"], a: 1, r: "TTM 32-36°C for ≥24 hours reduces cerebral metabolic demand and limits reperfusion injury. Monitor for bradycardia, coagulopathy, electrolyte shifts, and shivering.", s: "Arrhythmias" },
  { q: "Which reversible cause should the nurse suspect in a drowning victim who develops VFib?", o: ["Toxins", "Hypothermia and hypoxia", "Thrombosis", "Tension pneumothorax"], a: 1, r: "Drowning: hypothermia + hypoxia (both H's). Hypothermia causes refractory VFib. 'No one is dead until warm and dead' — rewarm before terminating resuscitation.", s: "Arrhythmias" },
  { q: "When is epinephrine first given in the ACLS VFib algorithm?", o: ["Before first shock", "After the second shock during CPR", "After amiodarone", "After ROSC only"], a: 1, r: "Epinephrine 1 mg IV/IO after second shock during CPR. Repeat q3-5 min. Amiodarone 300 mg after third shock.", s: "Arrhythmias" },
  { q: "What are the H's and T's of reversible cardiac arrest causes?", o: ["History and Treatment", "Hypovolemia, Hypoxia, Acidosis, Hypo/Hyperkalemia, Hypothermia; Tension pneumo, Tamponade, Toxins, Thrombosis", "Head injury and Trauma", "Heart rate and Temperature"], a: 1, r: "H's: Hypovolemia, Hypoxia, H+ (acidosis), Hypo/Hyperkalemia, Hypothermia. T's: Tension pneumothorax, Tamponade, Toxins, Thrombosis (PE/coronary).", s: "Arrhythmias" },
  { q: "How to differentiate fine VFib from asystole?", o: ["Identical treatment", "Check multiple leads — fine VFib shows fibrillatory activity in other leads", "Fine VFib has QRS", "Asystole has P waves"], a: 1, r: "Confirm in multiple leads (rotate 90°). Fine VFib shows low-amplitude fibrillatory activity. VFib is shockable; asystole is NOT. Check electrode connections and gain.", s: "Arrhythmias" },
  { q: "Recommended CPR rate and depth for adults?", o: ["60/min, 1 inch", "100-120/min, at least 2 inches (5 cm)", "200/min, 3 inches", "80/min, 1.5 inches"], a: 1, r: "High-quality CPR: 100-120/min, ≥2 inches but ≤2.4 inches, full chest recoil, minimize interruptions, rotate compressors q2 min.", s: "Arrhythmias" },
  { q: "What is the amiodarone dose for refractory VFib?", o: ["150 mg", "300 mg IV push first dose, then 150 mg second dose", "600 mg", "50 mg"], a: 1, r: "VFib: amiodarone 300 mg IV/IO push after third shock. Second dose 150 mg if VFib persists. Lidocaine 1-1.5 mg/kg is alternative.", s: "Arrhythmias" },
  { q: "Compression-to-ventilation ratio for 2-rescuer adult CPR with advanced airway?", o: ["30:2", "Continuous compressions at 100-120/min with 1 breath every 6 seconds", "15:2", "5:1"], a: 1, r: "With advanced airway: continuous compressions (no pauses) at 100-120/min. Ventilations: 1 breath every 6 sec (10/min). Without advanced airway: 30:2 with pauses.", s: "Arrhythmias" },
  { q: "What does end-tidal CO2 monitoring tell us during cardiac arrest?", o: ["Oxygen levels", "ETCO2 correlates with CPR quality; sudden rise may indicate ROSC", "Hemoglobin levels", "Only useful post-ROSC"], a: 1, r: "ETCO2 during arrest: correlates with CPR quality (target >10 mmHg). Sudden sustained rise often indicates ROSC. ETCO2 <10 after 20 min may suggest poor prognosis.", s: "Arrhythmias" },
  { q: "Why must chest compression interruptions be minimized during VFib arrest?", o: ["Saves time", "Each interruption drops coronary perfusion pressure to zero — longer pauses worsen outcomes", "No reason", "Compressor fatigue only"], a: 1, r: "CPP drops to zero immediately with any pause and takes multiple compressions to rebuild. Pre/post-shock pauses <10 seconds. Higher CPP correlates with ROSC.", s: "Arrhythmias" },
  { q: "A VFib arrest patient has suspected hyperkalemia (renal failure). What additional intervention?", o: ["Kayexalate only", "IV calcium chloride, sodium bicarbonate, insulin/dextrose to emergently lower potassium", "Restrict IV fluids", "Oral potassium"], a: 1, r: "Hyperkalemia (H's and T's): IV calcium (membrane stabilizer), sodium bicarbonate, insulin/D50, albuterol (all shift K+ intracellularly). Dialysis post-ROSC if needed.", s: "Arrhythmias" },
  { q: "Recommended defibrillation energy for first shock in VFib?", o: ["50 J", "120-200 J biphasic (or 360 J monophasic)", "10 J", "400 J"], a: 1, r: "First shock: 120-200 J biphasic (device-specific) or 360 J monophasic. Use maximum energy if unsure. Subsequent shocks at same or escalating levels.", s: "Arrhythmias" },
  { q: "A witnessed VFib arrest occurs in the ICU with immediate defibrillator availability. Should CPR be started before defibrillation?", o: ["Always CPR first for 2 minutes", "Shock ASAP; brief CPR while charging is acceptable for witnessed arrest with available defibrillator", "Never start CPR if defibrillator available", "Only CPR"], a: 1, r: "For witnessed VFib with immediately available defibrillator: defibrillate ASAP. Perform CPR while charging. Early defibrillation <3 min has highest survival.", s: "Arrhythmias" },
  { q: "Why should IV push medications in cardiac arrest be followed by a 20 mL flush?", o: ["To hydrate", "To push medication from peripheral IV into central circulation since there is no cardiac output", "No reason", "To dilute medication"], a: 1, r: "During arrest, no cardiac output means medications must be pushed centrally by CPR-generated flow. 20 mL flush ensures delivery from peripheral to central circulation.", s: "Arrhythmias" },
  { q: "Post-ROSC, the client has ST elevation on 12-lead ECG. What should the nurse anticipate?", o: ["Repeat arrest only", "Emergent cardiac catheterization/PCI — acute MI may have caused the arrest", "No further workup", "Discharge planning"], a: 1, r: "Post-ROSC STEMI requires emergent catheterization regardless of neurological status. Acute MI is a common VFib cause. Early PCI improves survival.", s: "Arrhythmias" },
  { q: "What is the nurse's documentation responsibility during a code?", o: ["Only after code ends", "Dedicated recorder documents: time of arrest, all interventions with times, medications with doses, rhythm changes, defibrillation attempts", "No documentation needed", "Only medications"], a: 1, r: "Code recorder documents real-time: arrest time, CPR start, rhythm changes, defibrillation (time, energy), medications (drug, dose, route, time), ROSC/death time.", s: "Arrhythmias" },
  { q: "What is the 'single-shock strategy' in ACLS?", o: ["Multiple rapid shocks", "One shock followed by immediate 2-minute CPR before rhythm check — avoids prolonged compression interruptions", "One shock then stop", "No shocks needed"], a: 1, r: "Current ACLS: single shock then immediate CPR for 2 minutes before rechecking rhythm. Stacking shocks creates prolonged pauses without compressions, dropping CPP.", s: "Arrhythmias" },
  { q: "Post-cardiac arrest neurological prognostication should occur when?", o: ["Immediately after ROSC", "At least 72 hours post-arrest using multimodal assessment", "At 6 hours", "Not needed"], a: 1, r: "Prognostication should NOT be early. Wait ≥72 hours post-ROSC (after TTM rewarming). Use multimodal: clinical exam, EEG, SSEP, MRI, NSE biomarkers.", s: "Arrhythmias" },
  { q: "What post-arrest complication is the most common cause of death after ROSC?", o: ["Renal failure", "Anoxic brain injury — the leading cause of mortality post-cardiac arrest", "Infection", "GI bleeding"], a: 1, r: "Post-cardiac arrest syndrome: anoxic brain injury (leading cause of death), global myocardial stunning, systemic ischemia-reperfusion injury, and precipitating cause.", s: "Arrhythmias" },
  { q: "During CPR, what is the maximum perishock pause?", o: ["30 seconds", "Less than 10 seconds", "60 seconds", "No limit"], a: 1, r: "Perishock pause (time between last compression and shock delivery) should be <10 seconds. Resume compressions immediately after each shock.", s: "Arrhythmias" },
  { q: "What is the role of vasopressin in current ACLS cardiac arrest guidelines?", o: ["First-line vasopressor", "Removed from ACLS guidelines; epinephrine is the only recommended vasopressor", "Used before epinephrine", "Replaces amiodarone"], a: 1, r: "Vasopressin was removed from 2015 ACLS guidelines. Epinephrine 1 mg IV q3-5 min is the only recommended vasopressor. Vasopressin showed no survival benefit.", s: "Arrhythmias" },
  { q: "What does coarse vs fine VFib indicate clinically?", o: ["No clinical difference", "Coarse VFib has higher amplitude and better defibrillation response; fine VFib may indicate prolonged arrest with less energy in the myocardium", "Coarse is worse prognosis", "Fine is always artifact"], a: 1, r: "Coarse VFib (higher amplitude) generally responds better to defibrillation and indicates more recent onset. Fine VFib (low amplitude) may indicate prolonged arrest or ischemic myocardium with worse prognosis.", s: "Arrhythmias" },
  { q: "A client in VFib arrest has a suspected tension pneumothorax. What specific intervention is needed alongside ACLS?", o: ["Chest X-ray first", "Needle decompression of the affected side — a reversible T cause of arrest", "Wait for surgical consult", "Additional epinephrine"], a: 1, r: "Tension pneumothorax (T's) causes pulseless electrical activity or VFib by compressing the heart and great vessels. Needle decompression at 2nd ICS midclavicular line is lifesaving during arrest. Don't wait for CXR.", s: "Arrhythmias" },

  // ===== HEART BLOCKS (35 questions) =====
  { q: "A nurse interprets an ECG showing PR interval 0.28 sec with 1:1 P-to-QRS conduction. Which heart block?", o: ["Second-degree Type I", "Second-degree Type II", "First-degree AV block", "Third-degree"], a: 2, r: "First-degree AV block: PR >0.20 sec with 1:1 conduction maintained. Usually benign, no treatment unless symptomatic.", s: "Arrhythmias" },
  { q: "Progressive PR prolongation from 0.22 to 0.34, then dropped QRS. Cycle repeats. What rhythm?", o: ["First-degree", "Second-degree Type I (Wenckebach)", "Second-degree Type II", "Third-degree"], a: 1, r: "Progressively lengthening PR culminating in a dropped QRS = Wenckebach. At AV node level, often benign. Seen in inferior MI, digoxin use, athletes.", s: "Arrhythmias" },
  { q: "Anterior MI develops sudden second-degree block with constant PR and intermittent dropped QRS with wide QRS. What is the significance?", o: ["Benign Wenckebach", "Mobitz Type II — high risk of complete heart block, pacemaker required", "First-degree only", "Normal in anterior MI"], a: 1, r: "Mobitz II in anterior MI indicates infranodal block. High risk of sudden complete heart block. Pacemaker indicated. Unlike Wenckebach with inferior MI, this rarely resolves.", s: "Arrhythmias" },
  { q: "Complete heart block with ventricular escape 32 bpm, hypotension, AMS. Atropine failed. Next intervention?", o: ["Repeat atropine", "Transcutaneous pacing", "Adenosine", "Position flat"], a: 1, r: "When atropine fails for complete heart block (often infranodal, doesn't respond to vagolytic therapy), transcutaneous pacing is next. Set rate 60-80, increase mA until capture.", s: "Arrhythmias" },
  { q: "Pacing spikes on monitor without QRS complexes. What does this indicate?", o: ["Normal function", "Failure to capture", "Failure to sense", "Undersensing"], a: 1, r: "Spikes without QRS = failure to capture. Causes: lead displacement, increased threshold, wire fracture, battery depletion. Increase mA output, check connections.", s: "Arrhythmias" },
  { q: "Why does atropine often fail in third-degree heart block?", o: ["Not anticholinergic", "Atropine enhances AV nodal conduction but complete block is often infranodal where atropine has no effect", "Always effective", "Slows rate"], a: 1, r: "Atropine blocks parasympathetic input to AV node. Infranodal block doesn't respond because tissue below AV node lacks significant parasympathetic innervation.", s: "Arrhythmias" },
  { q: "Inferior MI develops new AV block. Which type and why?", o: ["Type II — inferior MI affects bundles", "Type I (Wenckebach) — RCA supplies AV node in 85-90% of people", "Third-degree always", "First-degree only"], a: 1, r: "RCA supplies AV node in 85-90%. Inferior MI causes AV nodal ischemia producing reversible Wenckebach. Anterior MI tends to cause Type II or complete block.", s: "Arrhythmias" },
  { q: "Normal PR interval range?", o: ["0.06-0.10 sec", "0.12-0.20 seconds", "0.20-0.40 sec", "0.40-0.60 sec"], a: 1, r: "Normal PR: 0.12-0.20 seconds (3-5 small boxes). >0.20 sec = first-degree block. <0.12 sec with delta wave = WPW.", s: "Arrhythmias" },
  { q: "What escape rhythm maintains output in complete heart block?", o: ["No escape exists", "Junctional (40-60 bpm, narrow QRS) or ventricular escape (20-40 bpm, wide QRS)", "Sinus continues normally", "Atrial only"], a: 1, r: "Junctional escape: 40-60 bpm, narrow QRS. Ventricular escape: 20-40 bpm, wide QRS, less reliable. Lower escape = more dangerous.", s: "Arrhythmias" },
  { q: "When is a permanent pacemaker indicated for heart blocks?", o: ["All first-degree", "Symptomatic Mobitz Type II, high-grade AV block, and symptomatic complete heart block", "Only temporary blocks", "Never"], a: 1, r: "Permanent pacemaker: symptomatic Mobitz II, high-grade (2:1 or 3:1) AV block, complete heart block (especially with symptoms, wide escape, rate <40).", s: "Arrhythmias" },
  { q: "What is the significance of wide QRS in heart block?", o: ["Normal variant", "Indicates infranodal block — more dangerous, higher risk of complete block, needs pacing", "Atrial origin", "Better prognosis"], a: 1, r: "Wide QRS in second/third-degree block = block below AV node (bundle branches). More dangerous, less reliable escape, almost always needs pacing.", s: "Arrhythmias" },
  { q: "Which medications can cause or worsen AV block?", o: ["Aspirin", "Beta-blockers, CCBs (non-DHP), digoxin, amiodarone, adenosine", "ACE inhibitors", "Statins"], a: 1, r: "Drugs slowing AV conduction: beta-blockers, non-DHP CCBs, digoxin, amiodarone, adenosine, clonidine. Common reversible causes of AV block.", s: "Arrhythmias" },
  { q: "A pacemaker patient has pacing spikes before P waves AND QRS complexes. What type?", o: ["Single-chamber ventricular", "Dual-chamber (DDD) pacemaker — pacing both atrium and ventricle", "No pacemaker present", "ICD only"], a: 1, r: "Spikes before both P waves and QRS = dual-chamber DDD pacemaker pacing atrium and ventricle. Maintains AV synchrony (preserves atrial kick).", s: "Arrhythmias" },
  { q: "What does 'failure to sense' mean in a pacemaker?", o: ["Doesn't deliver impulses", "Fails to detect intrinsic rhythm, delivering inappropriate spikes that may compete with native beats — risk of R-on-T", "Battery depletion", "Normal function"], a: 1, r: "Undersensing: pacemaker fails to detect native activity, pacing inappropriately. Can cause R-on-T triggering VTach/VFib. Increase sensitivity (lower mV threshold).", s: "Arrhythmias" },
  { q: "What is the Stokes-Adams attack?", o: ["Stroke", "Sudden syncope from transient complete heart block causing cerebral hypoperfusion", "Seizure disorder", "Panic attack"], a: 1, r: "Stokes-Adams: sudden syncope from transient complete heart block. May have seizure-like activity from cerebral anoxia. Characteristic facial flushing on recovery. Requires pacemaker.", s: "Arrhythmias" },
  { q: "What is 2:1 AV block and why is it difficult to classify?", o: ["Always Type II", "Every other P is blocked; cannot determine Type I vs II because there's only one conducted PR to assess", "Always Type I", "Same as complete block"], a: 1, r: "In 2:1 block, only one PR interval between drops — can't tell if PR would have prolonged (Type I) or stayed constant (Type II). QRS width and atropine response help.", s: "Arrhythmias" },
  { q: "A client with a new permanent pacemaker. What education is most important?", o: ["No restrictions", "Carry ID card, avoid strong magnets, check MRI compatibility, report signs of infection and dizziness, regular device checks", "Avoid all activity forever", "No follow-up needed"], a: 1, r: "Pacemaker teaching: carry ID, avoid strong magnetic fields, MRI check compatibility, keep cell phone 6 inches from device, report infection signs, hiccups, dizziness. Regular device checks.", s: "Arrhythmias" },
  { q: "What is transcutaneous pacing and when is it used?", o: ["Permanent pacing solution", "Emergency external pacing using chest pads for symptomatic bradycardia or heart block when atropine fails — bridge to transvenous pacing", "Only for VFib", "For rate control"], a: 1, r: "Transcutaneous pacing: emergent, non-invasive pacing via external pads. Used when atropine fails for symptomatic bradycardia. Painful (requires sedation). Bridge to transvenous pacing.", s: "Arrhythmias" },
  { q: "What is high-grade AV block?", o: ["Same as first-degree", "Two or more consecutive non-conducted P waves (3:1 or 4:1 block) with very slow ventricular rate", "Complete heart block", "Wenckebach"], a: 1, r: "High-grade block: ≥2 consecutive non-conducted P waves. More severe than standard second-degree. Often symptomatic. Usually requires permanent pacing.", s: "Arrhythmias" },
  { q: "Atropine dose for symptomatic bradycardia?", o: ["0.1 mg IV", "0.5 mg IV, may repeat q3-5 min, maximum 3 mg total", "5 mg IV", "10 mg IM"], a: 1, r: "Atropine 0.5 mg IV q3-5 min, max 3 mg. Doses <0.5 mg can cause paradoxical bradycardia. Should not delay pacing when indicated.", s: "Arrhythmias" },
  { q: "A client with Lyme disease develops new second-degree AV block. What is the likely cause?", o: ["Unrelated", "Lyme carditis — usually resolves with antibiotics (IV ceftriaxone), may need temporary pacing", "Needs permanent pacemaker", "Allergic reaction"], a: 1, r: "Lyme carditis: AV nodal inflammation causing AV block, usually Wenckebach but can progress. Reversible with antibiotics. Temporary pacing may be needed.", s: "Arrhythmias" },
  { q: "What is the significance of a new bifascicular block in acute MI?", o: ["Benign finding", "Indicates extensive conduction damage with risk of complete heart block — may need prophylactic pacing pads", "Normal in MI", "Improves prognosis"], a: 1, r: "New bifascicular block (RBBB + left fascicular block) in acute MI = widespread His-Purkinje damage. Risk of sudden complete heart block. Place transcutaneous pacing pads prophylactically.", s: "Arrhythmias" },
  { q: "After temporary pacemaker insertion via subclavian, what should the nurse assess?", o: ["Only settings", "Insertion site, pneumothorax signs (CXR), capture on monitor, distal pulses, and lead security", "Nothing specific", "Only blood glucose"], a: 1, r: "Post-transvenous pacer: monitor insertion site (bleeding), CXR for lead position and pneumothorax, verify capture on monitor, check neurovascular status, immobilize extremity.", s: "Arrhythmias" },
  { q: "A client's pacemaker is set at 70 bpm but HR is 54 bpm. What does this indicate?", o: ["Normal function", "Pacemaker malfunction — failure to capture, output, or lead displacement", "Expected finding", "Check at next appointment"], a: 1, r: "Rate below set pacemaker rate = malfunction. Check for failure to capture, failure to output, lead displacement, battery depletion, or EMI. Assess immediately.", s: "Arrhythmias" },
  { q: "Why is external pacing painful?", o: ["Causes burns", "Large electrical currents through chest wall cause skeletal muscle contractions and activate pain receptors", "Not painful", "Only painful in children"], a: 1, r: "Transcutaneous pacing sends current through chest wall, stimulating skeletal muscle contraction and pain receptors. Adequate sedation/analgesia essential. Temporary bridge only.", s: "Arrhythmias" },

  // ===== SINUS BRADYCARDIA/TACHYCARDIA (35 questions) =====
  { q: "A client on metoprolol has HR 44, BP 86/52, dizziness. Priority?", o: ["Give next metoprolol dose", "Hold metoprolol, administer atropine 0.5 mg IV, notify provider", "Encourage ambulation", "Adenosine"], a: 1, r: "Symptomatic bradycardia from beta-blocker: hold medication, atropine 0.5 mg IV first-line per ACLS. Glucagon is specific antidote for beta-blocker toxicity.", s: "Arrhythmias" },
  { q: "Postop client: sinus tachycardia HR 126, tachypnea RR 26, decreased wound drainage. Suspect?", o: ["Anxiety", "Hypovolemia from concealed hemorrhage", "Normal postop finding", "Medication reaction"], a: 1, r: "Sinus tach + decreased drainage = suspect concealed hemorrhage. Assess for hypotension, pallor, restlessness, decreased UOP, abdominal distension.", s: "Arrhythmias" },
  { q: "Which symptoms indicate sinus bradycardia requires treatment?", o: ["No symptoms needed", "Hypotension, syncope, altered mental status, chest pain, or shock", "Fatigue only", "Elevated BP"], a: 1, r: "Treat only if symptomatic: hypotension, syncope/presyncope, AMS, chest pain, shock. Asymptomatic bradycardia (athletes, sleep) doesn't require intervention.", s: "Arrhythmias" },
  { q: "Sinus bradycardia HR 42 unresponsive to atropine. Next intervention?", o: ["More atropine beyond max", "Transcutaneous pacing or dopamine/epinephrine infusion", "Cardioversion", "Adenosine"], a: 1, r: "If atropine fails: transcutaneous pacing (most reliable), dopamine 5-20 mcg/kg/min, or epinephrine 2-10 mcg/min.", s: "Arrhythmias" },
  { q: "Cushing's triad (bradycardia, hypertension, irregular respirations) indicates what?", o: ["Cardiac tamponade", "Critically elevated ICP with brainstem herniation", "Cardiogenic shock", "Neurogenic shock"], a: 1, r: "Cushing's triad: late sign of dangerously elevated ICP. Bradycardia from vagal stimulation. Neurosurgical emergency — treat ICP, not the bradycardia.", s: "Arrhythmias" },
  { q: "What is sick sinus syndrome?", o: ["Heart failure", "SA node dysfunction causing alternating bradycardia and tachycardia (tachy-brady syndrome)", "Sinus infection", "Congenital septal defect"], a: 1, r: "Sick sinus: SA node dysfunction with inappropriate bradycardia, sinus arrest, sinoatrial exit block, and tachy-brady syndrome. Often requires permanent pacemaker.", s: "Arrhythmias" },
  { q: "Specific antidote for beta-blocker toxicity causing bradycardia?", o: ["Naloxone", "Glucagon", "Flumazenil", "Protamine"], a: 1, r: "Glucagon stimulates cardiac contractility and HR through non-adrenergic mechanism (increases cAMP independently of beta receptors). Dose: 3-10 mg IV.", s: "Arrhythmias" },
  { q: "When assessing sinus tachycardia, what should the nurse always consider?", o: ["Always pathologic", "It is nearly always compensatory — always treat the underlying cause, not the tachycardia", "Only during exercise", "Always defibrillate"], a: 1, r: "Sinus tachycardia is compensatory: pain, fever, anxiety, hypovolemia, anemia, hypoxia, HF, PE, infection. Treating HR without addressing cause can be dangerous.", s: "Arrhythmias" },
  { q: "A healthy 25-year-old athlete has resting HR 48. Is this pathologic?", o: ["Always pathologic", "No — physiologic bradycardia from enhanced vagal tone and increased stroke volume", "Needs pacing", "Sick sinus"], a: 1, r: "Athletic bradycardia is physiologic. Enhanced parasympathetic tone and increased stroke volume reduce resting HR. No treatment unless symptomatic.", s: "Arrhythmias" },
  { q: "A client on digoxin and metoprolol has HR 44. Which medication is most likely contributing?", o: ["Neither", "Both — combined additive bradycardic effect from slowing AV and SA node conduction", "Aspirin", "Lisinopril"], a: 1, r: "Digoxin (slows AV conduction) + beta-blocker (slows SA/AV node) = additive bradycardia. Both should be held, monitor K+ and digoxin level.", s: "Arrhythmias" },
  { q: "What antidote is used for CCB overdose causing bradycardia?", o: ["Glucagon only", "IV calcium gluconate or calcium chloride", "Vitamin K", "Protamine"], a: 1, r: "IV calcium directly antagonizes CCB effects. Also consider high-dose insulin-euglycemia therapy and vasopressors for severe toxicity.", s: "Arrhythmias" },
  { q: "Assessment finding in a sinus tachycardia client suggesting life-threatening cause?", o: ["Anxiety before procedure", "Unilateral leg swelling, acute dyspnea, and pleuritic chest pain — suspect PE", "Just ate a meal", "Mild caffeine intake"], a: 1, r: "Unilateral leg swelling (DVT) + acute dyspnea + pleuritic chest pain + tachycardia = PE. Sinus tach is the most common ECG finding in PE.", s: "Arrhythmias" },
  { q: "What is the danger of treating sinus tachycardia with beta-blockers in a hypovolemic patient?", o: ["No danger", "Removes compensatory tachycardia, causing cardiovascular collapse", "Improves outcome", "Only mild fatigue"], a: 1, r: "In hypovolemia, tachycardia maintains cardiac output. Beta-blocking removes this compensation, causing precipitous BP drop. Treat volume deficit, not heart rate.", s: "Arrhythmias" },
  { q: "What is inappropriate sinus tachycardia (IST)?", o: ["Normal exercise response", "Persistently elevated resting HR >100 bpm with exaggerated response to minimal exertion, without identifiable cause", "Sinus tach from hemorrhage", "AFib misidentified"], a: 1, r: "IST: diagnosis of exclusion. Resting HR >100 bpm disproportionate to activity. Treatment: ivabradine, beta-blockers, or catheter ablation in refractory cases.", s: "Arrhythmias" },
  { q: "What effect does hypothyroidism have on heart rate?", o: ["Tachycardia", "Sinus bradycardia from decreased metabolic rate", "No effect", "Causes AFib"], a: 1, r: "Hypothyroidism causes bradycardia from decreased metabolic demand and reduced cardiac catecholamine sensitivity. Check TSH in unexplained bradycardia.", s: "Arrhythmias" },
  { q: "What is the dopamine dose range for symptomatic bradycardia?", o: ["1-2 mcg/kg/min", "5-20 mcg/kg/min (chronotropic dose range)", "0.1 mcg/kg/min", "100 mcg/kg/min"], a: 1, r: "Dopamine 5-20 mcg/kg/min provides chronotropic and inotropic support for symptomatic bradycardia refractory to atropine.", s: "Arrhythmias" },
  { q: "A client has sinus tach HR 118 with hemoglobin 6.2 g/dL. What is the cause?", o: ["Anxiety", "Compensatory tachycardia from severe anemia — heart pumps faster to maintain O2 delivery", "Medication reaction", "Hyperthyroidism"], a: 1, r: "Severe anemia reduces O2-carrying capacity. Heart compensates by increasing rate. Treat the anemia (transfusion), not the tachycardia.", s: "Arrhythmias" },
  { q: "A spinal cord injury at T4 develops sinus bradycardia HR 40 and hypotension. Mechanism?", o: ["Hypovolemia", "Neurogenic shock — loss of sympathetic outflow causes unopposed parasympathetic tone", "Cardiogenic shock", "Septic shock"], a: 1, r: "High spinal cord injury (above T6): loss of sympathetic tone causes bradycardia and vasodilation. Warm, dry skin differentiates from hypovolemic shock. Treat with atropine, vasopressors.", s: "Arrhythmias" },
  { q: "What is the epinephrine infusion dose for refractory bradycardia?", o: ["1 mg IV push", "2-10 mcg/min continuous infusion", "100 mcg bolus", "0.01 mcg/min"], a: 1, r: "Epinephrine infusion 2-10 mcg/min for refractory bradycardia. The 1 mg IV push dose is for cardiac arrest ONLY. Titrate to desired HR and BP.", s: "Arrhythmias" },
  { q: "What is chronotropic incompetence?", o: ["Normal HR response", "Inability of HR to increase appropriately with exercise — may indicate SA node dysfunction", "Excessive HR response", "Only in children"], a: 1, r: "Chronotropic incompetence: failure of HR to rise adequately with exercise (<80% predicted max HR). Causes: SA node disease, medications. Rate-responsive pacemaker may be indicated.", s: "Arrhythmias" },
  { q: "A client receiving IV dobutamine develops sinus tach HR 130. Expected?", o: ["No, never happens", "Yes — dobutamine is a beta-1 agonist causing dose-related tachycardia", "Allergic reaction", "Drug error"], a: 1, r: "Dobutamine (beta-1 agonist) increases contractility and HR. Sinus tachycardia is a known side effect. May need dose reduction if HR is excessive.", s: "Arrhythmias" },
  { q: "A client develops sinus tach after tracheal suctioning. Why?", o: ["Equipment malfunction", "Suctioning stimulates sympathetic response and can cause hypoxia, both triggering tachycardia", "Allergic reaction", "Medication coincidence"], a: 1, r: "Suctioning causes: sympathetic response (tachycardia), hypoxia (compensatory tachycardia), coughing. Pre-oxygenate. Limit suction to 10-15 seconds.", s: "Arrhythmias" },
  { q: "What is reflex (neurogenic) bradycardia?", o: ["From exercise", "Vagal nerve stimulation from vomiting, bearing down, carotid massage, or increased ICP", "From medications", "From exercise"], a: 1, r: "Reflex bradycardia: vagus activation from vomiting, straining, ocular pressure, carotid massage, increased ICP. Usually transient.", s: "Arrhythmias" },
  { q: "How does the nurse determine if sinus tach is appropriate vs concerning?", o: ["All tachycardia is same", "Appropriate has identifiable proportional cause; absence of cause or disproportionate rate warrants investigation for PE, sepsis, thyrotoxicosis", "Check only BP", "Order CXR only"], a: 1, r: "Assess for identifiable causes. If no cause found or rate disproportionate, investigate: PE, sepsis, thyrotoxicosis, tamponade, IST.", s: "Arrhythmias" },
  { q: "A febrile client with sinus tach HR 112. What does the nurse assess?", o: ["Only the fever", "Assess for source of infection — sinus tach with fever may indicate sepsis requiring early antibiotics and fluids", "Heart rhythm only", "Lung sounds only"], a: 1, r: "Sinus tach + fever: assess for sepsis (cultures, lactate, WBC). Apply sepsis criteria. Early recognition and treatment improve outcomes.", s: "Arrhythmias" },

  // ===== CHD OVERVIEW (35 questions) =====
  { q: "A newborn fails pulse oximetry screening with SpO2 88% in right hand. 100% O2 doesn't improve. What does this suggest?", o: ["RDS", "Cyanotic congenital heart defect", "Normal transition", "Equipment malfunction"], a: 1, r: "Failed hyperoxia test strongly suggests cyanotic CHD. Intracardiac shunting bypasses lungs so supplemental O2 cannot improve oxygenation.", s: "Pediatrics" },
  { q: "A neonate on PGE1 for ductal-dependent lesion. What side effect requires closest monitoring?", o: ["Hyperglycemia", "Apnea (occurs in 10-12%)", "Constipation", "Hypernatremia"], a: 1, r: "Apnea occurs in 10-12% on PGE1. Intubation equipment must be at bedside. Other effects: fever, hypotension, bradycardia.", s: "Pediatrics" },
  { q: "An infant with large VSD shows tachypnea, diaphoresis during feeding, poor weight gain, hepatomegaly. What complication?", o: ["Pyloric stenosis", "Heart failure from L→R shunting and pulmonary overcirculation", "GERD", "Colic"], a: 1, r: "Classic infant HF from large VSD: tachypnea, feeding diaphoresis, FTT, hepatomegaly from pulmonary overcirculation and volume overload.", s: "Pediatrics" },
  { q: "Classification of CHD where blood flows L→R increasing pulmonary flow?", o: ["Cyanotic R→L shunt", "Acyanotic L→R shunt", "Obstructive lesion", "Regurgitant lesion"], a: 1, r: "Acyanotic defects (VSD, ASD, PDA) feature L→R shunting. Oxygenated blood recirculates to lungs. Cyanosis doesn't initially occur.", s: "Pediatrics" },
  { q: "What are the 5 T's of cyanotic heart defects?", o: ["VSD, ASD, PDA", "TOF, TGA, Truncus Arteriosus, Tricuspid Atresia, TAPVR", "Coarctation, MS, AS", "PFO only"], a: 1, r: "5 T's: Tetralogy of Fallot, Transposition, Truncus Arteriosus, Tricuspid Atresia, Total Anomalous Pulmonary Venous Return.", s: "Pediatrics" },
  { q: "What medication keeps the ductus arteriosus open?", o: ["Indomethacin", "Prostaglandin E1 (alprostadil)", "Ibuprofen", "Digoxin"], a: 1, r: "PGE1 maintains ductal patency in ductal-dependent lesions. Monitor for apnea, have intubation equipment ready.", s: "Pediatrics" },
  { q: "What medication CLOSES a PDA?", o: ["PGE1", "Indomethacin or ibuprofen (prostaglandin synthesis inhibitors)", "Alprostadil", "Digoxin"], a: 1, r: "Indomethacin and ibuprofen inhibit prostaglandin synthesis, promoting PDA closure. OPPOSITE of PGE1.", s: "Pediatrics" },
  { q: "What is Eisenmenger syndrome?", o: ["Valve defect", "Reversal of L→R shunt to R→L due to irreversible pulmonary hypertension", "Neonatal arrhythmia", "Cardiomyopathy"], a: 1, r: "Long-standing L→R shunt → irreversible pulmonary HTN → shunt reversal (R→L) → cyanosis. Surgical repair contraindicated at this stage.", s: "Pediatrics" },
  { q: "How does fetal circulation differ from postnatal?", o: ["No difference", "Fetal has three shunts bypassing lungs: ductus venosus, foramen ovale, ductus arteriosus", "Fetal lungs do gas exchange", "Fetal heart has 2 chambers"], a: 1, r: "Three fetal shunts: ductus venosus (bypasses liver), foramen ovale (R→L atrial), ductus arteriosus (PA→aorta). First breath triggers closure.", s: "Pediatrics" },
  { q: "What is the most common CHD overall?", o: ["TOF", "Ventricular septal defect (VSD)", "ASD", "PDA"], a: 1, r: "VSD is the most common CHD (25-30%). Small VSDs may close spontaneously; large ones need repair.", s: "Pediatrics" },
  { q: "What is a ductal-dependent lesion?", o: ["Doesn't need ductus", "Heart defect requiring PDA for systemic or pulmonary blood flow to survive", "Only PDA itself", "Valvular disease"], a: 1, r: "Ductal-dependent lesions require PDA for pulmonary flow (e.g., pulmonary atresia) or systemic flow (e.g., HLHS, critical coarctation). PGE1 is lifesaving.", s: "Pediatrics" },
  { q: "What is the continuous machinery murmur characteristic of?", o: ["VSD", "Patent ductus arteriosus (PDA)", "ASD", "Coarctation"], a: 1, r: "PDA produces continuous 'machinery-like' murmur at left upper sternal border. Continuous because flow through PDA occurs in both systole and diastole.", s: "Pediatrics" },
  { q: "What is the 'egg-on-a-string' CXR appearance?", o: ["TOF", "Transposition of the Great Arteries (TGA)", "Coarctation", "VSD"], a: 1, r: "TGA: egg-shaped heart on a narrow vascular pedicle (string). Egg from malpositioned great vessels creating narrow mediastinal shadow.", s: "Pediatrics" },
  { q: "What newborn CCHD screening involves?", o: ["Hearing test", "Pulse oximetry in right hand and either foot at 24-48 hours", "Metabolic panel", "Jaundice check"], a: 1, r: "CCHD screening: SpO2 in right hand (preductal) and either foot (postductal). Failed: <95% or >3% difference. Identifies ductal-dependent and cyanotic lesions.", s: "Pediatrics" },
  { q: "What genetic syndrome is associated with complete AV canal defect?", o: ["Turner syndrome", "Down syndrome (Trisomy 21)", "Marfan syndrome", "Williams syndrome"], a: 1, r: "Down syndrome strongly associated with AVCD. ~40% of Down syndrome children have CHD, most commonly AVCD. Echo screening recommended.", s: "Pediatrics" },
  { q: "What dietary modification helps infants with CHD?", o: ["Fluid restriction only", "Calorie-dense formula (24-30 kcal/oz) to maximize nutrition with minimal volume", "Low-fat diet", "Soy only"], a: 1, r: "CHD infants have increased metabolic demand but tire during feeds. Concentrated formula provides nutrition without excessive volume. Small, frequent feeds.", s: "Pediatrics" },
  { q: "What is polycythemia in cyanotic CHD?", o: ["Low RBC count", "Elevated RBCs compensating for chronic hypoxemia — increases viscosity and thrombosis risk", "High WBC", "High platelets"], a: 1, r: "Chronic hypoxemia stimulates erythropoietin → increased RBCs. Excessive polycythemia (Hct >65%) increases viscosity and stroke/thrombosis risk.", s: "Pediatrics" },
  { q: "What is the Fontan procedure?", o: ["VSD repair", "Palliative surgery for single-ventricle defects directing systemic venous blood to lungs without a pumping chamber", "Heart transplant", "PDA ligation"], a: 1, r: "Fontan: final single-ventricle palliation. Connects IVC to PA so venous blood flows passively to lungs. Requires low pulmonary pressures.", s: "Pediatrics" },
  { q: "A neonate with TGA has severe cyanosis. What emergency procedure creates atrial mixing?", o: ["VSD creation", "Balloon atrial septostomy (Rashkind procedure)", "Fontan", "CTI ablation"], a: 1, r: "Balloon septostomy enlarges atrial communication, allowing mixing of oxygenated and deoxygenated blood. Temporizes until arterial switch operation.", s: "Pediatrics" },
  { q: "What is the primary diagnostic tool for CHD?", o: ["CXR", "Echocardiography — provides anatomical detail, shunt quantification, hemodynamics without radiation", "CT scan", "MRI only"], a: 1, r: "Echo is the gold standard: visualizes defects, quantifies shunts (Qp:Qs), measures chambers, evaluates valves. Non-invasive, no radiation, bedside.", s: "Pediatrics" },
  { q: "What is the 'snowman sign' on CXR?", o: ["TOF", "Total anomalous pulmonary venous return (TAPVR) — supracardiac type", "Coarctation", "VSD"], a: 1, r: "Supracardiac TAPVR: upper 'snowball' = dilated vertical vein and SVC, lower = enlarged heart. Pulmonary veins drain abnormally to right atrium.", s: "Pediatrics" },
  { q: "What is clubbing in CHD?", o: ["Sport injury", "Widened fingertips from chronic hypoxemia indicating long-standing cyanotic disease", "Normal nail variant", "Nutritional deficiency"], a: 1, r: "Digital clubbing develops from chronic tissue hypoxia. In CHD, indicates long-standing cyanosis. Should prompt evaluation for surgical correction.", s: "Pediatrics" },
  { q: "A neonate with known CHD suddenly collapses. Priority?", o: ["Obtain weight", "Suspect ductal closure — start PGE1, airway support, prepare for emergency intervention", "Schedule echo next week", "Observe 6 hours"], a: 1, r: "Sudden collapse in CHD neonate: suspect ductal closure. Immediate PGE1, airway management, IV access, fluid resuscitation, cardiology notification.", s: "Pediatrics" },
  { q: "What psychosocial support does the nurse provide to CHD parents?", o: ["No support needed", "Clear education, connect with support groups, address parental anxiety, coordinate team communication", "Written materials only", "Refer psychiatry immediately"], a: 1, r: "Nursing support: education about defect and plan, address guilt and anxiety, connect with support organizations, facilitate communication between teams and family.", s: "Pediatrics" },
  { q: "When is SBE prophylaxis indicated in CHD?", o: ["All CHD", "Unrepaired cyanotic CHD, prosthetic valves, repaired CHD with residual defects, and prior endocarditis — before dental procedures", "Never needed", "Only after repair"], a: 1, r: "AHA guidelines: SBE prophylaxis for unrepaired cyanotic CHD, prosthetic valves, repaired CHD with residual defects, prior endocarditis. Amoxicillin 30-60 min before dental procedures.", s: "Pediatrics" },

  // ===== TETRALOGY OF FALLOT (35 questions) =====
  { q: "A nurse is caring for an infant with unrepaired TOF who becomes deeply cyanotic, irritable, and hyperpneic. Priority?", o: ["Oxygen by face mask", "Knee-chest position", "Cardioversion", "IV fluids"], a: 1, r: "During tet spell: knee-chest position increases SVR and reduces R→L shunting, forcing more blood through pulmonary circuit. Then: calm infant, O2, morphine, phenylephrine.", s: "Pediatrics" },
  { q: "Why do TOF children squat during play?", o: ["Behavioral problem", "Squatting increases SVR, reducing R→L shunting and improving oxygenation", "Leg pain", "Normal development"], a: 1, r: "Squatting traps venous blood and compresses femoral arteries → increases SVR → reduces R→L shunt → improves pulmonary flow and oxygenation.", s: "Pediatrics" },
  { q: "Definitive surgical repair for TOF?", o: ["Fontan", "VSD patch closure and RVOT reconstruction at 3-6 months", "Heart transplant", "Balloon septostomy"], a: 1, r: "Complete repair: VSD patch + RVOT relief (muscle resection, transannular patch). Ideally at 3-6 months. BT shunt may palliate unstable neonates.", s: "Pediatrics" },
  { q: "CXR of child with TOF shows boot-shaped heart with decreased pulmonary markings. What does this indicate?", o: ["Normal", "RV hypertrophy and decreased pulmonary blood flow from RVOT obstruction", "LV failure", "Pulmonary edema"], a: 1, r: "Boot-shaped heart (coeur en sabot) from RV hypertrophy. Decreased pulmonary markings from reduced pulmonary flow. Contrasts with L→R shunts (increased markings).", s: "Pediatrics" },
  { q: "Four anatomical defects in TOF?", o: ["ASD, PDA, coarctation, MS", "VSD, RVOT obstruction (PS), overriding aorta, RV hypertrophy", "Tricuspid atresia, ASD, PDA, PS", "TGA, truncus, VSD, ASD"], a: 1, r: "TOF: (1) large VSD, (2) RVOT obstruction, (3) overriding aorta, (4) RV hypertrophy. Severity of RVOT obstruction determines cyanosis degree.", s: "Pediatrics" },
  { q: "What triggers tet spells?", o: ["Eating", "Crying, agitation, straining, dehydration, fever — anything increasing O2 demand or decreasing SVR", "Sleeping", "Cold weather"], a: 1, r: "Triggers increase O2 demand, decrease SVR, or trigger infundibular spasm — all worsen R→L shunting. Minimize crying/agitation.", s: "Pediatrics" },
  { q: "What is a BT shunt?", o: ["ASD repair", "Surgical connection between subclavian and pulmonary artery to increase pulmonary blood flow", "PDA ligation", "Fontan"], a: 1, r: "Modified BT shunt: Gore-Tex graft from subclavian to PA. Palliative for neonates too small for complete repair. Monitor for shunt thrombosis.", s: "Pediatrics" },
  { q: "What is the role of morphine during a tet spell?", o: ["Pain relief only", "Relaxes infundibular spasm, reduces preload, reduces agitation and O2 demand", "Sedation only", "Increases HR"], a: 1, r: "IV morphine 0.1 mg/kg: relaxes infundibular muscle spasm, decreases preload, reduces agitation/O2 demand, reduces sympathetic drive.", s: "Pediatrics" },
  { q: "What is the role of phenylephrine in tet spells?", o: ["Decreases SVR", "IV alpha-1 agonist increases SVR, reducing VSD pressure gradient and R→L shunting", "Bronchodilator", "Anti-arrhythmic"], a: 1, r: "Phenylephrine raises SVR, reducing pressure gradient favoring R→L shunt. Used when knee-chest + morphine fail.", s: "Pediatrics" },
  { q: "What is 'pink tet'?", o: ["Different disease", "TOF with minimal RVOT obstruction — acyanotic at rest, may develop cyanosis with stress", "TOF after repair", "Normal variant"], a: 1, r: "Pink tet: mild RVOT obstruction allows adequate pulmonary flow. Pink at rest but may cyanose with exertion. Still needs eventual repair.", s: "Pediatrics" },
  { q: "Most common cyanotic heart defect?", o: ["TGA", "Tetralogy of Fallot", "Tricuspid atresia", "Truncus arteriosus"], a: 1, r: "TOF is the most common cyanotic CHD, ~10% of all CHD. Most common cyanotic lesion presenting beyond newborn period.", s: "Pediatrics" },
  { q: "What should the nurse monitor post-TOF repair?", o: ["Only temperature", "Arrhythmias (JET, heart block), bleeding, low cardiac output, residual VSD, pulmonary regurgitation", "Only wound", "Only UOP"], a: 1, r: "Post-repair: arrhythmias (JET most common, heart block from VSD patch), bleeding, low cardiac output, residual VSD, pulmonary regurgitation.", s: "Pediatrics" },
  { q: "Long-term complication after TOF repair?", o: ["No long-term issues", "Pulmonary regurgitation requiring valve replacement later in life", "Immediate cure", "Only scarring"], a: 1, r: "Chronic PR causes RV dilation/dysfunction. Many patients need pulmonary valve replacement in adolescence/adulthood.", s: "Pediatrics" },
  { q: "Why is iron supplementation important in cyanotic CHD?", o: ["Not important", "Iron maintains hemoglobin for O2 transport; deficiency worsens anemia and can trigger tet spells", "Avoid iron", "Iron causes cyanosis"], a: 1, r: "Cyanotic CHD infants depend on adequate Hgb for O2 transport. Iron deficiency reduces RBC deformability and can trigger tet spells.", s: "Pediatrics" },
  { q: "What murmur is heard in TOF?", o: ["Continuous machinery", "Systolic ejection murmur from RVOT obstruction at LUSB — paradoxically decreases during tet spells", "Diastolic rumble", "No murmur"], a: 1, r: "TOF murmur: systolic ejection from RVOT obstruction. DECREASES during tet spells because less blood flows through obstructed RVOT. Absent murmur during cyanosis is ominous.", s: "Pediatrics" },
  { q: "Why is propranolol prescribed for unrepaired TOF?", o: ["Hypertension", "Reduces HR and dynamic RVOT obstruction, helping prevent tet spells", "For AFib", "Pain management"], a: 1, r: "Propranolol reduces HR, decreases dynamic infundibular spasm (beta-blockade), prophylactically prevents tet spells while awaiting surgical repair.", s: "Pediatrics" },
  { q: "Typical SpO2 in unrepaired TOF?", o: ["100%", "75-85% baseline depending on RVOT obstruction severity", "95-100%", "Below 50%"], a: 1, r: "Baseline SpO2 varies with obstruction severity. During tet spells, SpO2 can drop to 40-60%. Individual baseline guides management.", s: "Pediatrics" },
  { q: "What nursing intervention prevents tet spells during procedures?", o: ["No prevention possible", "Minimize crying with parental comfort, topical anesthetics, cluster care, adequate hydration", "Sedate all children", "Only under general anesthesia"], a: 1, r: "Minimize agitation: parental presence, EMLA cream, cluster care, calm environment, adequate hydration. If spell begins during procedure, stop and knee-chest.", s: "Pediatrics" },
  { q: "What discharge teaching for parents of infant with unrepaired TOF?", o: ["No special instructions", "Recognize tet spells, knee-chest position, when to call 911, maintain hydration and iron, follow-up for planned surgery", "Only keep scheduled appointments", "Avoid all activity"], a: 1, r: "Parents must learn: tet spell recognition, knee-chest technique, 911 criteria, hydration, iron-rich diet, and follow-up schedule for planned surgery.", s: "Pediatrics" },
  { q: "Expected recovery after complete TOF repair?", o: ["Immediate recovery", "ICU 2-5 days, hospital 5-10 days, full recovery 4-6 weeks, lifelong cardiology follow-up", "1 day", "Takes years"], a: 1, r: "Post-repair: ICU 2-5 days, hospital 5-10 days, activity restriction 4-6 weeks. Lifelong follow-up for PR, RV function, arrhythmias.", s: "Pediatrics" },
  { q: "What position should a TOF infant be in for feeding?", o: ["Flat on back", "Semi-upright to reduce cardiac workload; small frequent feeds with rest breaks", "Prone", "Trendelenburg"], a: 1, r: "Semi-upright position reduces cardiac workload. Small, frequent feeds. Monitor for distress. Calorie-dense formula reduces volume needed.", s: "Pediatrics" },
  { q: "What is absent pulmonary valve syndrome in TOF?", o: ["Same as standard TOF", "TOF variant with rudimentary/absent pulmonary valve causing massive PR and dilated PAs that compress airways", "TOF without VSD", "ASD with PS"], a: 1, r: "Absent pulmonary valve: rare TOF variant with no functional pulmonary valve. Massive PR with hugely dilated PAs compressing tracheobronchial tree. Requires early surgery.", s: "Pediatrics" },
  { q: "A child with repaired TOF develops new exercise intolerance and a wide-open pulmonary regurgitation on echo. What does the nurse anticipate?", o: ["No intervention", "Evaluation for pulmonary valve replacement — surgical or transcatheter", "Heart transplant", "More medication"], a: 1, r: "Progressive exercise intolerance with severe PR and RV dilation after TOF repair typically indicates the need for pulmonary valve replacement to preserve RV function.", s: "Pediatrics" },
  { q: "What cardiac catheterization findings confirm TOF?", o: ["Normal pressures", "Equal RV and LV systolic pressures (large VSD), RVOT gradient, and R→L shunt", "L→R shunt only", "No shunt"], a: 1, r: "Cath shows equal biventricular systolic pressures (nonrestrictive VSD), aortic desaturation (R→L shunt), RVOT gradient. Echo has largely replaced diagnostic cath.", s: "Pediatrics" },
  { q: "A parent asks about long-term outlook after TOF repair. What should the nurse share?", o: ["Cure with no follow-up", "Most patients live normal lives with lifelong cardiology follow-up needed for monitoring RV function, arrhythmias, and potential re-intervention", "Poor prognosis always", "Activity always restricted"], a: 1, r: "Excellent long-term survival. Most patients lead active lives. Lifelong monitoring needed for: PR/RV function, arrhythmias, exercise capacity, and potential valve replacement.", s: "Pediatrics" },

  // ===== SEPTAL DEFECTS VSD/ASD (35 questions) =====
  { q: "Loud harsh holosystolic murmur at left lower sternal border in a newborn. Which defect?", o: ["ASD", "VSD", "PDA", "Coarctation"], a: 1, r: "VSD: harsh holosystolic murmur at LLSB. Smaller restrictive VSDs produce louder murmurs due to higher velocity flow.", s: "Pediatrics" },
  { q: "Characteristic ASD auscultatory finding?", o: ["Holosystolic murmur", "Fixed split S2 that does not vary with respiration", "Systolic click", "Diastolic rumble only"], a: 1, r: "ASD: fixed S2 splitting. ASD equalizes atrial pressures, maintaining constant RV volume regardless of respiratory cycle.", s: "Pediatrics" },
  { q: "What percentage of small VSDs close spontaneously?", o: ["0%", "Up to 80% of small muscular VSDs by age 2-3", "100% need surgery", "5%"], a: 1, r: "Up to 80% of small muscular VSDs close spontaneously within first 2-3 years. Serial echocardiography monitors for closure.", s: "Pediatrics" },
  { q: "When does a VSD require surgical repair?", o: ["All VSDs immediately", "Large VSDs causing heart failure, FTT, or pulmonary HTN unresponsive to medical management — ideally before age 1", "Never", "Only at 18"], a: 1, r: "Surgical indications: large VSD with HF despite meds, FTT, Qp:Qs >2:1, developing pulmonary HTN. Repair before age 1 to prevent Eisenmenger.", s: "Pediatrics" },
  { q: "What is the Qp:Qs ratio of 2.5:1?", o: ["Normal", "2.5x more blood flows to lungs than systemic circulation — hemodynamically significant L→R shunt", "Ratio of arterial/venous", "Measures cardiac output"], a: 1, r: "Qp:Qs measures pulmonary vs systemic flow. Normal 1:1. Ratio >2:1 generally indicates significant shunt requiring surgical intervention.", s: "Pediatrics" },
  { q: "Unrepaired large VSD with progressive cyanosis and clubbing indicates?", o: ["Pneumonia", "Eisenmenger syndrome — irreversible shunt reversal, surgical closure now contraindicated", "Endocarditis", "Normal growth"], a: 1, r: "Progressive cyanosis + clubbing in unrepaired VSD = Eisenmenger. Irreversible pulmonary HTN caused R→L shunt reversal. Closure now contraindicated.", s: "Pediatrics" },
  { q: "How is transcatheter ASD closure performed?", o: ["Open-heart surgery only", "Amplatzer device via femoral vein catheterization to seal the defect", "Medication only", "External compression"], a: 1, r: "Secundum ASD: device closure via femoral vein. Amplatzer opens on each side, sealing defect. Avoids open-heart surgery. Aspirin/clopidogrel 6 months.", s: "Pediatrics" },
  { q: "What are the three types of ASD?", o: ["Only one type", "Secundum (70%, amenable to device), primum (Down syndrome), sinus venosus (near SVC/IVC)", "VSD types", "Only PFO"], a: 1, r: "Secundum (70%, central), Primum (lower septum, cleft MV, Down syndrome), Sinus venosus (near SVC/IVC, often with PAPVR).", s: "Pediatrics" },
  { q: "What is the difference between ASD and PFO?", o: ["Same thing", "PFO is a residual fetal flap (25% of adults); ASD is a true structural hole", "PFO is larger", "ASD only in infants"], a: 1, r: "PFO: residual fetal flap valve in ~25% of adults. Usually functionally closed but can allow paradoxical embolism. ASD: true structural defect.", s: "Pediatrics" },
  { q: "Why might a large ASD remain asymptomatic until adulthood?", o: ["It closes", "Low-pressure L→R shunt is well-tolerated for years; symptoms develop in 30s-40s with RV dilation and arrhythmias", "Always symptomatic at birth", "Impossible"], a: 1, r: "ASD shunt is low-pressure, well-tolerated in childhood. Gradual RV volume overload leads to exercise intolerance and atrial arrhythmias in adulthood.", s: "Pediatrics" },
  { q: "Medications for HF from large VSD while awaiting surgery?", o: ["No medications", "Digoxin, furosemide, captopril (reduces afterload and L→R shunting)", "Beta-blockers only", "Aspirin only"], a: 1, r: "Medical management: digoxin (contractility), furosemide (pulmonary congestion), ACE inhibitor (reduces afterload/shunt magnitude). Bridges to surgical repair.", s: "Pediatrics" },
  { q: "What is a paradoxical embolism?", o: ["Arterial embolism only", "Venous thrombus crosses ASD/PFO to systemic circulation causing stroke", "Only with PE", "LA embolism"], a: 1, r: "Paradoxical embolism: venous thrombus crosses through ASD/PFO (R→L shunt) into systemic circulation → stroke. Why PFO closure considered after cryptogenic stroke.", s: "Pediatrics" },
  { q: "Surgical approach for VSD repair?", o: ["Catheter always", "Median sternotomy, cardiopulmonary bypass, Dacron/Gore-Tex patch or primary suture closure", "No surgery needed", "Thoracotomy only"], a: 1, r: "VSD repair: median sternotomy, CPB, patch closure. Approached through right atrium to avoid ventriculotomy. Risk of heart block near conduction system.", s: "Pediatrics" },
  { q: "Child with VSD develops fever, splinter hemorrhages, Janeway lesions. Suspect?", o: ["Kawasaki", "Infective endocarditis — VSD increases risk from turbulent flow", "Scarlet fever", "Normal illness"], a: 1, r: "VSD patients have increased endocarditis risk. Classic: fever, new/changing murmur, splinter hemorrhages, Janeway lesions. Blood cultures x3 and antibiotics.", s: "Pediatrics" },
  { q: "At what age should an unclosed significant ASD be repaired?", o: ["Never if asymptomatic", "By age 3-5 years if Qp:Qs >1.5:1 with RV dilation", "After age 18", "At birth"], a: 1, r: "Significant ASD (Qp:Qs >1.5:1 with RV dilation): close by age 3-5. Prevents long-term RV dysfunction, arrhythmias, pulmonary HTN, paradoxical embolism.", s: "Pediatrics" },
  { q: "Post-VSD repair complication specific to membranous VSD?", o: ["No specific risk", "Complete heart block from injury to AV node/bundle of His along inferior margin", "PE", "Aortic stenosis"], a: 1, r: "AV node and bundle of His course along posteroinferior rim of membranous VSDs. Surgical repair risks heart block requiring permanent pacemaker (1-2%).", s: "Pediatrics" },
  { q: "What happens to VSD murmur as pulmonary HTN develops?", o: ["Gets louder", "Murmur softens or disappears as pressure gradient equalizes — quiet murmur with cyanosis is ominous", "Changes to diastolic", "No change"], a: 1, r: "As pulmonary HTN develops, VSD pressure gradient decreases → softer/absent murmur. A 'quiet' VSD with cyanosis = Eisenmenger. Loud P2 develops.", s: "Pediatrics" },
  { q: "How does the nurse assess for pulmonary overcirculation in an infant with VSD?", o: ["Only check temp", "Monitor tachypnea, crackles, hepatomegaly, poor weight gain, diaphoresis during feeds, frequent RTIs", "Only HR", "Only BP"], a: 1, r: "Pulmonary overcirculation signs: tachypnea (most reliable early sign), crackles, hepatomegaly, FTT, feeding diaphoresis, recurrent respiratory infections.", s: "Pediatrics" },
  { q: "Why are recurrent RTIs common in infants with large VSDs?", o: ["Unrelated", "Pulmonary overcirculation causes congestion and edema, creating favorable environment for bacterial growth", "Due to meds", "Only in adults"], a: 1, r: "Excessive pulmonary flow causes interstitial edema, impairing gas exchange and mucociliary clearance. Wet, congested lungs are prone to infection.", s: "Pediatrics" },
  { q: "What is the relationship between VSD size and symptoms?", o: ["Small VSDs worse", "Small restrictive: asymptomatic with loud murmur. Large nonrestrictive: HF with potentially softer murmur", "All equally symptomatic", "Size irrelevant"], a: 1, r: "Small restrictive VSDs: loud murmur (high velocity), asymptomatic, may close. Large nonrestrictive: significant shunt, HF, FTT, quieter murmur.", s: "Pediatrics" },
  { q: "What post-transcatheter ASD closure complication should the nurse monitor for?", o: ["Only bruising", "Device embolization, cardiac erosion, residual shunt, arrhythmias, thrombus on device", "No complications", "Only infection"], a: 1, r: "Complications: device embolization, cardiac erosion (rare, serious), residual shunt, arrhythmias, device thrombus. Monitor with serial echo. Antiplatelet therapy required.", s: "Pediatrics" },
  { q: "Nursing assessment after surgical VSD repair?", o: ["Only pain", "Telemetry for heart block, auscultation for residual murmur, perfusion assessment, UOP, chest drain output", "Only wound care", "Only temperature"], a: 1, r: "Post-repair: telemetry for heart block (PR prolongation, bradycardia), auscultation for new murmur, perfusion (cap refill, pulses), UOP (>1 mL/kg/hr), drain output.", s: "Pediatrics" },
  { q: "What is a doubly committed (subarterial) VSD?", o: ["Two VSDs", "VSD beneath both semilunar valves — doesn't close spontaneously, can cause aortic regurgitation", "VSD with ASD", "VSD in two locations"], a: 1, r: "Subarterial VSD lies directly beneath aortic and pulmonary valves. Doesn't close spontaneously. Can cause progressive aortic regurgitation. Early repair recommended.", s: "Pediatrics" },
  { q: "A child with ASD develops new palpitations and an irregular pulse at age 35. What is the likely cause?", o: ["Unrelated to ASD", "Atrial fibrillation or flutter from chronic right atrial dilation due to long-standing ASD shunt", "Ventricular tachycardia", "Normal aging"], a: 1, r: "Unrepaired ASD causes chronic RA dilation, which is a substrate for atrial arrhythmias (AFib/flutter) presenting in the 3rd-4th decade. This is why timely ASD closure is recommended.", s: "Pediatrics" },
  { q: "What is the post-operative antiplatelet regimen after transcatheter ASD device closure?", o: ["No medications needed", "Aspirin and/or clopidogrel for 6 months to prevent thrombus formation on the device until endothelialization", "Warfarin for life", "Heparin infusion for 2 weeks"], a: 1, r: "Post-device closure: dual antiplatelet therapy (aspirin + clopidogrel) or aspirin alone for 6 months until the device endothelializes. SBE prophylaxis for 6 months per guidelines.", s: "Pediatrics" },

  // ===== COARCTATION OF THE AORTA (35 questions) =====
  { q: "Hallmark finding in coarctation?", o: ["Central cyanosis", "BP higher in upper extremities than lower (>20 mmHg gradient), weak femoral pulses", "Irregular rhythm", "Absent heart sounds"], a: 1, r: "Systolic BP gradient >20 mmHg upper > lower + weak/absent femoral pulses. Check 4-extremity BPs in neonates.", s: "Pediatrics" },
  { q: "Critical neonatal coarctation depends on what structure?", o: ["Foramen ovale", "PDA providing blood flow to lower body", "Coronary arteries", "Umbilical vein"], a: 1, r: "Critical preductal coarctation: PDA is only pathway for blood to descending aorta. When ductus closes → cardiovascular collapse. PGE1 immediately.", s: "Pediatrics" },
  { q: "Genetic syndrome associated with coarctation?", o: ["Down syndrome", "Turner syndrome (45,X)", "Marfan", "Edwards"], a: 1, r: "Turner syndrome: coarctation in ~10-15%, bicuspid aortic valve ~30%. All Turner patients need cardiac screening.", s: "Pediatrics" },
  { q: "Classic CXR finding in older children with coarctation?", o: ["Boot-shaped heart", "Rib notching from dilated collateral intercostal arteries", "Snowman sign", "Egg-on-a-string"], a: 1, r: "Bilateral inferior rib notching after age 5-6 from enlarged collateral intercostal arteries. May also see '3 sign' from pre/post stenotic dilation.", s: "Pediatrics" },
  { q: "Most important assessment for suspected coarctation?", o: ["Blood glucose", "Simultaneous 4-extremity BPs comparing upper and lower extremities", "Hearing screening", "Hip ultrasound"], a: 1, r: "Compare right arm and lower extremity BPs/pulses. Gradient >20 mmHg (upper > lower) and weak femoral pulses are diagnostic.", s: "Pediatrics" },
  { q: "Most common cardiac defect associated with coarctation?", o: ["ASD", "Bicuspid aortic valve (50-85% of coarctation patients)", "PDA only", "VSD only"], a: 1, r: "BAV found in 50-85% of coarctation patients. Other associations: VSD, MV abnormalities, Berry aneurysms.", s: "Pediatrics" },
  { q: "What is post-coarctectomy syndrome?", o: ["Normal recovery", "Paradoxical hypertension and abdominal pain from sudden increased mesenteric blood flow", "Infection", "Heart block"], a: 1, r: "Post-coarctectomy syndrome: paradoxical HTN + abdominal pain 2-3 days after repair. Sudden pulsatile flow to mesenteric arteries causes arteritis. Antihypertensives and bowel rest.", s: "Pediatrics" },
  { q: "Surgical options for coarctation?", o: ["Medication only", "Resection with end-to-end anastomosis, subclavian flap, patch aortoplasty, or balloon/stent", "Heart transplant only", "No treatment"], a: 1, r: "Surgical: resection with end-to-end anastomosis (most common), subclavian flap. Catheter: balloon angioplasty ± stent for recoarctation or native coarctation in older children.", s: "Pediatrics" },
  { q: "Long-term complication requiring lifelong monitoring after coarctation repair?", o: ["None", "Recoarctation and persistent hypertension (up to 30% develop late HTN)", "Only wound healing", "Only growth"], a: 1, r: "Long-term: recoarctation, persistent HTN (30%), aortic aneurysm at repair site, BAV complications, Berry aneurysms. Lifelong cardiology follow-up.", s: "Pediatrics" },
  { q: "Why might a neonate with coarctation appear normal initially?", o: ["Resolves spontaneously", "PDA maintains lower body perfusion; symptoms appear when ductus closes (day 1-5)", "Develops later", "Foramen ovale compensates"], a: 1, r: "With PDA open, blood flows through ductus to descending aorta. Neonate appears well. When ductus closes → collapse. CCHD screening is vital.", s: "Pediatrics" },
  { q: "Child with coarctation complains of headaches, nosebleeds, and leg claudication during exercise. Explanation?", o: ["Unrelated symptoms", "Upper body HTN (headaches, epistaxis) and lower body hypoperfusion (claudication) from aortic narrowing", "Migraine", "Iron deficiency"], a: 1, r: "Classic undiagnosed coarctation: upper body HTN causes headaches/epistaxis. Lower body receives reduced flow → exercise claudication.", s: "Pediatrics" },
  { q: "How does coarctation affect cerebrovascular risk?", o: ["No risk", "Upper body HTN increases risk of Berry aneurysm rupture and hemorrhagic stroke", "Only renal", "Protects against stroke"], a: 1, r: "Coarctation-related upper body HTN increases Berry aneurysm risk in circle of Willis. Rupture causes subarachnoid hemorrhage.", s: "Pediatrics" },
  { q: "Role of balloon angioplasty in coarctation?", o: ["First-line for neonates", "Primarily for recoarctation or native coarctation in older children/adults with stent", "Never used", "Only for PDA"], a: 1, r: "Balloon + stent preferred for recoarctation after prior repair. For native coarctation: stent in older children (>25 kg)/adults. Surgery preferred in young infants.", s: "Pediatrics" },
  { q: "Pre-operative priority for neonate with critical coarctation in shock?", o: ["Immediate surgery", "Stabilize first: PGE1 to reopen PDA, correct acidosis, inotropes, ventilation if needed", "Observation", "Antibiotics only"], a: 1, r: "Stabilize before surgery: PGE1, correct acidosis, inotropes, mechanical ventilation for respiratory failure, correct coagulopathy. Surgery once stabilized.", s: "Pediatrics" },
  { q: "Post-coarctation repair BP monitoring pattern?", o: ["Annual only", "Both upper and lower extremity BPs to detect recoarctation (return of gradient) and persistent HTN", "None after repair", "Only upper extremity"], a: 1, r: "Monitor both arms and legs for gradient return. Persistent HTN common even after repair. Exercise testing may unmask exercise-induced HTN.", s: "Pediatrics" },
  { q: "Why are femoral pulses assessed in all newborn exams?", o: ["Check for DVT", "Absent/weak femoral pulses may be the first sign of coarctation", "Assess hip dysplasia", "Check reflexes"], a: 1, r: "Femoral pulse palpation is critical in newborn cardiovascular exam. Absent/weak vs bounding brachial pulses = hallmark of coarctation.", s: "Pediatrics" },
  { q: "What effect does coarctation have on renal function?", o: ["No effect", "Reduced renal blood flow activates RAAS, contributing to HTN", "Improves renal function", "Only affects liver"], a: 1, r: "Reduced flow distal to coarctation → renal hypoperfusion → RAAS activation → HTN. Major contributor to persistent HTN even after repair.", s: "Pediatrics" },
  { q: "What is interrupted aortic arch vs coarctation?", o: ["Same", "Complete aortic arch discontinuity (no lumen) vs narrowing — interrupted is more severe, always ductal-dependent", "Less severe", "Only in adults"], a: 1, r: "Interrupted arch: complete discontinuity (no flow). Always ductal-dependent. Often associated with DiGeorge (22q11 deletion). 100% lethal without PGE1 and surgery.", s: "Pediatrics" },
  { q: "Medications for post-repair HTN?", o: ["None needed", "ACE inhibitors, beta-blockers, or ARBs for persistent hypertension", "Only diuretics", "Only CCBs"], a: 1, r: "ACE inhibitors (enalapril) or ARBs first-line (address RAAS activation). Beta-blockers also used. Goal: normalize BP to prevent complications.", s: "Pediatrics" },
  { q: "What imaging is used for long-term surveillance after coarctation repair?", o: ["None needed", "MRI/CT angiography for recoarctation, aneurysm at repair site, and arch morphology", "Only CXR", "Only echo"], a: 1, r: "MRA/CTA for detailed aortic arch imaging. Echo monitors cardiac function and BAV. MRI preferred to avoid radiation. Serial imaging throughout life.", s: "Pediatrics" },
  { q: "A 16-year-old diagnosed with coarctation. Preferred treatment?", o: ["Medication only", "Transcatheter stent placement preferred for older children/adolescents", "No treatment at this age", "Heart transplant"], a: 1, r: "For older children/adolescents/adults: transcatheter balloon + stent increasingly preferred. Less invasive, shorter recovery. Surgery for complex anatomy.", s: "Pediatrics" },
  { q: "What is subclavian steal after subclavian flap repair?", o: ["Normal finding", "Left subclavian artery sacrificed causing left arm claudication and BP discrepancy between arms", "Brain ischemia", "Right arm affected"], a: 1, r: "Subclavian flap repair uses left subclavian artery. May cause left arm shortening, reduced BP, claudication. Use right arm for BP monitoring.", s: "Pediatrics" },
  { q: "What collateral vessels develop with chronic coarctation?", o: ["Never develop", "Intercostal and internal mammary arteries enlarge to bypass the narrowing — cause rib notching on CXR", "Resolve the coarctation", "Only after surgery"], a: 1, r: "Dilated intercostal arteries (rib notching), internal mammary arteries bypass the coarctation. Presence indicates chronic obstruction in undiagnosed patients.", s: "Pediatrics" },
  { q: "Activity restrictions for child with coarctation?", o: ["No restrictions", "Before repair: avoid strenuous isometric exercise. After repair: depends on residual findings", "Complete bed rest", "Only swimming"], a: 1, r: "Before repair: restrict isometric exercise (dangerous BP spikes). After repair with no residual: gradual activity return. If residual gradient or BAV: restrict competitive sports.", s: "Pediatrics" },
  { q: "A neonate at 3 days of life develops acute cardiovascular collapse with absent femoral pulses, metabolic acidosis, and shock. Most likely diagnosis?", o: ["Sepsis", "Critical coarctation with ductal closure", "Heart failure from VSD", "Pneumonia"], a: 1, r: "Day 3 collapse with absent femoral pulses and acidosis: classic presentation of critical coarctation as the ductus arteriosus closes. Start PGE1 immediately.", s: "Pediatrics" },

  // ===== ANTICOAGULATION THERAPY (35 questions) =====
  { q: "Mechanism of UFH?", o: ["Vitamin K inhibition", "Potentiates antithrombin III, inactivating thrombin and factor Xa", "Direct thrombin inhibitor", "Blocks platelet aggregation"], a: 1, r: "UFH binds AT III, accelerating inactivation of thrombin and factor Xa. Short half-life (60-90 min), monitored by aPTT (target 1.5-2.5x control).", s: "Pharmacology" },
  { q: "Lab monitoring for heparin?", o: ["INR", "aPTT (activated partial thromboplastin time)", "Platelet count only", "Fibrinogen"], a: 1, r: "aPTT: therapeutic 1.5-2.5x control (~60-80 sec). Checked 6 hours after initiation or dose change. INR monitors warfarin.", s: "Pharmacology" },
  { q: "How does warfarin work?", o: ["Direct thrombin inhibition", "Inhibits vitamin K epoxide reductase, blocking synthesis of factors II, VII, IX, X", "Activates AT III", "Inhibits platelet adhesion"], a: 1, r: "Warfarin blocks vitamin K recycling → prevents synthesis of vitamin K-dependent factors (II, VII, IX, X) and proteins C, S. Full effect takes 3-5 days.", s: "Pharmacology" },
  { q: "Why overlap warfarin with heparin for 3-5 days?", o: ["Cost savings", "Warfarin takes 3-5 days for full effect; protein C depletion creates transient hypercoagulable state", "Same pathway", "No clinical reason"], a: 1, r: "Protein C (anticoagulant) depleted first, creating paradoxical hypercoagulable state. Heparin bridges until warfarin fully therapeutic.", s: "Pharmacology" },
  { q: "Advantage of DOACs over warfarin?", o: ["Cheaper", "Predictable PK, fixed dosing, no routine monitoring, fewer drug-food interactions", "No bleeding risk", "Reversed by vitamin K"], a: 1, r: "DOACs: predictable dose-response, no INR monitoring, fewer interactions, rapid onset (2-4 hours). Disadvantages: shorter half-life requires adherence, limited reversal agents.", s: "Pharmacology" },
  { q: "aPTT 95 seconds on heparin (therapeutic 60-80). No bleeding. Action?", o: ["Continue", "Stop/reduce heparin per protocol, notify provider, recheck aPTT", "Give protamine", "Increase rate"], a: 1, r: "Supratherapeutic aPTT = over-anticoagulation. Follow weight-based protocol to hold or reduce infusion.", s: "Pharmacology" },
  { q: "Key difference between LMWH and UFH?", o: ["Identical", "LMWH: longer half-life, predictable PK, SQ dosing, usually no aPTT monitoring needed", "UFH is SQ only", "LMWH needs more monitoring"], a: 1, r: "LMWH: predictable dose-response, weight-based SQ, predominantly inhibits factor Xa, no routine aPTT. Monitor anti-Xa in special populations.", s: "Pharmacology" },
  { q: "Warfarin INR 6.2 with gingival bleeding. Treatment?", o: ["Continue warfarin", "Hold warfarin, IV vitamin K, consider PCC if significant bleeding", "Protamine", "Idarucizumab"], a: 1, r: "INR >5 with bleeding: hold warfarin, IV vitamin K 5-10 mg. For significant bleeding, 4-factor PCC provides immediate factor replacement.", s: "Pharmacology" },
  { q: "Warfarin dietary teaching?", o: ["Avoid all green vegetables", "Maintain CONSISTENT vitamin K intake — don't dramatically change", "Eat max vitamin K", "No modifications"], a: 1, r: "Consistency is key. Sudden changes in vitamin K intake cause INR fluctuations. Don't eliminate vitamin K — maintain stable daily intake.", s: "Pharmacology" },
  { q: "Target INR for AFib/DVT on warfarin?", o: ["1.0-1.5", "2.0-3.0", "3.0-4.5", "4.0-5.0"], a: 1, r: "Most indications: INR 2.0-3.0. Mechanical mitral valve: 2.5-3.5. Below 2.0 = inadequate. Above 3.0 increases bleeding risk significantly.", s: "Pharmacology" },
  { q: "Mechanism of apixaban (Eliquis)?", o: ["Vitamin K antagonist", "Direct factor Xa inhibitor", "Direct thrombin inhibitor", "AT III activator"], a: 1, r: "Apixaban directly inhibits factor Xa. Oral, BID dosing, no routine monitoring required. Predictable pharmacokinetics.", s: "Pharmacology" },
  { q: "Mechanism of dabigatran (Pradaxa)?", o: ["Factor Xa inhibitor", "Direct thrombin (factor IIa) inhibitor", "Vitamin K antagonist", "Platelet inhibitor"], a: 1, r: "Dabigatran directly binds thrombin's active site. Doesn't need AT III. Only DOAC with specific reversal agent (idarucizumab).", s: "Pharmacology" },
  { q: "LMWH in renal impairment (CrCl <30)?", o: ["No concern", "Accumulation increases bleeding risk; reduce to once daily or switch to UFH", "Double dose", "Switch to aspirin"], a: 1, r: "LMWH cleared renally. CrCl <30: enoxaparin reduced to 1 mg/kg ONCE daily or switch to UFH. Monitor anti-Xa if continuing.", s: "Pharmacology" },
  { q: "What is HIT Type II?", o: ["Minor platelet drop", "Immune-mediated: antibodies against heparin-PF4 cause platelet activation and paradoxical THROMBOSIS", "Viral infection", "Hemophilia"], a: 1, r: "HIT II: IgG antibodies vs heparin-PF4 → platelet activation → thrombocytopenia + paradoxical thrombosis. Days 5-10. ALL heparin must stop.", s: "Pharmacology" },
  { q: "Client on heparin 7 days, platelets drop 250K to 90K. Suspect?", o: ["Normal variation", "HIT Type II — stop ALL heparin immediately", "Iron deficiency", "Dehydration"], a: 1, r: ">50% platelet drop at days 5-10 = suspect HIT II. Stop ALL heparin (including flushes). Start argatroban. No platelets. No warfarin until platelets recover.", s: "Pharmacology" },
  { q: "Weight-based heparin protocol?", o: ["One dose fits all", "80 units/kg bolus then 18 units/kg/hr infusion with aPTT adjustments q6h", "Fixed 1000 units/hr", "SQ only"], a: 1, r: "Weight-based: bolus 80 u/kg, then 18 u/kg/hr. aPTT at 6 hours, adjusted per nomogram. More reliable than fixed-dose protocols.", s: "Pharmacology" },
  { q: "DOAC teaching about rivaroxaban?", o: ["Skip doses for a week", "Take 20 mg dose WITH food (increases bioavailability by 39%); if missed, take same day", "Take without food", "Double next dose"], a: 1, r: "Rivaroxaban 20 mg must be taken WITH FOOD. If missed, take same day. Unique among DOACs: once-daily for AFib.", s: "Pharmacology" },
  { q: "What is bridge anticoagulation?", o: ["Never needed", "Short-acting anticoagulant perioperatively when warfarin is held for high-risk patients", "Switching oral drugs", "IV to oral only"], a: 1, r: "Bridge: stop warfarin 5 days pre-op, start LMWH/UFH. Needed for high-risk (mechanical valve, recent VTE). DOACs usually don't need bridging.", s: "Pharmacology" },
  { q: "Drugs that increase warfarin bleeding risk?", o: ["Vitamin K", "Antibiotics (metronidazole, TMP-SMX), amiodarone, NSAIDs, many herbals", "ACE inhibitors", "Statins"], a: 1, r: "Drugs increasing warfarin effect: antibiotics, amiodarone, NSAIDs, SSRIs, acetaminophen (high doses). Herbals: ginkgo, garlic, ginger.", s: "Pharmacology" },
  { q: "SQ injection technique for enoxaparin?", o: ["IM in deltoid", "SQ into abdominal fat, alternating sides, do NOT aspirate or massage", "IV push", "SQ in thigh only"], a: 1, r: "Enoxaparin SQ: abdominal fat (2 inches from umbilicus), alternate sides. No aspiration. No massage. Leave air bubble in syringe.", s: "Pharmacology" },
  { q: "Significance of CrCl in DOAC prescribing?", o: ["Not important", "DOACs have varying renal clearance; dose adjustments or contraindications based on CrCl", "Only warfarin", "Only UFH"], a: 1, r: "Renal clearance: dabigatran (80% renal), rivaroxaban (33%), apixaban (27%). Lower CrCl requires dose reduction. Monitor renal function annually.", s: "Pharmacology" },
  { q: "What is the anti-Xa assay used for?", o: ["Alternative to INR", "Measures anticoagulant effect of LMWH and Xa inhibitors in special populations", "Measures platelet function", "Only for heparin"], a: 1, r: "Anti-Xa monitors LMWH in obesity, renal failure, pregnancy, pediatrics. Can also monitor DOACs in emergencies.", s: "Pharmacology" },
  { q: "Client on warfarin eats consistent large daily salad. Concerned?", o: ["Yes, avoid all vitamin K", "No — consistent intake is fine; the dose is adjusted accordingly", "Switch to DOAC", "Double warfarin"], a: 1, r: "Consistent vitamin K intake is acceptable. Warfarin dose is titrated to the patient's usual pattern. Only CHANGES cause INR fluctuations.", s: "Pharmacology" },
  { q: "What is warfarin skin necrosis?", o: ["Common side effect", "Rare complication 3-8 days post-initiation from protein C depletion causing microvascular thrombosis", "Allergic rash", "Sun damage"], a: 1, r: "Warfarin skin necrosis: protein C (short half-life) depleted before procoagulant factors → transient hypercoagulability → microvascular thrombosis → skin necrosis. Prevention: heparin bridging.", s: "Pharmacology" },
  { q: "What labs should be drawn before starting any anticoagulant?", o: ["Only CBC", "Baseline CBC, PT/INR, aPTT, renal function, liver function, pregnancy test if applicable", "Only BMP", "None"], a: 1, r: "Baseline labs establish reference for monitoring: CBC (hemoglobin for bleeding detection, platelets), coag studies, renal function (DOAC dosing), hepatic function, pregnancy test.", s: "Pharmacology" },

  // ===== BLEEDING RISKS & REVERSAL (35 questions) =====
  { q: "Heparin reversal agent?", o: ["Vitamin K", "Protamine sulfate — 1 mg per 100 units heparin", "Idarucizumab", "Andexanet alfa"], a: 1, r: "Protamine: 1 mg per 100 units heparin in preceding 2-3 hours. Slow IV (10 min). Partially reverses LMWH (~60%).", s: "Pharmacology" },
  { q: "What is idarucizumab (Praxbind)?", o: ["Reverses warfarin", "Monoclonal antibody fragment specifically reversing dabigatran", "Reverses all DOACs", "Reverses heparin"], a: 1, r: "Idarucizumab binds dabigatran with 350x greater affinity than thrombin. Dose: 5 g IV. Reverses ONLY dabigatran.", s: "Pharmacology" },
  { q: "What reverses factor Xa inhibitors?", o: ["Protamine", "Vitamin K", "Idarucizumab", "Andexanet alfa (Andexxa) — recombinant modified Xa decoy"], a: 3, r: "Andexanet alfa: recombinant modified factor Xa that acts as decoy receptor. If unavailable, 4-factor PCC is off-label alternative.", s: "Pharmacology" },
  { q: "Anticoagulant bleeding precautions?", o: ["No precautions", "Soft toothbrush, electric razor, avoid IM injections, hold pressure 5+ min, fall prevention", "Restrict all activity", "Stop all meds"], a: 1, r: "Bleeding precautions: soft toothbrush, electric razor, avoid IM, prolonged pressure on venipunctures, fall prevention, stool softeners, avoid ASA/NSAIDs.", s: "Pharmacology" },
  { q: "Signs of internal bleeding in anticoagulated patients?", o: ["Elevated glucose", "Unexplained tachycardia, hypotension, melena, hemoptysis, hematuria, declining Hgb, AMS", "Elevated temp only", "Weight gain"], a: 1, r: "Internal bleeding: tachycardia (earliest), hypotension, dropping Hgb, melena, hemoptysis, hematuria, petechiae, headache with neuro changes (ICH).", s: "Pharmacology" },
  { q: "Alternative anticoagulant for HIT?", o: ["Different heparin", "Argatroban (direct thrombin inhibitor, no HIT cross-reactivity)", "Warfarin immediately", "Aspirin"], a: 1, r: "Argatroban: DTI, no HIT cross-reactivity. IV infusion monitored by aPTT. Bivalirudin also an option. No warfarin until platelets recover.", s: "Pharmacology" },
  { q: "What is 4-factor PCC?", o: ["Blood type", "Concentrated factors II, VII, IX, X for urgent warfarin reversal", "A coag test", "A type of FFP"], a: 1, r: "4-factor PCC (Kcentra): concentrated factors II, VII, IX, X + proteins C, S. Rapid INR reversal (15-30 min). Off-label for Xa inhibitor reversal.", s: "Pharmacology" },
  { q: "How does protamine reverse heparin?", o: ["Blocks receptors", "Positively charged protamine forms ionic bond with negatively charged heparin, neutralizing it", "Enhances metabolism", "Hepatic destruction"], a: 1, r: "Protamine (positive charge) electrostatically binds heparin (negative charge), forming stable inactive complex. Immediate effect.", s: "Pharmacology" },
  { q: "Allergic considerations with protamine?", o: ["No allergic risk", "Increased risk in fish allergy, prior protamine exposure, vasectomized men (derived from fish sperm)", "Only latex allergy", "Only in children"], a: 1, r: "Protamine from salmon sperm. Increased anaphylactoid risk: fish allergy, prior exposure, vasectomized men. Administer slowly, have epinephrine ready.", s: "Pharmacology" },
  { q: "IV vs oral vitamin K for warfarin reversal?", o: ["No speed difference", "IV acts 6-8 hours; oral acts 12-24 hours. IV has anaphylactoid risk, infuse slowly", "Oral is faster", "IV never used"], a: 1, r: "IV vitamin K: onset 6-8 hours, for serious bleeding. Must infuse slowly. Oral: onset 12-24 hours, for elevated INR without bleeding. SQ erratic — avoid.", s: "Pharmacology" },
  { q: "Anticoagulated client falls and hits head. No visible injury. Priority?", o: ["Apply ice", "Neurological assessment, notify provider, anticipate CT — ICH risk is high on anticoagulants", "No assessment needed", "Give vitamin K"], a: 1, r: "Head trauma on anticoagulation: high ICH risk with possible delayed presentation. Immediate neuro assessment, CT head, close monitoring 24 hours.", s: "Pharmacology" },
  { q: "When is activated charcoal useful for DOAC overdose?", o: ["Never", "Within 2 hours of ingestion to reduce GI absorption", "After 24 hours", "Only warfarin"], a: 1, r: "Charcoal can reduce DOAC absorption if given within 2 hours of ingestion. Not useful for heparin (IV) or chronic warfarin.", s: "Pharmacology" },
  { q: "Client on anticoagulation reports black tarry stools. Priority?", o: ["Normal finding", "Hold anticoagulant, assess vitals, check Hgb, type/screen, notify provider — melena indicates upper GI bleeding", "Continue meds", "Only if >1 week"], a: 1, r: "Melena = upper GI bleeding. Hold anticoagulant, assess for hypovolemia, check labs, prepare for possible endoscopy.", s: "Pharmacology" },
  { q: "Preoperative anticoagulation management?", o: ["Continue all", "Warfarin: stop 5 days pre-op. DOACs: 24-48 hours hold. Bridge if high thrombotic risk", "Stop 1 month before", "No changes"], a: 1, r: "Warfarin stopped 5 days (INR <1.5). DOACs 24-48 hours (longer for renal impairment). Bridge for high-risk patients.", s: "Pharmacology" },
  { q: "What is the HAS-BLED 'L' component?", o: ["Liver disease", "Labile INR — <60% time in therapeutic range", "Leukemia", "Lactation"], a: 1, r: "L = Labile INR: TTR <60%. Indicates poor control. Consider switching to DOAC to eliminate this risk factor.", s: "Pharmacology" },
  { q: "Why should platelet transfusion be AVOIDED in HIT?", o: ["Too expensive", "Transfused platelets are activated by HIT antibodies, fueling MORE thrombosis", "Not available", "No reason to avoid"], a: 1, r: "In HIT, transfused platelets activated by existing antibodies → more thrombin → worsening thrombosis. 'Adding fuel to fire.' Only transfuse if life-threatening hemorrhage.", s: "Pharmacology" },
  { q: "Components of the 4T scoring system for HIT?", o: ["Temperature, Tenderness, Timing, Treatment", "Thrombocytopenia severity, Timing of fall, Thrombosis, oTher causes ruled out", "Four tests", "Therapeutic, Toxic, Target, Treatment"], a: 1, r: "4T score: Thrombocytopenia (% drop), Timing (days 5-10), Thrombosis, oTher causes ruled out. Score ≥5 = compatible with overt HIT.", s: "Pharmacology" },
  { q: "Client on HIT develops DVT. Why is this NOT contradictory?", o: ["It is contradictory", "HIT is a PROthrombotic disorder — activated platelets release prothrombotic particles; clotting is the primary risk", "DVT is unrelated", "HIT only causes bleeding"], a: 1, r: "HIT paradox: platelets consumed in thrombotic processes, not destroyed by bleeding. Primary risk is thrombosis (50% if untreated).", s: "Pharmacology" },
  { q: "What is tranexamic acid (TXA)?", o: ["An anticoagulant", "Antifibrinolytic preventing clot breakdown; adjunct in severe bleeding", "A thrombolytic", "Vitamin K supplement"], a: 1, r: "TXA inhibits plasminogen activation, preventing fibrinolysis. Used in trauma, postpartum hemorrhage, surgical bleeding as adjunct.", s: "Pharmacology" },
  { q: "Nurse's role in anticoagulation stewardship?", o: ["Only give meds", "Verify drug/dose/indication, assess contraindications, monitor labs, educate patients, recognize complications, ensure safe transitions", "No role", "Only check INR"], a: 1, r: "Comprehensive role: verify indication, assess contraindications, monitor labs, patient education, recognize complications, safe discharge.", s: "Pharmacology" },
  { q: "Reversal agent for edoxaban?", o: ["Idarucizumab", "No specific agent; 4-factor PCC off-label or andexanet alfa", "Protamine", "Vitamin K"], a: 1, r: "Edoxaban has no specifically approved reversal agent. 4-factor PCC is recommended off-label. Andexanet alfa may work but approval may be limited.", s: "Pharmacology" },
  { q: "What is the nurse's priority when transitioning from heparin to warfarin?", o: ["Stop heparin when first warfarin given", "Overlap minimum 5 days AND INR therapeutic ≥24 hours before stopping heparin", "Never overlap", "Switch immediately"], a: 1, r: "Both criteria must be met before stopping heparin. Early discontinuation risks thrombosis from insufficient warfarin effect.", s: "Pharmacology" },
  { q: "Client discharged on warfarin. Which statement shows correct understanding?", o: ["I'll take ibuprofen for headaches", "I'll maintain consistent vitamin K intake, use soft toothbrush, report unusual bleeding, keep INR appointments", "I'll stop when I feel better", "Unlimited alcohol is fine"], a: 1, r: "Correct: consistent vitamin K, soft toothbrush, electric razor, avoid NSAIDs, report bleeding, regular INR, inform all providers, medical alert ID.", s: "Pharmacology" },
  { q: "What is the difference between 4-factor PCC and FFP for warfarin reversal?", o: ["No difference", "PCC provides concentrated factors in smaller volume with faster onset (15-30 min) vs FFP (hours, larger volume, risk of volume overload)", "FFP is faster", "PCC only for DOACs"], a: 1, r: "4-factor PCC advantages: concentrated factors in small volume (~40 mL), rapid onset (15-30 min), no thawing required. FFP: larger volume (multiple units), slower, thawing delay, volume overload risk.", s: "Pharmacology" },
  { q: "A client on apixaban is scheduled for emergency surgery. What does the nurse anticipate for reversal?", o: ["Vitamin K", "Andexanet alfa if available, or 4-factor PCC off-label; activated charcoal if last dose <2 hours ago", "Protamine sulfate", "Wait 48 hours"], a: 1, r: "Emergency apixaban reversal: andexanet alfa (specific reversal), or 4-factor PCC (off-label). Charcoal if last dose recent. Time-dependent clearance may also suffice for non-emergent procedures.", s: "Pharmacology" },

  // ===== DIC (35 questions) =====
  { q: "What is the DIC paradox?", o: ["Only bleeding", "Simultaneous widespread clotting AND hemorrhage — consumptive coagulopathy", "Only thrombosis", "Only affects lungs"], a: 1, r: "DIC: widespread microvascular thrombosis CONSUMES factors/platelets → hemorrhage from depletion. Meanwhile, microthrombi cause end-organ ischemia.", s: "Pharmacology" },
  { q: "Most common DIC trigger?", o: ["Chronic HTN", "Sepsis", "Osteoarthritis", "GERD"], a: 1, r: "Sepsis is #1 trigger. Others: obstetric complications, major trauma, malignancy (APL), massive transfusion, burns, snake bites.", s: "Pharmacology" },
  { q: "Classic DIC lab findings?", o: ["All normal", "Elevated D-dimer, elevated PT/aPTT, decreased fibrinogen, decreased platelets, schistocytes", "Elevated Hgb", "Normal D-dimer"], a: 1, r: "DIC labs: markedly elevated D-dimer/FDPs, prolonged PT/aPTT, decreased fibrinogen (<100), thrombocytopenia, schistocytes, elevated LDH.", s: "Pharmacology" },
  { q: "Most important DIC treatment principle?", o: ["Heparin for all", "Treat the underlying cause while providing supportive blood product replacement", "Surgery always", "Steroids"], a: 1, r: "Cornerstone: treat CAUSE (antibiotics for sepsis, delivery for obstetric). Supportive: platelets, cryoprecipitate, FFP, pRBCs.", s: "Pharmacology" },
  { q: "D-dimer significance in DIC?", o: ["Always normal", "Elevated D-dimer = active fibrinolysis. Normal D-dimer essentially rules out DIC", "Measures platelet function", "Only for PE"], a: 1, r: "D-dimer from fibrin degradation. Markedly elevated in DIC. While nonspecific, normal D-dimer essentially rules out DIC.", s: "Pharmacology" },
  { q: "What are schistocytes?", o: ["WBCs", "Fragmented RBCs from mechanical shearing through fibrin strands — microangiopathic hemolytic anemia", "Normal RBCs", "Immature platelets"], a: 1, r: "Schistocytes form when RBCs are sheared through fibrin strands in microvessels. Their presence supports DIC diagnosis.", s: "Pharmacology" },
  { q: "Blood products for actively bleeding DIC?", o: ["Albumin only", "Platelets, FFP, cryoprecipitate, and pRBCs as indicated", "NS only", "Dextrose"], a: 1, r: "Active DIC: platelets if <50K, cryoprecipitate for fibrinogen (target >100-150), FFP for factors, pRBCs for anemia.", s: "Pharmacology" },
  { q: "Critical DIC nursing assessments?", o: ["Daily weight only", "Check ALL body fluids for blood, assess perfusion, track serial coag labs", "RR only", "Temp only"], a: 1, r: "Check all fluids for blood (urine, stool, sputum, drains), petechiae/ecchymoses, neuro status, extremity perfusion, VS, serial labs.", s: "Pharmacology" },
  { q: "Why is cryoprecipitate used in DIC?", o: ["Contains RBCs", "Rich in fibrinogen, factor VIII, XIII, and vWF — components consumed in DIC", "Lowers BP", "Treats infections"], a: 1, r: "Cryoprecipitate: concentrated fibrinogen, factor VIII, XIII, vWF, fibronectin. Efficiently replaces fibrinogen (each unit raises ~5-10 mg/dL).", s: "Pharmacology" },
  { q: "Obstetric DIC from placental abruption: priority?", o: ["Tocolytics", "Delivery to remove thromboplastin source", "Continue expectant management", "Heparin"], a: 1, r: "Placenta = source of tissue factor triggering coagulation. Delivery removes trigger = definitive treatment. Blood product resuscitation simultaneously.", s: "Pharmacology" },
  { q: "What is the ISTH DIC scoring system?", o: ["Treatment protocol", "Diagnostic score using platelet count, D-dimer, PT prolongation, fibrinogen. Score ≥5 = overt DIC", "Imaging classification", "Surgical staging"], a: 1, r: "ISTH DIC score: platelet count (0-2), D-dimer (0-3), PT prolongation (0-2), fibrinogen (0-1). Score ≥5 = overt DIC. Serial scoring q8-12h.", s: "Pharmacology" },
  { q: "Why does DIC cause organ damage without visible hemorrhage?", o: ["It doesn't", "Microvascular thrombosis obstructs blood flow to organs causing ischemic injury", "Only bleeding matters", "From medications"], a: 1, r: "Microthrombi occlude small vessels: renal failure, ARDS, hepatic dysfunction, AMS, skin necrosis (purpura fulminans).", s: "Pharmacology" },
  { q: "Role of heparin in DIC?", o: ["Always contraindicated", "Controversial; may help when thrombotic features predominate; contraindicated in hemorrhagic DIC", "First-line for all", "Only chronic DIC"], a: 1, r: "Heparin in DIC is controversial. May help thrombotic-predominant (purpura fulminans, digital ischemia). Contraindicated in hemorrhagic DIC.", s: "Pharmacology" },
  { q: "What is purpura fulminans?", o: ["Mild rash", "Rapidly progressive purpura with skin necrosis from DIC microvascular thrombosis", "Allergic reaction", "Vitamin deficiency"], a: 1, r: "Purpura fulminans: rapidly progressive, symmetrical purpura with skin necrosis from DIC. Most commonly with meningococcemia. Aggressive DIC management required.", s: "Pharmacology" },
  { q: "Client with DIC has fibrinogen 48 mg/dL. How many cryo units needed?", o: ["1 unit", "10-20 units to achieve target >100-150 mg/dL", "100 units", "None"], a: 1, r: "Target >100-150 mg/dL. Starting at 48, need to raise ~50-100 mg/dL. Each unit raises ~5-10 mg/dL. Approximately 10-20 units needed.", s: "Pharmacology" },
  { q: "What is chronic (compensated) DIC?", o: ["Same as acute", "Slower form with partial compensation; seen in malignancy, may present with thrombosis", "Resolved DIC", "CKD"], a: 1, r: "Chronic DIC: slower activation balanced by increased factor production. Labs may be near-normal. Seen with malignancy. May present with thrombosis rather than hemorrhage.", s: "Pharmacology" },
  { q: "How do FDPs worsen DIC?", o: ["Helpful factors", "FDPs inhibit thrombin, impair fibrin polymerization, and worsen bleeding — vicious cycle", "Stop bleeding", "RBC fragments"], a: 1, r: "FDPs from fibrin breakdown: inhibit thrombin, interfere with clot formation, impair platelet function. Creates vicious cycle of more bleeding.", s: "Pharmacology" },
  { q: "Septic patient with DIC develops decreased UOP and rising creatinine. What does this indicate?", o: ["Normal in sepsis", "Renal microvascular thrombosis causing AKI — may need RRT", "Dehydration only", "UTI"], a: 1, r: "Renal microthrombi → AKI (oliguria, rising Cr). May need RRT. Improving DIC by treating underlying cause is essential for recovery.", s: "Pharmacology" },
  { q: "What differentiates DIC from TTP?", o: ["Same condition", "DIC: low fibrinogen, elevated PT/aPTT. TTP: normal fibrinogen and PT/aPTT, ADAMTS13 deficiency", "Only age", "Only gender"], a: 1, r: "Key: DIC has consumed fibrinogen (low) and prolonged PT/aPTT. TTP has normal fibrinogen and PT/aPTT. Both have schistocytes/thrombocytopenia. Different treatments.", s: "Pharmacology" },
  { q: "Priority when DIC is suspected?", o: ["Wait for labs", "Notify provider, STAT coag labs, type/screen, assess bleeding and organ perfusion", "Give aspirin", "Warm compresses"], a: 1, r: "Immediate: notify provider, STAT labs (PT, aPTT, fibrinogen, D-dimer, CBC, smear), type/screen, assess all body fluids for blood, assess organ perfusion.", s: "Pharmacology" },
  { q: "How does amniotic fluid embolism cause DIC?", o: ["Through infection", "Tissue factor and fetal antigens enter maternal circulation, triggering massive coagulation activation", "Through hemorrhage only", "Only respiratory"], a: 1, r: "Amniotic fluid rich in tissue factor/fetal cells enters maternal circulation → massive coagulation cascade activation → DIC. Also anaphylactoid reaction. Mortality 20-60%.", s: "Pharmacology" },
  { q: "Expected fibrinogen trend in improving DIC?", o: ["Continues to drop", "Rising fibrinogen indicates improving DIC — a positive prognostic sign", "Stays at zero", "Unmeasurable"], a: 1, r: "Rising fibrinogen = improving DIC. As cause is treated, consumption decreases and liver resumes production. Trend fibrinogen q6-8h.", s: "Pharmacology" },
  { q: "Why minimize venipunctures in DIC patients?", o: ["Not important", "Each puncture site is a potential uncontrolled bleeding source due to depleted factors and platelets", "Save time", "Reduce pain only"], a: 1, r: "DIC patients lack clotting factors/platelets. Every puncture can bleed uncontrollably. Use existing lines, consolidate draws, apply prolonged pressure (10+ min).", s: "Pharmacology" },
  { q: "APL patient with DIC. What specific treatment helps both?", o: ["Doxorubicin", "All-trans retinoic acid (ATRA) stops procoagulant granule release from malignant promyelocytes", "Cisplatin", "Methotrexate"], a: 1, r: "ATRA induces promyelocyte differentiation, stopping release of procoagulant granules that trigger DIC. Treats root cause of APL-associated DIC.", s: "Pharmacology" },
  { q: "Massive transfusion in DIC: key considerations?", o: ["Only pRBCs", "Balanced 1:1:1 ratio (pRBCs:FFP:platelets), cryoprecipitate for fibrinogen, monitor ionized calcium, use blood warmers", "No protocol", "Only crystalloids"], a: 1, r: "1:1:1 ratio prevents dilutional coagulopathy. Cryo for fibrinogen. Monitor ionized calcium (citrate chelation). Blood warmers prevent hypothermia.", s: "Pharmacology" },
  { q: "A client with DIC has petechiae on the trunk and oozing from IV sites but is also developing digital ischemia in the fingers. How does the nurse explain this dual presentation?", o: ["Two separate diseases", "DIC causes BOTH hemorrhage (from depleted clotting factors) AND thrombosis (from microvascular clot formation) simultaneously", "The bleeding is from the IV sites only", "Digital ischemia is unrelated to DIC"], a: 1, r: "This is the hallmark DIC paradox: consumption of clotting factors causes hemorrhage while simultaneous microvascular thrombosis causes ischemia. Treatment must address both: blood products for bleeding, treat underlying cause to stop the process.", s: "Pharmacology" },
  { q: "What is the target fibrinogen level in DIC management?", o: ["Any level above zero", "Greater than 100-150 mg/dL — replace with cryoprecipitate", "Greater than 300 mg/dL", "Less than 50 mg/dL"], a: 1, r: "Target fibrinogen >100-150 mg/dL. Below this level, insufficient fibrinogen is available for effective clot formation, worsening hemorrhage. Give cryoprecipitate to replace.", s: "Pharmacology" },
  { q: "A nurse is monitoring a client with DIC. Which finding indicates the condition is worsening?", o: ["Platelet count increasing", "Fibrinogen dropping, D-dimer rising, new petechiae, and declining renal function", "INR normalizing", "Improving mental status"], a: 1, r: "Worsening DIC: falling fibrinogen (increased consumption), rising D-dimer (increased fibrinolysis), new bleeding (petechiae, oozing), and organ dysfunction (renal, neurological).", s: "Pharmacology" },
  { q: "What blood component replaces clotting factors in DIC?", o: ["Packed RBCs", "Fresh frozen plasma (FFP) — contains all clotting factors", "Albumin", "Normal saline"], a: 1, r: "FFP contains all coagulation factors and is used when PT/aPTT are significantly prolonged. Cryoprecipitate specifically replaces fibrinogen. Platelets replace consumed platelets.", s: "Pharmacology" },
  { q: "What is the primary nursing goal in DIC management?", o: ["Achieve normal labs immediately", "Maintain tissue perfusion and prevent life-threatening hemorrhage while supporting treatment of the underlying cause", "Eliminate all clotting", "Complete bed rest only"], a: 1, r: "Primary goals: maintain perfusion (monitor VS, UOP, neuro), prevent/control hemorrhage (blood products, minimize trauma), support treatment of underlying cause, and monitor serial labs to trend improvement.", s: "Pharmacology" },

  // ===== ATRIAL FLUTTER SUPPLEMENTAL (5 questions) =====
  { q: "A client with atrial flutter has a ventricular rate of 150 bpm with 2:1 conduction. What does '2:1 conduction' mean?", o: ["Two QRS complexes for each flutter wave", "For every two flutter waves (atrial rate ~300), only one is conducted to the ventricles, resulting in ventricular rate of ~150 bpm", "The heart rate doubles every minute", "Two ventricles are beating simultaneously"], a: 1, r: "Flutter atrial rate ~300 bpm. With 2:1 block, every other impulse is conducted → ventricular rate ~150. With 4:1 block → ~75 bpm. A regular rate of exactly 150 should always raise suspicion for flutter with 2:1 block.", s: "Arrhythmias" },
  { q: "What is the difference between typical and atypical atrial flutter?", o: ["There is no difference", "Typical flutter uses a counterclockwise circuit around the tricuspid valve annulus (cavotricuspid isthmus dependent); atypical flutter uses other reentrant circuits and is harder to ablate", "Typical is faster", "Atypical only occurs in children"], a: 1, r: "Typical (CTI-dependent) flutter: counterclockwise circuit around tricuspid annulus → predictable sawtooth in inferior leads → highly responsive to CTI ablation (>95% success). Atypical uses other circuits and is more challenging to treat.", s: "Arrhythmias" },
  { q: "A nurse is preparing a client with atrial flutter for electrical cardioversion. What energy level is typically used initially?", o: ["360 joules", "50-100 joules synchronized — flutter typically converts at lower energy than fibrillation", "10 joules", "Unsynchronized shock at 200 joules"], a: 1, r: "Atrial flutter responds to lower cardioversion energy (50-100J synchronized) compared to AFib (120-200J). Always use synchronized mode to deliver shock on the R wave and avoid inducing VFib.", s: "Arrhythmias" },
  { q: "Why is ibutilide used cautiously for pharmacological cardioversion of atrial flutter?", o: ["It causes hyperkalemia", "It prolongs the QT interval and carries risk of torsades de pointes — requires continuous cardiac monitoring for at least 4-6 hours after administration", "It increases heart rate", "It has no effect on flutter"], a: 1, r: "Ibutilide: Class III antiarrhythmic that prolongs repolarization (QT prolongation). Risk of torsades de pointes is ~4%. Requires: continuous telemetry, IV magnesium available, defibrillator at bedside during and for 4-6 hours after infusion.", s: "Arrhythmias" },
  { q: "A client with chronic atrial flutter is on flecainide without a rate-controlling agent. What dangerous complication can occur?", o: ["No complications", "1:1 conduction — flecainide slows the atrial rate (from 300 to ~200 bpm), which may allow 1:1 AV conduction resulting in ventricular rate of 200 bpm", "Complete heart block", "Hypothermia"], a: 1, r: "Class IC drugs (flecainide, propafenone) can slow atrial flutter rate enough that the AV node can conduct every beat (1:1). This creates dangerously fast ventricular rates. ALWAYS co-prescribe an AV nodal blocker (beta-blocker or CCB).", s: "Arrhythmias" },

  // ===== SVT SUPPLEMENTAL (4 questions) =====
  { q: "A nurse administers adenosine 6 mg rapid IV push for SVT. After a brief pause, the SVT returns. What is the next step?", o: ["Give a third dose immediately", "Administer 12 mg adenosine rapid IV push — the second dose is doubled when the initial 6 mg dose is ineffective", "Start an adenosine drip", "Perform synchronized cardioversion"], a: 1, r: "Adenosine dosing for SVT: 6 mg rapid IV push → if ineffective, 12 mg rapid IV push → if still ineffective, 12 mg one more time. Must be given rapidly (1-2 sec) followed by 20 mL NS flush due to ultra-short half-life (~6 seconds).", s: "Arrhythmias" },
  { q: "What happens on the telemetry monitor during adenosine administration for SVT?", o: ["Nothing visible occurs", "Brief period of asystole (flat line) or marked bradycardia as the AV node is transiently blocked — this is expected and self-resolving within seconds", "Immediate conversion to VFib", "Gradual rate decrease over minutes"], a: 1, r: "Adenosine causes transient AV nodal block → brief asystole or extreme bradycardia on the monitor. This is EXPECTED and resolves within 6-10 seconds. Warn the patient they may feel a brief sensation of chest pressure or 'impending doom'.", s: "Arrhythmias" },
  { q: "A client with WPW syndrome (delta wave on ECG) presents with SVT. Which medication is CONTRAINDICATED?", o: ["Adenosine is always safe", "AV nodal blockers (verapamil, diltiazem, digoxin) — blocking the AV node may force conduction down the accessory pathway, potentially causing VFib", "Procainamide", "Amiodarone"], a: 1, r: "WPW + SVT: AV nodal blockers are DANGEROUS. If AFib develops with WPW, blocking the AV node forces all conduction down the accessory pathway → extremely rapid ventricular rate → VFib. Use procainamide or cardioversion instead.", s: "Arrhythmias" },
  { q: "What is the Valsalva maneuver and why does it help terminate SVT?", o: ["Deep breathing to increase oxygen", "Bearing down as if having a bowel movement increases vagal tone, which slows AV nodal conduction and can break the reentrant circuit that sustains SVT", "Coughing to clear the airway", "Raising the arms above the head"], a: 1, r: "Valsalva maneuver (bearing down, blowing against closed glottis) → increased intrathoracic pressure → vagal stimulation → slowed AV conduction → may interrupt reentrant SVT circuit. Other vagal maneuvers: carotid massage, cold water to face (diving reflex).", s: "Arrhythmias" },

  // ===== VENTRICULAR TACHYCARDIA SUPPLEMENTAL (5 questions) =====
  { q: "A nurse is caring for a client on telemetry who develops sustained monomorphic VTach at 180 bpm with a blood pressure of 82/50. What is the FIRST intervention?", o: ["Give adenosine", "Synchronized cardioversion — the client has pulsatile VTach with hemodynamic instability (hypotension)", "Defibrillate unsynchronized", "Administer oral amiodarone"], a: 1, r: "Sustained VTach WITH pulse but hemodynamically unstable (hypotension, AMS, chest pain) → synchronized cardioversion at 100J. If pulseless VTach → defibrillation (unsynchronized). Stable VTach may trial amiodarone first.", s: "Arrhythmias" },
  { q: "What distinguishes monomorphic from polymorphic VTach on ECG?", o: ["They look identical", "Monomorphic has uniform QRS morphology (one reentrant circuit); polymorphic has varying QRS morphology and may include torsades de pointes (twisting around the baseline)", "Monomorphic is always faster", "Polymorphic only occurs in pediatric patients"], a: 1, r: "Monomorphic VTach: consistent QRS shape (single focus/circuit) — treat with amiodarone, cardioversion. Polymorphic VTach: varying QRS morphology — if QT prolonged, it's torsades → treat with IV magnesium, overdrive pacing. Different treatments.", s: "Arrhythmias" },
  { q: "A client has recurrent VTach episodes despite antiarrhythmic therapy and has an ICD in place. The ICD has fired 4 times in 1 hour. What is this called?", o: ["Normal ICD function", "Electrical storm — 3 or more sustained VT/VF episodes within 24 hours, requiring urgent intervention with IV amiodarone, sedation, and possibly catheter ablation", "ICD malfunction", "Phantom shocks"], a: 1, r: "Electrical storm: ≥3 VT/VF episodes in 24 hours. Emergency management: IV amiodarone loading, anxiolysis/sedation, correct electrolytes, consider intubation and deep sedation. Long-term: catheter ablation of VT focus, sympathetic denervation.", s: "Arrhythmias" },
  { q: "Why is hypomagnesemia dangerous in a client at risk for VTach?", o: ["Magnesium has no cardiac effects", "Low magnesium prolongs repolarization and destabilizes the cardiac membrane, increasing risk of ventricular arrhythmias including torsades de pointes", "It only affects skeletal muscle", "It causes bradycardia"], a: 1, r: "Magnesium stabilizes the cardiac cell membrane and is a cofactor for the Na/K ATPase pump. Deficiency → prolonged QT → increased risk of early afterdepolarizations → torsades de pointes. Always check and replace Mg alongside K.", s: "Arrhythmias" },
  { q: "A client with known structural heart disease develops wide-complex tachycardia. Should this be treated as SVT with aberrancy or VTach?", o: ["Always assume SVT", "Always assume VTach in a patient with structural heart disease — wide-complex tachycardia is VTach until proven otherwise, especially with cardiac history", "Wait for cardiology consult", "The distinction doesn't matter"], a: 1, r: "Clinical rule: wide-complex tachycardia = VTach until proven otherwise, especially with structural heart disease (prior MI, cardiomyopathy). Treating VTach as SVT (giving verapamil) can be fatal. The safe approach is to treat as VTach.", s: "Arrhythmias" },

  // ===== VENTRICULAR FIBRILLATION SUPPLEMENTAL (10 questions) =====
  { q: "A code blue is called. The monitor shows VFib. What is the FIRST action?", o: ["Give epinephrine", "Begin high-quality CPR and prepare for immediate defibrillation — VFib is a shockable rhythm", "Intubate the patient", "Obtain IV access first"], a: 1, r: "VFib = immediate CPR + defibrillation. Do not delay defibrillation for medications or intubation. Early defibrillation is the single most important intervention. Every minute without defibrillation decreases survival by 7-10%.", s: "Arrhythmias" },
  { q: "During a code, the first defibrillation attempt does not convert VFib. What is the next step per ACLS?", o: ["Pronounce death", "Resume CPR for 2 minutes, then reassess rhythm and shock again if still VFib. Give epinephrine 1 mg IV after the second shock", "Immediately shock again", "Start an amiodarone drip"], a: 1, r: "ACLS VFib algorithm: Shock → CPR 2 min → reassess → Shock → CPR 2 min + epi 1 mg → reassess → Shock → CPR 2 min + amiodarone 300 mg → continue cycles. Epi every 3-5 min. Amiodarone second dose 150 mg.", s: "Arrhythmias" },
  { q: "What energy level is used for defibrillation of VFib with a biphasic defibrillator?", o: ["50 joules", "120-200 joules (manufacturer-specific); if unknown, use maximum available energy", "10 joules", "360 joules monophasic only"], a: 1, r: "Biphasic defibrillation for VFib: 120-200J (device-specific). If unknown → max energy. Monophasic: 360J. Biphasic is more effective at lower energy levels and causes less myocardial damage.", s: "Arrhythmias" },
  { q: "Why is defibrillation used for VFib but NOT for asystole?", o: ["Defibrillation works for all rhythms", "Defibrillation works by simultaneously depolarizing all myocardial cells to allow the SA node to resume control — asystole has no electrical activity to reset", "Asystole is not a real rhythm", "Both require defibrillation"], a: 1, r: "Defibrillation resets chaotic electrical activity. VFib has disorganized electrical activity that can be 'reset.' Asystole = no electrical activity = nothing to reset. Shocking asystole wastes time and provides no benefit.", s: "Arrhythmias" },
  { q: "What is the role of amiodarone in VFib management?", o: ["First-line treatment before defibrillation", "Given after the third defibrillation attempt (300 mg IV push) to stabilize the myocardium and improve response to subsequent defibrillation", "It replaces epinephrine", "Used only post-resuscitation"], a: 1, r: "Amiodarone for refractory VFib: 300 mg IV push after 3rd shock, 150 mg for persistent VFib. Mechanism: multiple channel blockade stabilizes the myocardium. Alternative: lidocaine 1-1.5 mg/kg. Neither replaces defibrillation.", s: "Arrhythmias" },
  { q: "A client is successfully resuscitated from VFib arrest. What post-resuscitation intervention improves neurological outcomes?", o: ["Immediate ambulation", "Targeted temperature management (TTM) — cooling to 32-36°C for 24 hours to reduce cerebral metabolic demand and minimize hypoxic brain injury", "Hot blankets", "Rapid rewarming"], a: 1, r: "TTM (32-36°C for 24 hours) reduces cerebral metabolic demand, decreases inflammatory cytokines, and limits reperfusion injury. Nursing: monitor temp closely, watch for shivering, manage electrolytes, hemodynamic support.", s: "Arrhythmias" },
  { q: "What are reversible causes of VFib that the nurse should help the team identify during a code (H's and T's)?", o: ["Only structural heart disease causes VFib", "Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia, Hypothermia; Tension pneumothorax, Tamponade, Toxins, Thrombosis (pulmonary/coronary)", "There are no reversible causes", "Only medication overdose"], a: 1, r: "H's and T's guide reversible cause identification during cardiac arrest. Treating the underlying cause improves ROSC chances. Common treatable causes: hyperkalemia (give calcium, insulin/dextrose), tension pneumo (needle decompression), PE.", s: "Arrhythmias" },
  { q: "During CPR for VFib, what is the correct compression-to-ventilation ratio for an intubated adult?", o: ["30:2 with pauses", "Continuous compressions at 100-120/min without pausing for ventilations; ventilate every 6 seconds (10 breaths/min) with an advanced airway in place", "15:2", "Compressions only, no ventilations"], a: 1, r: "With advanced airway (ET tube, supraglottic): continuous compressions (no pausing) at 100-120/min, depth 2-2.4 inches. Ventilations: 1 breath every 6 seconds (10/min). Without advanced airway: 30:2 ratio with pauses.", s: "Arrhythmias" },
  { q: "A nurse discovers a client in VFib on a cardiac monitor. The crash cart is not immediately available. What should the nurse do?", o: ["Wait for the crash cart", "Call for help and begin immediate high-quality chest compressions — do not delay CPR waiting for equipment. Compressions maintain some cardiac output until defibrillation is available", "Run to get the crash cart", "Give a precordial thump"], a: 1, r: "In witnessed arrest: call for help, begin CPR immediately. High-quality compressions generate ~25-30% of normal cardiac output, maintaining some perfusion to brain and heart until defibrillation. Every second without compressions reduces survival.", s: "Arrhythmias" },
  { q: "What is 'fine VFib' and how should it be managed?", o: ["Same as coarse VFib — shock immediately", "Fine VFib has low-amplitude waveforms that may resemble asystole. If uncertain, treat as VFib and defibrillate. CPR may convert fine VFib to coarse VFib (more amenable to defibrillation)", "It's not a real rhythm", "Only treat with medications"], a: 1, r: "Fine VFib: small amplitude fibrillatory waves. May be mistaken for asystole. Check in multiple leads. CPR with epinephrine may increase amplitude (→ coarse VFib) making it more responsive to defibrillation. When in doubt, defibrillate.", s: "Arrhythmias" },

  // ===== HEART BLOCKS SUPPLEMENTAL (10 questions) =====
  { q: "A client's ECG shows a constant PR interval of 0.24 seconds with all P waves followed by QRS complexes. What type of heart block is this?", o: ["No heart block", "First-degree AV block — PR interval >0.20 seconds but every P wave conducts. Usually benign and asymptomatic", "Second-degree Type I", "Third-degree heart block"], a: 1, r: "First-degree AV block: prolonged PR interval (>0.20 sec) but consistent 1:1 conduction (every P wave has a QRS). Usually benign, no treatment needed. Monitor for progression if new-onset, especially with medications that affect conduction.", s: "Arrhythmias" },
  { q: "How does a nurse differentiate Mobitz Type I (Wenckebach) from Mobitz Type II on ECG?", o: ["They look identical", "Type I shows progressive PR prolongation until a dropped QRS (grouped beating pattern). Type II has constant PR intervals with sudden unexpected dropped QRS complexes", "Type I has no P waves", "Type II has shortened PR intervals"], a: 1, r: "Type I (Wenckebach): progressive PR lengthening → dropped beat → cycle repeats (usually at AV node level, often benign). Type II: constant PR → sudden dropped QRS (below AV node, His-Purkinje level → higher risk of progressing to complete block).", s: "Arrhythmias" },
  { q: "A client with Mobitz Type II heart block has a ventricular rate of 38 bpm and is symptomatic (dizzy, confused). What is the definitive treatment?", o: ["Atropine will definitely work", "Permanent pacemaker — Mobitz Type II has a high risk of progressing to complete heart block. Atropine may not be effective because the block is below the AV node", "Only observation needed", "Digoxin to increase rate"], a: 1, r: "Mobitz II definitive treatment: permanent pacemaker. Atropine increases SA node firing and AV node conduction but has NO effect on infranodal blocks (Mobitz II occurs at His-Purkinje level). Use transcutaneous pacing as bridge.", s: "Arrhythmias" },
  { q: "What is the significance of a new bundle branch block (wide QRS) in a client presenting with chest pain?", o: ["Normal ECG variant", "New BBB with chest pain is a STEMI equivalent — treat as acute MI with emergent cardiac catheterization. Cannot evaluate ST changes when BBB is present", "Wait and monitor", "Only significant with left BBB"], a: 1, r: "New LBBB + chest pain = STEMI equivalent → activate cath lab. BBB masks ST-segment changes, making standard STEMI criteria unreliable. The Sgarbossa criteria may help identify MI in the presence of LBBB.", s: "Arrhythmias" },
  { q: "A nurse is caring for a client with a temporary transvenous pacemaker. What is the priority assessment?", o: ["Check skin integrity at insertion site only", "Verify capture (each pacemaker spike followed by a QRS complex) and sensing (pacer recognizes intrinsic rhythm and does not fire inappropriately) on the monitor", "Only monitor blood pressure", "No specific assessment needed"], a: 1, r: "Temporary pacer assessment: (1) Capture: spike → QRS? (2) Sensing: does pacer inhibit when intrinsic beats occur? (3) Rate/output settings appropriate? (4) Connections secure? (5) Insertion site for infection/bleeding. Immobilize extremity.", s: "Arrhythmias" },
  { q: "A client with a new permanent pacemaker asks about activity restrictions. What should the nurse teach?", o: ["No restrictions at all", "Avoid raising the arm on the pacemaker side above shoulder level for 4-6 weeks to prevent lead displacement. Avoid MRI unless the device is MRI-conditional. Carry pacemaker ID card", "Never exercise again", "Only avoid swimming"], a: 1, r: "Post-pacemaker teaching: (1) Limit arm movement 4-6 weeks (lead stabilization), (2) Avoid strong magnetic fields/MRI (unless MRI-conditional), (3) Cell phone on opposite ear, (4) Notify security at airports, (5) Regular device checks, (6) Monitor site for infection.", s: "Arrhythmias" },
  { q: "A client with third-degree (complete) heart block is given atropine 0.5 mg IV. The atrial rate increases but the ventricular rate remains unchanged. Why?", o: ["Atropine dose is too low", "In complete heart block, the atria and ventricles are electrically disconnected. Atropine increases the SA node rate (atrial rate) but cannot cross the blocked conduction system to affect ventricular rate", "Atropine takes longer to work", "The monitor is inaccurate"], a: 1, r: "Complete heart block: total AV dissociation. Atropine acts on the SA node and AV node but the block is complete — no amount of AV node stimulation overcomes it. The ventricles rely on an escape pacemaker below the block. Pacing is needed.", s: "Arrhythmias" },
  { q: "What type of escape rhythm does a client with complete heart block typically exhibit if the block is at the AV node level vs below the AV node?", o: ["Same escape rhythm regardless", "AV nodal block: junctional escape at 40-60 bpm with narrow QRS (more stable). Infranodal block: ventricular escape at 20-40 bpm with wide QRS (less stable, higher risk)", "Both produce wide QRS", "Neither produces escape rhythm"], a: 1, r: "Block location determines escape rhythm reliability. Junctional escape (40-60 bpm, narrow QRS): more reliable, hemodynamically better tolerated. Ventricular escape (20-40 bpm, wide QRS): less reliable, prone to asystole, more urgent pacing need.", s: "Arrhythmias" },
  { q: "Which medications can cause or worsen heart block and should be used cautiously?", o: ["Only beta-blockers", "Beta-blockers, calcium channel blockers (diltiazem, verapamil), digoxin, amiodarone, and adenosine — all slow conduction through the AV node", "Only antibiotics", "No medications affect conduction"], a: 1, r: "AV nodal blocking agents: beta-blockers, non-dihydropyridine CCBs (diltiazem, verapamil), digoxin, amiodarone. Check for conduction disease before starting. Hold and notify provider if new heart block develops.", s: "Arrhythmias" },
  { q: "A client's pacemaker is set to VVI mode. What does this mean?", o: ["It paces both chambers", "V = paces Ventricle, V = senses Ventricle, I = Inhibited by sensed ventricular activity (paces only when intrinsic ventricular rate falls below set rate)", "It defibrillates automatically", "It monitors without pacing"], a: 1, r: "Pacemaker codes: 1st letter = chamber paced, 2nd = chamber sensed, 3rd = response to sensing. VVI: paces ventricle, senses ventricle, inhibits when it sees intrinsic ventricular activity. DDD: dual pace, dual sense, dual response (most common for complete block).", s: "Arrhythmias" },

  // ===== SINUS BRADYCARDIA/TACHYCARDIA SUPPLEMENTAL (10 questions) =====
  { q: "A client has a heart rate of 48 bpm but denies dizziness, chest pain, or shortness of breath. Blood pressure is 118/72. What is the appropriate nursing action?", o: ["Immediate atropine", "Monitor and document — asymptomatic sinus bradycardia in a stable patient requires no intervention. Common in athletes and during sleep", "Call a code blue", "Apply transcutaneous pacing"], a: 1, r: "Asymptomatic sinus bradycardia: NO treatment needed. Common physiologic causes: athletic conditioning, sleep, high vagal tone. Only treat when symptomatic (hypotension, syncope, AMS, chest pain, HF symptoms).", s: "Arrhythmias" },
  { q: "A nurse administers atropine 0.5 mg IV for symptomatic bradycardia. The heart rate increases from 42 to 52 bpm but the client remains hypotensive. What is the next step?", o: ["Wait for atropine to work more", "Repeat atropine 0.5 mg IV every 3-5 minutes (max 3 mg) or initiate transcutaneous pacing if atropine is ineffective", "No further action needed", "Give another medication first"], a: 1, r: "Atropine for bradycardia: 0.5 mg IV, may repeat every 3-5 min, max 3 mg total. If ineffective or max dose reached: transcutaneous pacing, dopamine 5-20 mcg/kg/min, or epinephrine 2-10 mcg/min infusion.", s: "Arrhythmias" },
  { q: "What medication dose of atropine is considered potentially harmful in bradycardia management?", o: ["Any dose above 0.5 mg", "Doses less than 0.5 mg — paradoxical bradycardia can occur with low doses due to central vagal stimulation before peripheral muscarinic blockade", "Doses above 1 mg", "All doses are safe"], a: 1, r: "Atropine doses <0.5 mg can cause paradoxical bradycardia via central vagal stimulation. Always give minimum 0.5 mg. Maximum total dose 3 mg (complete vagal blockade). Space doses 3-5 minutes apart.", s: "Arrhythmias" },
  { q: "A client develops sinus tachycardia at 130 bpm after surgery. What should the nurse assess FIRST?", o: ["Give a beta-blocker immediately", "Assess for the UNDERLYING CAUSE — sinus tachycardia is a compensatory response, not a primary arrhythmia. Check for pain, hypovolemia, fever, anxiety, hemorrhage, PE, or infection", "Perform vagal maneuvers", "Administer adenosine"], a: 1, r: "Sinus tachycardia = symptom, not the disease. ALWAYS identify and treat the cause: pain (analgesics), hypovolemia (fluids), fever (antipyretics), anxiety (reassurance), PE (anticoagulation). Blocking the rate without treating the cause can be dangerous.", s: "Arrhythmias" },
  { q: "How does the nurse differentiate sinus tachycardia from SVT on the cardiac monitor?", o: ["They cannot be differentiated", "Sinus tachycardia: gradual onset/offset, rate usually <150 in adults, upright P waves in lead II. SVT: abrupt onset/offset, rate often >150, P waves absent or retrograde", "SVT is always slower", "Sinus tachycardia has no P waves"], a: 1, r: "Key differences: Sinus tach: P wave before each QRS, rate varies with activity/breathing, gradual acceleration. SVT: sudden onset (like a light switch), fixed rapid rate, P waves buried or absent. Adenosine can be both diagnostic and therapeutic.", s: "Arrhythmias" },
  { q: "A client on a beta-blocker develops symptomatic bradycardia (HR 38, BP 78/50, dizzy). Which reversal agent may be used?", o: ["Flumazenil", "Glucagon IV — bypasses beta receptors to stimulate cAMP production and increase heart rate and contractility", "Narcan", "Protamine"], a: 1, r: "Glucagon for beta-blocker-induced bradycardia: 3-10 mg IV bolus → infusion. Mechanism: activates adenylyl cyclase independent of beta receptors → increases cAMP → chronotropic and inotropic effect. Also use: atropine, pacing, epinephrine.", s: "Arrhythmias" },
  { q: "Sick sinus syndrome (SSS) is characterized by which ECG findings?", o: ["Only tachycardia", "Alternating periods of bradycardia and tachycardia (tachy-brady syndrome), sinus pauses, sinus arrest, and chronotropic incompetence", "Normal sinus rhythm only", "Only premature beats"], a: 1, r: "SSS (sinus node dysfunction): SA node fails to consistently generate impulses. Presents with: sinus bradycardia, sinus pauses (>3 sec), tachy-brady syndrome, chronotropic incompetence (inability to increase HR with activity). Treatment: pacemaker.", s: "Arrhythmias" },
  { q: "A nurse notes a sinus pause of 4 seconds on the telemetry monitor. The client is unresponsive. What is the immediate action?", o: ["Document and continue monitoring", "Stimulate the patient, call for help, prepare for transcutaneous pacing — sinus pause >3 seconds with loss of consciousness indicates hemodynamically significant pause requiring intervention", "Wait for the SA node to resume", "Give nitroglycerin"], a: 1, r: "Sinus pause >3 seconds: significant if symptomatic (syncope, near-syncope). Immediate: stimulate patient, start CPR if pulseless, transcutaneous pacing if available, atropine. Evaluate for pacemaker indication.", s: "Arrhythmias" },
  { q: "A client with hypothyroidism has persistent sinus bradycardia (HR 50-55). What is the appropriate treatment approach?", o: ["Permanent pacemaker", "Treat the underlying hypothyroidism with thyroid hormone replacement — the bradycardia should resolve as thyroid function normalizes", "Atropine standing order", "No treatment possible"], a: 1, r: "Hypothyroidism causes sinus bradycardia by decreasing SA node automaticity and cardiac output. Treatment: thyroid hormone replacement (levothyroxine). Heart rate should normalize over weeks as thyroid levels improve. Pacemaker only if bradycardia persists after euthyroid state achieved.", s: "Arrhythmias" },
  { q: "What does 'chronotropic incompetence' mean and how is it assessed?", o: ["Inability to lower heart rate", "Inability to appropriately increase heart rate in response to increased metabolic demand (exercise) — assessed by exercise stress testing showing failure to reach 80% of age-predicted maximum heart rate", "Rapid heart rate at rest", "Normal exercise response"], a: 1, r: "Chronotropic incompetence: HR fails to rise appropriately with activity → exercise intolerance, fatigue, dyspnea with exertion. Diagnosis: exercise stress test. Treatment: rate-responsive (DDDR) pacemaker that senses activity and increases pacing rate.", s: "Arrhythmias" },

  // ===== CHD OVERVIEW SUPPLEMENTAL (10 questions) =====
  { q: "How does fetal circulation differ from postnatal circulation regarding the ductus arteriosus?", o: ["No difference", "In fetal circulation, the ductus arteriosus shunts blood from the pulmonary artery to the aorta (bypassing the non-functioning lungs). After birth, rising O2 levels cause it to close, establishing separate pulmonary and systemic circuits", "The ductus carries blood to the liver", "It only functions after birth"], a: 1, r: "Fetal ductus arteriosus: R→L shunt (PA to aorta) bypassing fluid-filled lungs. Birth: oxygen exposure + decreased prostaglandins → functional closure (hours) → permanent closure (weeks). PGE1 keeps it open in ductal-dependent CHD.", s: "Pediatrics" },
  { q: "A nurse is caring for a neonate with a ductal-dependent lesion receiving PGE1 (alprostadil). What is the most common and dangerous side effect to monitor?", o: ["Hypertension", "Apnea — occurs in ~10-12% of neonates on PGE1, requiring intubation equipment at bedside at all times", "Hyperglycemia", "Polycythemia"], a: 1, r: "PGE1 side effects: apnea (10-12%, dose-related), fever, flushing, hypotension, bradycardia, seizures. CRITICAL: have intubation equipment at bedside. Do NOT stop PGE1 for apnea — the ductus must remain open. Intubate and continue PGE1.", s: "Pediatrics" },
  { q: "What is the difference between cyanotic and acyanotic congenital heart defects?", o: ["Cyanotic defects are always more severe", "Cyanotic defects have right-to-left shunting (deoxygenated blood enters systemic circulation → cyanosis). Acyanotic defects have left-to-right shunting (oxygenated blood recirculates through the lungs → volume overload)", "Acyanotic defects always cause cyanosis eventually", "There is no clinical difference"], a: 1, r: "Acyanotic (L→R shunt): VSD, ASD, PDA — increased pulmonary blood flow → volume overload → HF symptoms. Cyanotic (R→L shunt): TOF, TGA, truncus — deoxygenated blood enters systemic circulation → cyanosis, clubbing.", s: "Pediatrics" },
  { q: "A nurse notes that a newborn has a pulse oximetry reading of 88% on room air with no improvement on supplemental oxygen. What does this suggest?", o: ["Equipment malfunction", "Cyanotic congenital heart disease — cyanosis unresponsive to supplemental O2 (failed hyperoxia test) suggests a cardiac cause rather than pulmonary cause", "Pneumonia", "Normal neonatal transition"], a: 1, r: "Hyperoxia test: administer 100% O2. If PaO2 remains <100 mmHg or SpO2 doesn't improve, suggests fixed R→L cardiac shunt (cyanotic CHD). Pulmonary causes of cyanosis typically improve with O2. This distinction guides urgency of cardiac evaluation.", s: "Pediatrics" },
  { q: "What is Eisenmenger syndrome?", o: ["A type of congenital heart defect", "Irreversible pulmonary hypertension from long-standing left-to-right shunt that eventually causes shunt reversal (right-to-left), resulting in cyanosis. Surgical closure of the original defect is then CONTRAINDICATED", "A temporary condition", "Only occurs in adults"], a: 1, r: "Eisenmenger syndrome: progressive, irreversible process. Chronic increased pulmonary flow → pulmonary vascular remodeling → fixed pulmonary HTN → shunt reversal. Once R→L shunting occurs, closing the defect removes the RV pressure relief → RV failure.", s: "Pediatrics" },
  { q: "A nurse is performing CCHD (critical congenital heart disease) screening on a newborn. What does the screening involve?", o: ["Listening for a murmur only", "Pulse oximetry on the right hand (preductal) and either foot (postductal) after 24 hours of age — looking for SpO2 <95% or >3% difference between sites", "Blood tests only", "Chest X-ray"], a: 1, r: "CCHD screening: pulse oximetry ≥24 hours of age. Pass: both readings ≥95% AND ≤3% difference. Fail: either <90% (immediate fail) or 90-94% or >3% difference on 3 repeated screens. Identifies 7 critical CHD lesions before symptoms develop.", s: "Pediatrics" },
  { q: "What is the significance of a continuous 'machinery-like' murmur in a premature neonate?", o: ["Normal heart sound", "Patent ductus arteriosus (PDA) — continuous murmur from persistent L→R shunting through the open ductus. In premature infants, the ductus often fails to close spontaneously", "Ventricular septal defect", "Aortic stenosis"], a: 1, r: "PDA continuous murmur: blood flows L→R through the ductus during both systole and diastole (aortic pressure > PA pressure throughout). In preemies: ductus often doesn't close. Treatment: indomethacin/ibuprofen (prostaglandin inhibitors) or surgical ligation.", s: "Pediatrics" },
  { q: "Why is prostaglandin E1 (PGE1) considered a lifesaving medication in critical CHD?", o: ["It repairs the heart defect", "PGE1 maintains ductal patency, providing the ONLY pathway for blood mixing or flow to the lungs/body in ductal-dependent lesions until surgical correction can be performed", "It improves oxygenation directly", "It strengthens heart contractions"], a: 1, r: "Ductal-dependent lesions: some neonates need the PDA for survival (TGA for mixing, critical coarctation for lower body flow, critical pulmonic stenosis for pulmonary flow). PGE1 keeps the ductus open until definitive surgery.", s: "Pediatrics" },
  { q: "A child with repaired CHD needs dental work. When is SBE (subacute bacterial endocarditis) prophylaxis indicated?", o: ["All CHD patients forever", "Prophylaxis indicated for: unrepaired cyanotic CHD, repaired CHD with residual defects near prosthetic material, prosthetic valves, and first 6 months after repair with prosthetic material", "Never needed after repair", "Only for VSD"], a: 1, r: "AHA guidelines for SBE prophylaxis: prosthetic valves, prior endocarditis, unrepaired cyanotic CHD, repaired CHD with residual defects at prosthetic patch/device, cardiac transplant with valvulopathy. Prophylaxis NOT needed for most repaired defects without residual.", s: "Pediatrics" },
  { q: "What nutritional challenge is common in infants with hemodynamically significant CHD?", o: ["Obesity", "Failure to thrive — increased metabolic demand from heart failure combined with feeding difficulty (tachypnea, diaphoresis during feeds) results in inadequate caloric intake", "No nutritional issues", "Only iron deficiency"], a: 1, r: "CHD feeding challenges: (1) Increased metabolic demand (30-50% higher), (2) Feeding fatigue (tachypnea, diaphoresis), (3) Poor intake. Interventions: concentrated formula, frequent small feeds, NG supplementation, caloric fortification.", s: "Pediatrics" },

  // ===== TETRALOGY OF FALLOT SUPPLEMENTAL (10 questions) =====
  { q: "What are the four anatomical defects that comprise Tetralogy of Fallot?", o: ["ASD, VSD, PDA, coarctation", "Ventricular septal defect, right ventricular outflow tract obstruction (pulmonic stenosis), overriding aorta, and right ventricular hypertrophy", "Only VSD and pulmonic stenosis", "Three ASDs and one VSD"], a: 1, r: "TOF tetralogy: (1) VSD (allows mixing), (2) Pulmonic stenosis/RVOT obstruction (limits pulmonary flow), (3) Overriding aorta (straddles VSD, receives blood from both ventricles), (4) RVH (from chronic pressure overload). The pulmonic stenosis determines severity.", s: "Pediatrics" },
  { q: "During a tet spell, why is knee-chest positioning effective?", o: ["It calms the child", "Knee-chest positioning increases systemic vascular resistance (compresses femoral arteries), which decreases right-to-left shunting and forces more blood through the pulmonary valve into the lungs", "It improves breathing", "It reduces fever"], a: 1, r: "Tet spell physiology: RVOT spasm → decreased pulmonary flow → increased R→L shunt → cyanosis. Knee-chest increases SVR → increased aortic pressure → decreases R→L shunt gradient → more blood goes to lungs. Also reduces venous return.", s: "Pediatrics" },
  { q: "A nurse is caring for an infant with unrepaired TOF. The infant becomes increasingly cyanotic and irritable during crying. What intervention is MOST important?", o: ["Allow the infant to cry it out", "Calm the infant immediately — crying increases metabolic demand and can trigger a tet spell. Place knee-to-chest, administer O2, and have morphine available", "Give the infant a bottle", "Check blood glucose"], a: 1, r: "Crying/agitation → increased O2 demand → increased R→L shunting → cyanosis spiral. Immediate interventions: calm infant (quiet environment), knee-chest positioning, O2, morphine (reduces RVOT spasm), IV fluids (increase preload). Prevent future episodes.", s: "Pediatrics" },
  { q: "What is the 'boot-shaped heart' seen on chest X-ray in TOF?", o: ["Normal neonatal finding", "The upturned apex from right ventricular hypertrophy combined with a concave pulmonary artery segment creates a characteristic boot (coeur en sabot) silhouette on CXR", "Pericardial effusion", "Cardiomegaly from left heart failure"], a: 1, r: "TOF CXR: (1) Boot-shaped heart from RVH lifting the apex, (2) Concave main PA segment (small PA from decreased flow), (3) Decreased pulmonary vascularity (oligemic lung fields). This triad is characteristic.", s: "Pediatrics" },
  { q: "What is the purpose of a Blalock-Taussig (BT) shunt in TOF management?", o: ["It repairs the VSD", "It creates a temporary systemic-to-pulmonary artery connection to increase pulmonary blood flow until the child is ready for complete surgical repair", "It closes the ductus", "It replaces the aortic valve"], a: 1, r: "Modified BT shunt: Gore-Tex graft from subclavian artery to pulmonary artery → increases pulmonary blood flow → improves oxygenation. Palliative procedure for symptomatic infants too small/sick for complete repair. Complete repair done later.", s: "Pediatrics" },
  { q: "What surgical intervention provides definitive repair for TOF?", o: ["Heart transplant", "Complete intracardiac repair: VSD patch closure + RVOT obstruction relief (muscle resection, pulmonary valvotomy, or transannular patch) — typically performed between 3-6 months of age", "BT shunt only", "Medication management"], a: 1, r: "Complete TOF repair: (1) Close VSD with patch, (2) Relieve RVOT obstruction. Timing: 3-6 months (earlier if symptomatic). Operative mortality <3% at experienced centers. Long-term issues: pulmonary regurgitation, arrhythmias, RV dysfunction.", s: "Pediatrics" },
  { q: "What is the most important long-term complication after TOF repair that the nurse should monitor for?", o: ["No long-term complications", "Pulmonary regurgitation (PR) from RVOT reconstruction → progressive RV dilation and dysfunction → may require pulmonary valve replacement years or decades after initial repair", "Mitral stenosis", "Renal failure"], a: 1, r: "Chronic PR is the hallmark long-term issue: RVOT surgery often causes progressive PI → RV volume overload → RV dilation → RV dysfunction → exercise intolerance, arrhythmias. Pulmonary valve replacement when RV reaches critical dilation threshold.", s: "Pediatrics" },
  { q: "An infant with TOF has a hemoglobin of 21 g/dL. Why is polycythemia expected, and when does it become dangerous?", o: ["This is normal and never dangerous", "Chronic hypoxemia stimulates erythropoietin production → polycythemia (compensatory). Becomes dangerous when hematocrit >65% due to hyperviscosity → stroke, thrombosis risk", "Low hemoglobin is expected", "Polycythemia only occurs in adults"], a: 1, r: "Compensatory polycythemia: chronic cyanosis → increased EPO → more RBCs → improved O2 carrying capacity. But hematocrit >65% = hyperviscosity → thrombosis risk (stroke, DVT). Maintain hydration, avoid dehydration, possible phlebotomy.", s: "Pediatrics" },
  { q: "What medications are used during a tet spell if positioning and calming are ineffective?", o: ["Only oxygen", "Morphine sulfate (reduces RVOT spasm), phenylephrine (increases SVR), IV fluids (increase preload), and supplemental O2. Beta-blockers (propranolol) may be used for recurrent spells", "Digoxin and diuretics", "Adenosine"], a: 1, r: "Tet spell escalation: (1) Knee-chest + calm, (2) O2, (3) Morphine 0.1 mg/kg SQ/IM (relaxes RVOT), (4) IVF bolus (increase preload), (5) Phenylephrine (increase SVR), (6) Propranolol for prevention. If refractory → emergent surgery.", s: "Pediatrics" },
  { q: "A parent asks why their infant with TOF 'squats' during play. What does the nurse explain?", o: ["It's a normal behavior", "Squatting is a self-learned compensatory mechanism — like knee-chest positioning, it increases systemic vascular resistance and decreases right-to-left shunting, improving oxygenation", "The child has leg weakness", "It indicates pain"], a: 1, r: "Squatting = instinctive knee-chest positioning. Older children with unrepaired TOF learn to squat during exertion. It increases SVR (decreases R→L shunt) and decreases venous return (decreases RVOT obstruction). A classic TOF behavioral adaptation.", s: "Pediatrics" },

  // ===== SEPTAL DEFECTS SUPPLEMENTAL (10 questions) =====
  { q: "What type of murmur is associated with a VSD?", o: ["Diastolic murmur", "Harsh holosystolic (pansystolic) murmur best heard at the left lower sternal border — caused by blood flowing from the higher-pressure LV to the lower-pressure RV throughout systole", "Continuous machinery murmur", "No murmur"], a: 1, r: "VSD murmur: harsh holosystolic at LLSB ± thrill. Loudness correlates inversely with size (small restrictive VSD = loud murmur from high-velocity jet; large nonrestrictive VSD = softer murmur from equalized pressures).", s: "Pediatrics" },
  { q: "What percentage of small VSDs close spontaneously?", o: ["None close spontaneously", "Up to 70-80% of small muscular VSDs close spontaneously by age 2-3 years — watchful waiting with regular follow-up is appropriate for small, hemodynamically insignificant VSDs", "100% close", "Only 5%"], a: 1, r: "Small muscular VSDs: 70-80% spontaneous closure rate (muscular septum grows and seals the defect). Perimembranous VSDs: lower closure rate (~35%). Large VSDs: rarely close spontaneously, usually need surgical repair.", s: "Pediatrics" },
  { q: "A child with ASD has a fixed split S2. What does this indicate hemodynamically?", o: ["Nothing significant", "Constant volume overload of the RV from the L→R shunt prevents normal respiratory variation in S2 splitting — the RV always takes longer to empty, keeping the pulmonic valve closure delayed", "Pulmonary hypertension", "Mitral valve prolapse"], a: 1, r: "Fixed split S2 pathophysiology: ASD equalizes atrial pressures → constant extra volume to RV regardless of respiratory phase → pulmonic valve closure consistently delayed. This is PATHOGNOMONIC for ASD (no other condition produces fixed splitting).", s: "Pediatrics" },
  { q: "What are the surgical options for ASD closure?", o: ["Only open-heart surgery", "Transcatheter device closure (Amplatzer) for secundum ASDs with adequate rims, OR open surgical patch closure for primum, sinus venosus, or large secundum ASDs", "Medication management only", "No treatment exists"], a: 1, r: "ASD closure options: (1) Transcatheter device (Amplatzer): secundum ASDs with adequate rims, minimally invasive, 1-2 day stay. (2) Surgical: sternotomy with CPB, direct or patch closure. Required for primum, sinus venosus types, or inadequate rims.", s: "Pediatrics" },
  { q: "Why is an ASD sometimes left unrepaired in elderly patients?", o: ["All ASDs must be repaired", "In elderly patients with long-standing ASD, the RV may be dependent on the volume load. Closing it could cause acute RV failure. Also, surgical risks increase with age and comorbidities", "ASDs don't cause problems in elderly", "Elderly can't have surgery"], a: 1, r: "Decision factors in elderly: (1) RV adaptation to chronic volume overload (sudden unloading risky), (2) Fixed pulmonary HTN (Eisenmenger), (3) Surgical risk vs benefit, (4) Quality of life. Careful hemodynamic assessment needed before closure.", s: "Pediatrics" },
  { q: "What is the nursing priority for a child with a large VSD who is in heart failure?", o: ["Restrict all fluids", "Optimize nutritional intake to support growth while managing heart failure — concentrate formula to 24-27 cal/oz, small frequent feeds, cluster cares to minimize energy expenditure", "Force large-volume feeds", "Only administer IV fluids"], a: 1, r: "VSD with HF nursing priorities: (1) Caloric optimization (concentrated formula, 24-27 cal/oz), (2) Small frequent feeds (reduce energy expenditure), (3) Cluster care (minimize disruption), (4) Monitor I&O/daily weights, (5) Administer digoxin/diuretics as ordered.", s: "Pediatrics" },
  { q: "What is the difference between an ostium primum and ostium secundum ASD?", o: ["No difference", "Primum ASD is lower in the septum near the AV valves (often associated with mitral cleft and AV canal defects). Secundum ASD is in the central fossa ovalis region and is more common and amenable to device closure", "Secundum is lower", "Primum is more common"], a: 1, r: "Secundum ASD: most common (70%), center of septum at fossa ovalis, usually isolated, device closure candidate. Primum ASD: lower septum, associated with AV canal/mitral cleft, part of Down syndrome spectrum, requires surgical repair.", s: "Pediatrics" },
  { q: "What chromosomal abnormality is MOST strongly associated with AV canal defects (endocardial cushion defects)?", o: ["Turner syndrome", "Down syndrome (trisomy 21) — 40-50% of children with Down syndrome have CHD, and AV canal defect is the most common type", "Klinefelter syndrome", "Edwards syndrome"], a: 1, r: "Down syndrome + CHD: ~40-50% incidence. Complete AV canal (AVSD) is the most common CHD in Down syndrome. All neonates with Down syndrome should have an echocardiogram regardless of symptoms. Surgical repair timing: 3-6 months.", s: "Pediatrics" },
  { q: "A child with VSD develops recurrent pneumonia. What is the connection?", o: ["VSD doesn't affect the lungs", "L→R shunting causes increased pulmonary blood flow → pulmonary vascular congestion → increased susceptibility to respiratory infections — recurrent pneumonia may indicate hemodynamically significant VSD", "Coincidental finding", "Only occurs with ASD"], a: 1, r: "Increased pulmonary blood flow from L→R shunt → pulmonary congestion → impaired mucociliary clearance → increased susceptibility to lower respiratory tract infections. Recurrent pneumonia in an infant should prompt cardiac evaluation.", s: "Pediatrics" },
  { q: "Post-VSD repair, what is the most serious immediate complication to monitor for?", o: ["Wound infection", "Complete heart block — the AV node and bundle of His course along the posteroinferior rim of membranous VSDs, and surgical patch placement can damage the conduction system", "Pneumonia", "Allergic reaction"], a: 1, r: "Post-VSD repair monitoring: (1) Complete heart block (1-2%): monitor telemetry continuously, temporary pacing wires in place. (2) Residual VSD (small leak around patch). (3) Hemodynamic instability. (4) Pericardial effusion/tamponade.", s: "Pediatrics" },

  // ===== COARCTATION OF THE AORTA SUPPLEMENTAL (10 questions) =====
  { q: "What is the hallmark physical finding that differentiates coarctation from other causes of neonatal shock?", o: ["Equal pulses throughout", "Differential upper and lower extremity pulses and blood pressures — bounding upper extremity pulses with weak or absent femoral pulses and >20 mmHg systolic gradient", "Abdominal distension", "Fever and rash"], a: 1, r: "Coarctation triad: (1) Upper extremity HTN with bounding pulses, (2) Lower extremity hypotension with weak/absent femoral pulses, (3) >20 mmHg arm-leg systolic gradient. EVERY newborn exam should include femoral pulse check.", s: "Pediatrics" },
  { q: "A neonate with critical coarctation receives PGE1. The femoral pulses improve and acidosis resolves. What is the next step?", o: ["Discharge home on PGE1", "Echocardiographic confirmation of the lesion and surgical planning — PGE1 stabilizes the patient by reopening the ductus, buying time for definitive surgical repair", "Stop PGE1 since the patient improved", "MRI of the brain"], a: 1, r: "PGE1 stabilization → echo confirmation → surgical planning. Continue PGE1 until surgery. Options: primary surgical repair (resection with end-to-end anastomosis) in neonates, or balloon angioplasty/stenting in older children.", s: "Pediatrics" },
  { q: "What surgical technique is most commonly used for coarctation repair in neonates?", o: ["Heart transplant", "Resection with extended end-to-end anastomosis — removing the coarctation segment and directly connecting the healthy aortic ends, performed through a left thoracotomy", "Balloon valvuloplasty", "Stent placement"], a: 1, r: "Neonatal coarctation repair: resection with end-to-end or extended end-to-end anastomosis (preferred). Other options: subclavian flap aortoplasty, patch aortoplasty. Left thoracotomy approach (no CPB needed). Transcatheter approaches reserved for older children.", s: "Pediatrics" },
  { q: "What is the recoarctation rate after neonatal repair, and how is it detected?", o: ["Recoarctation never occurs", "Recoarctation occurs in 5-10% of neonates, detected by recurrence of arm-leg BP gradient, diminished femoral pulses, or hypertension — often treated with balloon angioplasty", "50% recoarctation rate", "Only detectable by MRI"], a: 1, r: "Recoarctation: 5-10% in neonates (higher than in older children). Detection: arm-leg BP gradient, diminished femoral pulses, HTN. Treatment: balloon angioplasty ± stent (preferred over redo surgery). Lifelong surveillance required.", s: "Pediatrics" },
  { q: "Why is coarctation associated with bicuspid aortic valve?", o: ["No association", "Both are left-sided obstructive lesions that share embryological origins — up to 50-85% of coarctation patients have bicuspid aortic valve, requiring lifelong valve surveillance", "Right-sided heart defect", "Acquired association only"], a: 1, r: "Coarctation + BAV: same embryological origin (neural crest cell abnormalities affecting left-sided structures). Clinical implication: ALL coarctation patients need aortic valve assessment. BAV may need future replacement for stenosis/regurgitation.", s: "Pediatrics" },
  { q: "A nurse is discharging a child after coarctation repair. What ESSENTIAL teaching points should be included?", o: ["No special follow-up needed", "Lifelong BP monitoring (risk of late HTN), activity restrictions for 6-8 weeks, signs of recoarctation (arm-leg BP difference, headaches, leg pain), SBE prophylaxis per guidelines, and regular cardiology follow-up", "Only wound care", "Return to full activity immediately"], a: 1, r: "Post-repair discharge teaching: (1) Lifelong cardiology follow-up, (2) BP monitoring (late HTN in 30%), (3) Activity restrictions during healing, (4) Recognize recoarctation signs, (5) SBE prophylaxis if indicated, (6) Avoid isometric exercise long-term.", s: "Pediatrics" },
  { q: "What is post-coarctectomy syndrome and when does it occur?", o: ["Immediate post-operative pain", "Paradoxical hypertension with abdominal pain occurring 2-3 days post-repair from sudden increase in mesenteric blood flow causing mesenteric arteritis", "Infection at the repair site", "Late recoarctation"], a: 1, r: "Post-coarctectomy syndrome: mesenteric arteries suddenly exposed to pulsatile flow → arteritis → abdominal pain, nausea, ileus, hypertension. Timing: days 2-5 post-op. Treatment: antihypertensives, bowel rest, pain management. Usually self-limiting.", s: "Pediatrics" },
  { q: "A 12-year-old with undiagnosed coarctation presents with persistent headaches and nosebleeds. Physical exam reveals upper body HTN and weak femorals. What diagnostic study confirms the diagnosis?", o: ["Blood tests only", "Echocardiography showing the discrete narrowing with Doppler gradient, followed by CT angiography or MRA for precise anatomical delineation before intervention", "Only auscultation", "Pulse oximetry"], a: 1, r: "Diagnostic workup: (1) Echo with Doppler (initial, shows gradient), (2) CT angiography or MRA (anatomic detail, collateral mapping, planning intervention), (3) Cardiac catheterization (therapeutic — balloon/stent, or hemodynamic assessment).", s: "Pediatrics" },
  { q: "Why do some adults with unrepaired coarctation develop berry aneurysms in the brain?", o: ["No association", "Chronic upper body hypertension damages cerebral vasculature — berry aneurysms at the circle of Willis occur more frequently, with risk of subarachnoid hemorrhage", "Aneurysms are congenital only", "Lower body HTN causes this"], a: 1, r: "Coarctation → chronic upper body HTN → accelerated cerebrovascular disease → higher incidence of berry aneurysms at circle of Willis → risk of SAH. This is a major cause of morbidity/mortality in unrepaired coarctation adults.", s: "Pediatrics" },
  { q: "A neonate with coarctation also has a VSD. How does this combination affect the presentation?", o: ["The VSD protects against problems", "The combination worsens heart failure — the VSD adds volume overload to the already pressure-overloaded LV. These neonates present earlier with more severe HF and may need combined surgical repair", "No interaction between defects", "The VSD makes the coarctation less severe"], a: 1, r: "Coarctation + VSD: worse outcome than either alone. VSD → volume overload + coarctation → pressure overload = rapid HF. May need combined repair or staged approach. Earlier presentation, more symptomatic, often need intervention in first weeks.", s: "Pediatrics" },

  // ===== ANTICOAGULATION THERAPY SUPPLEMENTAL (10 questions) =====
  { q: "A nurse is starting a heparin infusion. What baseline labs must be obtained BEFORE initiating therapy?", o: ["Only CBC", "aPTT (baseline for monitoring), PT/INR (baseline coagulation), CBC with platelets (baseline for HIT monitoring), and BMP (renal function for dosing considerations)", "No labs needed", "Only blood type"], a: 1, r: "Pre-heparin labs: aPTT (monitoring baseline), PT/INR (overall coagulation), CBC with platelets (HIT baseline — recheck in 4-6 hours, then every 2-3 days), BMP (renal function). Document baseline for comparison.", s: "Pharmacology" },
  { q: "What is the therapeutic aPTT range for a standard heparin infusion?", o: ["20-30 seconds", "1.5-2.5 times the control value (typically 60-80 seconds) — check aPTT 6 hours after initiation or rate change", "Over 120 seconds", "Under 25 seconds"], a: 1, r: "Therapeutic aPTT: 1.5-2.5× control (varies by institution's reagent). Check 6 hours after start or any rate change. Below range: increase rate per protocol. Above range: hold/decrease per protocol. Supratherapeutic + bleeding = hold + consider protamine.", s: "Pharmacology" },
  { q: "A client on warfarin eats a large salad with kale, spinach, and broccoli for the first time. What should the nurse teach about diet and warfarin?", o: ["Avoid all green vegetables", "Maintain CONSISTENT daily vitamin K intake rather than avoiding vitamin K foods — sudden increases in vitamin K decrease INR, sudden decreases increase INR and bleeding risk", "Eat as much vitamin K as desired", "Diet has no effect on warfarin"], a: 1, r: "Warfarin + vitamin K: consistency is key, not avoidance. Patients can eat vitamin K foods (leafy greens) but must maintain consistent intake. Sudden changes in diet alter INR unpredictably. Educate about high vitamin K sources.", s: "Pharmacology" },
  { q: "What is the mechanism of action difference between UFH and LMWH?", o: ["They work identically", "UFH inhibits both thrombin (IIa) and factor Xa equally. LMWH primarily inhibits factor Xa with less anti-IIa activity, providing more predictable dosing and less monitoring requirement", "LMWH works faster", "UFH only affects platelets"], a: 1, r: "UFH: binds antithrombin III → inhibits thrombin (IIa) + Xa equally. Requires aPTT monitoring, IV/SQ. LMWH: shorter chains primarily inhibit Xa (anti-Xa:anti-IIa ratio of 4:1). Predictable kinetics, SQ dosing, usually no monitoring needed.", s: "Pharmacology" },
  { q: "A client is transitioning from heparin to warfarin ('bridging'). Why must both be given simultaneously for several days?", o: ["One is for day, one for night", "Warfarin takes 3-5 days to reach therapeutic effect (waiting for existing clotting factors to be depleted). Heparin provides immediate anticoagulation during this lag period. Overlap until INR is therapeutic (2-3) for 24 hours", "Insurance requires both", "They work on different clots"], a: 1, r: "Bridge therapy: heparin provides immediate anticoagulation while waiting for warfarin's full effect. Warfarin blocks new factor synthesis, but existing factors must decay (factor II half-life ~60 hrs). Overlap minimum 4-5 days AND INR therapeutic for ≥24 hrs.", s: "Pharmacology" },
  { q: "What are the advantages of DOACs (apixaban, rivaroxaban) over warfarin?", o: ["No advantages", "Fixed dosing without routine monitoring, fewer drug-food interactions, rapid onset/offset, predictable pharmacokinetics, and lower intracranial hemorrhage risk", "They are cheaper", "They work faster than heparin"], a: 1, r: "DOAC advantages: no routine INR monitoring, fixed dosing, fewer interactions (no vitamin K concern), rapid onset (2-4 hrs vs 3-5 days), shorter half-life (easier periprocedural management). Limitations: specific reversal agents needed, renal clearance concerns.", s: "Pharmacology" },
  { q: "A client on apixaban needs emergency surgery in 2 hours. What is the reversal strategy?", o: ["Wait for the drug to wear off", "Administer andexanet alfa (specific reversal agent for factor Xa inhibitors) or use 4-factor PCC (prothrombin complex concentrate) if andexanet is unavailable", "Give vitamin K", "Give protamine"], a: 1, r: "Apixaban/rivaroxaban reversal: andexanet alfa (specific Xa inhibitor reversal agent). Alternative: 4-factor PCC. Vitamin K is ineffective (DOACs don't affect vitamin K cycle). Protamine reverses heparin only. Charcoal if ingestion <2 hours.", s: "Pharmacology" },
  { q: "A nurse notices a new order for enoxaparin in a client with a creatinine clearance of 15 mL/min. What concern should the nurse raise?", o: ["No concern", "LMWH is renally cleared and accumulates in severe renal impairment (CrCl <30 mL/min), dramatically increasing bleeding risk. IV UFH is preferred for anticoagulation in severe renal failure", "Increase the dose", "Switch to warfarin immediately"], a: 1, r: "LMWH contraindication: CrCl <30 mL/min (accumulation → unpredictable anticoagulation → bleeding). Use UFH instead (reticuloendothelial clearance). If LMWH must be used: reduce dose, monitor anti-Xa levels. Always check renal function before LMWH.", s: "Pharmacology" },
  { q: "What are the signs and symptoms of heparin-induced thrombocytopenia (HIT) Type II?", o: ["Only minor bruising", "Platelet count drop >50% from baseline occurring 5-10 days after heparin initiation (or sooner with prior exposure), often paradoxically accompanied by thrombosis rather than bleeding", "Immediate allergic reaction", "Only occurs with IV heparin"], a: 1, r: "HIT Type II: immune-mediated (PF4-heparin complex antibodies). Timing: 5-10 days (or <1 day with prior exposure). Paradox: thrombocytopenia with THROMBOSIS (not bleeding). Any heparin exposure (flushes, coated lines) can trigger. 4T score assesses probability.", s: "Pharmacology" },
  { q: "A client's INR is 8.5 with minor gum bleeding. What is the appropriate intervention?", o: ["Give FFP immediately", "Hold warfarin, administer oral vitamin K 2.5-5 mg, recheck INR in 12-24 hours. Oral vitamin K is preferred for elevated INR with minor bleeding. IV vitamin K reserved for serious bleeding", "Resume warfarin at lower dose", "No intervention needed"], a: 1, r: "INR 8.5 + minor bleeding: hold warfarin + oral vitamin K 2.5-5 mg. Oral preferred (lower anaphylaxis risk than IV). INR should decrease within 12-24 hours. If major/life-threatening bleeding: IV vitamin K + 4-factor PCC or FFP.", s: "Pharmacology" },

  // ===== BLEEDING RISKS & REVERSAL SUPPLEMENTAL (10 questions) =====
  { q: "A client on heparin develops active bleeding. What is the specific reversal agent and how is the dose calculated?", o: ["Vitamin K", "Protamine sulfate — 1 mg protamine reverses approximately 100 units of heparin. Calculate based on the amount of heparin given in the last 2-3 hours", "Andexanet alfa", "Fresh frozen plasma"], a: 1, r: "Protamine reversal of heparin: 1 mg per 100 units heparin (last dose within 30 min: full dose; 30-60 min: 0.5 mg/100 units; >60 min: 0.25 mg/100 units). Max 50 mg. Give slowly (over 10 min) — rapid infusion causes hypotension, bradycardia, anaphylaxis.", s: "Pharmacology" },
  { q: "What is the reversal agent for dabigatran (Pradaxa)?", o: ["Vitamin K", "Idarucizumab (Praxbind) — a monoclonal antibody fragment that specifically binds dabigatran, neutralizing its anticoagulant effect within minutes", "Protamine sulfate", "Andexanet alfa"], a: 1, r: "Idarucizumab: specific dabigatran reversal agent. 5 g IV (two 2.5 g doses, max 15 min apart). Onset: immediate. Does not affect other anticoagulants. Also: hemodialysis can remove dabigatran (small molecule, low protein binding).", s: "Pharmacology" },
  { q: "A nurse is implementing bleeding precautions for a client with INR of 4.2. What specific interventions should be included?", o: ["No special precautions", "Use soft toothbrush, electric razor, avoid IM injections, apply prolonged pressure to venipuncture sites, avoid rectal temperatures, use stool softeners, fall prevention measures, no aspirin/NSAIDs", "Only avoid aspirin", "Only use a soft toothbrush"], a: 1, r: "Bleeding precautions: soft toothbrush, electric razor, no IM/rectal procedures, prolonged pressure on sites (5+ min), pad bed rails, stool softeners (prevent straining), no aspirin/NSAIDs, guaiac stools, monitor H&H, fall prevention.", s: "Pharmacology" },
  { q: "What is the maximum rate of protamine sulfate administration, and why is it important?", o: ["Give as fast as possible", "No faster than 5 mg/min (50 mg over 10 minutes) — rapid administration causes severe hypotension, bradycardia, and anaphylactoid reactions, especially in patients with fish allergies", "100 mg/min is safe", "Only give orally"], a: 1, r: "Protamine: max 5 mg/min. Rapid infusion → hypotension, bradycardia, pulmonary HTN, anaphylaxis. Higher risk: fish allergy (protamine derived from salmon sperm), prior protamine/NPH insulin exposure. Have resuscitation equipment available.", s: "Pharmacology" },
  { q: "A client on warfarin has an INR of 12.5 with active hematuria and large ecchymoses but stable vital signs. What is the MOST appropriate management?", o: ["Oral vitamin K only", "Hold warfarin, IV vitamin K 10 mg, AND 4-factor PCC (prothrombin complex concentrate) for immediate factor replacement — the combination provides rapid reversal for significant bleeding", "FFP alone", "Just hold warfarin"], a: 1, r: "INR >10 with active bleeding: hold warfarin + IV vitamin K (10 mg slow infusion) + 4-factor PCC (preferred over FFP: faster correction, less volume). PCC provides immediate factor replacement while vitamin K works over 12-24 hours.", s: "Pharmacology" },
  { q: "Why is 4-factor PCC preferred over FFP for urgent warfarin reversal?", o: ["It's cheaper", "PCC provides concentrated clotting factors (II, VII, IX, X) in a small volume with rapid correction (15-30 min) vs FFP which requires larger volumes, longer infusion, type-matching, and thawing time", "No difference between them", "FFP is always preferred"], a: 1, r: "4-factor PCC advantages: concentrated factors (small volume ~100 mL vs FFP 600-1500 mL), rapid administration, no thawing/type needed, faster INR correction. FFP: larger volume load (risk of TACO in HF), requires thawing (30-45 min delay), ABO matching.", s: "Pharmacology" },
  { q: "A post-surgical client is on prophylactic enoxaparin. The nurse notes a new platelet count of 88K (baseline 245K). The HIT probability should be assessed using which scoring tool?", o: ["CHADS2-VASc", "4T score — evaluates Thrombocytopenia severity, Timing of onset, Thrombosis presence, and oTher causes excluded", "Wells score", "NIHSS"], a: 1, r: "4T score for HIT: (1) Thrombocytopenia (% fall and nadir), (2) Timing (days 5-10 or recent heparin), (3) Thrombosis (new thrombosis or skin necrosis), (4) Other causes (excluded?). Score 0-3: low probability, 4-5: intermediate, 6-8: high.", s: "Pharmacology" },
  { q: "What nursing assessments should be performed at LEAST every shift for a client on anticoagulation therapy?", o: ["Only check lab values", "Neurological status (headache, confusion = intracranial bleed), abdominal assessment (guarding = GI/retroperitoneal bleed), skin (new petechiae, ecchymoses), urine/stool color, vital signs, and venipuncture sites", "Only vital signs", "Only skin assessment"], a: 1, r: "Anticoagulation assessment: neuro checks (ICH is most dangerous), abdominal (GI/retroperitoneal bleed), skin (petechiae, ecchymoses), urine (hematuria), stool (melena, guaiac), gums (bleeding), VS (tachycardia, hypotension), H&H trends.", s: "Pharmacology" },
  { q: "A client on therapeutic anticoagulation falls and hits their head. They currently have no neurological symptoms. What is the priority action?", o: ["Reassure and continue monitoring", "Obtain STAT CT head — anticoagulated patients are at high risk for delayed intracranial hemorrhage that may not present with symptoms initially. Serial neuro checks and repeat imaging in 6-24 hours", "Apply ice to the head", "Give reversal agent immediately"], a: 1, r: "Anticoagulated patient + head injury = high ICH risk even if initially asymptomatic. STAT CT, serial neuro checks q1h × 24h, consider repeat CT at 6-24h. Low threshold for reversal if any neuro change. Delayed bleed is a known risk.", s: "Pharmacology" },
  { q: "A client with a mechanical heart valve is on lifelong warfarin. They need an elective knee replacement. How is anticoagulation managed perioperatively?", o: ["Stop warfarin and proceed with surgery", "Bridge therapy: stop warfarin 5 days pre-op, start therapeutic heparin/LMWH bridging when INR falls below therapeutic, hold heparin day of surgery, resume postoperatively when safe", "Continue warfarin through surgery", "Switch to aspirin only"], a: 1, r: "Mechanical valve = high thrombotic risk → bridging required. Timeline: stop warfarin 5 days pre-op, bridge with therapeutic heparin/LMWH, hold bridge 12-24h pre-op, resume 12-24h post-op when hemostasis confirmed. Restart warfarin ASAP.", s: "Pharmacology" },

  // ===== DIC SUPPLEMENTAL (5 questions) =====
  { q: "What is the ISTH scoring system for diagnosing DIC?", o: ["A genetic test", "International Society on Thrombosis and Haemostasis scoring system: assigns points for platelet count, D-dimer, prolonged PT, and fibrinogen level. Score ≥5 = overt DIC", "An imaging study", "Only a clinical diagnosis"], a: 1, r: "ISTH DIC score: platelet count (0-2 points), D-dimer (0-3 points), prolonged PT (0-2 points), fibrinogen level (0-1 point). Score ≥5: overt DIC compatible. Score <5: suggestive, not affirmative — repeat in 1-2 days. Serial scoring tracks progression.", s: "Pharmacology" },
  { q: "What is the role of antithrombin III (AT III) in DIC, and why might AT III concentrate be considered?", o: ["AT III is not relevant to DIC", "AT III is a natural anticoagulant depleted in DIC by consumption. AT III concentrate may restore the ability of heparin to work (heparin requires AT III as cofactor) in cases of severe AT III depletion", "AT III causes DIC", "AT III replaces platelets"], a: 1, r: "AT III in DIC: consumed by the coagulation cascade → depletion → heparin becomes ineffective (heparin needs AT III to inhibit thrombin/Xa). AT III concentrate may restore heparin efficacy in severe DIC with AT III levels <50%. Evidence is mixed.", s: "Pharmacology" },
  { q: "A nurse receives a trauma client with massive hemorrhage developing signs of DIC. What is the priority blood product resuscitation strategy?", o: ["Give packed RBCs only", "Massive transfusion protocol (MTP): balanced 1:1:1 ratio of pRBCs:FFP:platelets to replace all blood components simultaneously and prevent dilutional coagulopathy", "Give FFP only", "Give crystalloid only"], a: 1, r: "Trauma-associated DIC: activate MTP with 1:1:1 ratio (pRBC:FFP:platelet). Balanced resuscitation prevents dilutional coagulopathy. Also: tranexamic acid within 3 hours, calcium replacement (citrate toxicity), warm all products.", s: "Pharmacology" },
  { q: "Why are schistocytes (fragmented red blood cells) present on the peripheral smear in DIC?", o: ["From medication side effects", "RBCs are sheared as they pass through partially occluded microvasculature — fibrin strands deposited in small vessels act like cheese wire, fragmenting the red blood cells", "From dehydration", "Normal finding in critically ill"], a: 1, r: "Schistocyte formation: fibrin strands deposited in microvasculature during DIC → mechanical shearing of RBCs as they pass through → fragmented cells (schistocytes, helmet cells). Also seen in TTP/HUS. Contributes to microangiopathic hemolytic anemia (MAHA).", s: "Pharmacology" },
  { q: "A client with gram-negative sepsis develops DIC. What specific component of the bacteria triggers the coagulation cascade?", o: ["Flagella", "Endotoxin (lipopolysaccharide/LPS) from the gram-negative bacterial cell wall activates tissue factor expression on monocytes and endothelial cells, triggering widespread coagulation", "Capsule proteins", "Pili"], a: 1, r: "Gram-negative sepsis DIC mechanism: endotoxin (LPS) → activates monocytes/macrophages → tissue factor expression → extrinsic coagulation pathway activation → widespread thrombin generation → fibrin deposition → consumption of factors/platelets → DIC.", s: "Pharmacology" },
];
